/**
 * Agent Bridge - Phase 4 Implementation
 * Abstracts agent calls with mock responses (no live LLM calls)
 */

// =============================================================================
// TYPES
// =============================================================================

export interface DialogSimResponse {
  id: string;
  timestamp: Date;
  response: string;
  confidence: number;
  suggestions?: string[];
}

export interface PropSuggestion {
  path: string;
  value: any;
  reason: string;
  confidence: number;
}

export interface PropSuggestionsResponse {
  suggestions: Record<string, any>;
  explanations: PropSuggestion[];
  confidence: number;
}

export interface DialogInput {
  boardId: string;
  frameId?: string;
  prompt: string;
  context?: {
    boardName?: string;
    frameType?: string;
    currentProps?: any;
  };
}

export interface PropSuggestInput {
  frameType: string;
  currentProps: any;
  context?: {
    boardName?: string;
    boardDescription?: string;
    pattern?: string;
  };
}

// =============================================================================
// MOCK DATA GENERATORS
// =============================================================================

const MOCK_RESPONSES = {
  general: [
    "I can help you improve your board design. What specific aspect would you like to work on?",
    "Based on your board structure, I notice you might want to consider adding more interactive elements.",
    "Your board looks good! Would you like me to suggest some enhancements?",
    "I can help with layout optimization, content suggestions, or interaction patterns. What interests you most?"
  ],
  cover: [
    "For your cover frame, consider using a hero image that represents your board's purpose.",
    "A compelling title and subtitle can make your board more engaging. Would you like suggestions?",
    "Cover frames work best with high-contrast images and clear, concise messaging.",
    "Consider adding a call-to-action button to guide users into your board experience."
  ],
  settings: [
    "Your settings look well-organized. Consider enabling autosave for better user experience.",
    "The default engagement pattern affects how new frames behave. Dialogic works well for interactive boards.",
    "Grid settings can help with precise layout control. A 12-pixel grid is often ideal.",
    "Consider your board's visibility settings based on who needs access."
  ],
  dialogic: [
    "Dialogic frames work great for conversational interfaces and guided experiences.",
    "Consider adding placeholder text to help users understand what to ask.",
    "For better engagement, you might want to add suggested conversation starters.",
    "Dialogic patterns are perfect for AI-assisted workflows and user guidance."
  ],
  wizard: [
    "Wizard patterns excel at breaking complex processes into manageable steps.",
    "Consider adding progress indicators and clear next/previous navigation.",
    "Each step should have a clear objective and validation before proceeding.",
    "Wizards work best with 3-7 steps - beyond that, consider breaking into multiple wizards."
  ],
  gallery: [
    "Gallery patterns are perfect for showcasing multiple items or media.",
    "Consider adding filters or categories to help users navigate large collections.",
    "Masonry layout often works better than strict grids for varied content sizes.",
    "Don't forget to add alt text and captions for accessibility."
  ]
};

const PROP_SUGGESTIONS = {
  media_card: {
    title: ["Engaging Title", "Clear & Descriptive", "Action-Oriented"],
    subtitle: ["Brief explanation", "Context setting", "Value proposition"],
    media: {
      type: "image",
      suggestions: ["Use high-quality images", "Ensure good contrast", "Consider aspect ratio"]
    },
    cta: {
      label: ["Get Started", "Learn More", "Explore", "Continue"],
      action: "Consider what users should do next"
    }
  },
  config_panel: {
    sections: ["Organize settings logically", "Group related options", "Use clear labels"],
    validation: ["Add helpful error messages", "Provide examples", "Use appropriate input types"]
  },
  dialog: {
    placeholder: ["What would you like to know?", "Ask me anything...", "How can I help?"],
    maxMessages: [20, 50, 100],
    showHistory: true
  }
};

// =============================================================================
// AGENT BRIDGE IMPLEMENTATION
// =============================================================================

export class AgentBridge {
  private static instance: AgentBridge;
  private dialogHistory: Map<string, DialogSimResponse[]> = new Map();

  private constructor() {}

  public static getInstance(): AgentBridge {
    if (!AgentBridge.instance) {
      AgentBridge.instance = new AgentBridge();
    }
    return AgentBridge.instance;
  }

  /**
   * Simulate a dialog interaction
   */
  public async simulateDialog(input: DialogInput): Promise<DialogSimResponse> {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 500 + Math.random() * 1000));

    const { boardId, frameId, prompt, context } = input;
    const sessionKey = `${boardId}:${frameId || 'general'}`;

    // Get or create history for this session
    if (!this.dialogHistory.has(sessionKey)) {
      this.dialogHistory.set(sessionKey, []);
    }
    const history = this.dialogHistory.get(sessionKey)!;

    // Generate response based on context and prompt
    let response = this.generateResponse(prompt, context);
    const confidence = 0.7 + Math.random() * 0.3; // 70-100%

    // Add some contextual awareness
    if (prompt.toLowerCase().includes('help')) {
      response = "I'm here to help! " + response;
    }
    
    if (prompt.toLowerCase().includes('suggest') || prompt.toLowerCase().includes('improve')) {
      response += " Would you like me to suggest specific improvements?";
    }

    const dialogResponse: DialogSimResponse = {
      id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date(),
      response,
      confidence,
      suggestions: this.generateSuggestions(prompt, context)
    };

    // Store in history
    history.push(dialogResponse);

    // Keep history manageable (last 20 messages)
    if (history.length > 20) {
      history.splice(0, history.length - 20);
    }

    return dialogResponse;
  }

  /**
   * Suggest props for a frame type
   */
  public async suggestProps(input: PropSuggestInput): Promise<PropSuggestionsResponse> {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 300 + Math.random() * 500));

    const { frameType, currentProps, context } = input;
    
    // Get base suggestions for frame type
    const baseSuggestions = PROP_SUGGESTIONS[frameType as keyof typeof PROP_SUGGESTIONS] || {};
    
    // Generate contextual suggestions
    const suggestions: Record<string, any> = {};
    const explanations: PropSuggestion[] = [];

    // Title suggestions based on context
    if (!currentProps.title || currentProps.title.length < 3) {
      const titleSuggestions = baseSuggestions.title || ["Untitled"];
      suggestions.title = titleSuggestions[Math.floor(Math.random() * titleSuggestions.length)];
      explanations.push({
        path: 'title',
        value: suggestions.title,
        reason: 'A clear title helps users understand the purpose of this frame',
        confidence: 0.8
      });
    }

    // Pattern-specific suggestions
    if (context?.pattern === 'dialogic' && !currentProps.placeholder) {
      suggestions.placeholder = "What would you like to know?";
      explanations.push({
        path: 'placeholder',
        value: suggestions.placeholder,
        reason: 'Placeholder text guides users on how to interact',
        confidence: 0.9
      });
    }

    if (context?.pattern === 'wizard' && !currentProps.steps?.length) {
      suggestions.steps = [
        { id: 'step1', label: 'Getting Started', completed: false },
        { id: 'step2', label: 'Configuration', completed: false },
        { id: 'step3', label: 'Review', completed: false }
      ];
      explanations.push({
        path: 'steps',
        value: suggestions.steps,
        reason: 'Wizard patterns work best with 3-5 clear steps',
        confidence: 0.85
      });
    }

    // Media suggestions for media cards
    if (frameType === 'media_card' && !currentProps.media) {
      suggestions.media = {
        type: 'image',
        url: null,
        placeholder: 'Consider adding a compelling image'
      };
      explanations.push({
        path: 'media',
        value: suggestions.media,
        reason: 'Visual content increases engagement and comprehension',
        confidence: 0.75
      });
    }

    const confidence = explanations.length > 0 ? 
      explanations.reduce((sum, exp) => sum + exp.confidence, 0) / explanations.length : 
      0.5;

    return {
      suggestions,
      explanations,
      confidence
    };
  }

  /**
   * Get dialog history for a session
   */
  public getDialogHistory(boardId: string, frameId?: string): DialogSimResponse[] {
    const sessionKey = `${boardId}:${frameId || 'general'}`;
    return this.dialogHistory.get(sessionKey) || [];
  }

  /**
   * Clear dialog history
   */
  public clearDialogHistory(boardId: string, frameId?: string): void {
    const sessionKey = `${boardId}:${frameId || 'general'}`;
    this.dialogHistory.delete(sessionKey);
  }

  // =============================================================================
  // PRIVATE HELPERS
  // =============================================================================

  private generateResponse(prompt: string, context?: any): string {
    const lowerPrompt = prompt.toLowerCase();
    
    // Context-aware responses
    if (context?.frameType === 'media_card' || lowerPrompt.includes('cover')) {
      return this.getRandomResponse(MOCK_RESPONSES.cover);
    }
    
    if (context?.frameType === 'config_panel' || lowerPrompt.includes('settings')) {
      return this.getRandomResponse(MOCK_RESPONSES.settings);
    }
    
    if (context?.pattern === 'dialogic' || lowerPrompt.includes('dialog')) {
      return this.getRandomResponse(MOCK_RESPONSES.dialogic);
    }
    
    if (context?.pattern === 'wizard' || lowerPrompt.includes('wizard') || lowerPrompt.includes('step')) {
      return this.getRandomResponse(MOCK_RESPONSES.wizard);
    }
    
    if (context?.pattern === 'gallery' || lowerPrompt.includes('gallery')) {
      return this.getRandomResponse(MOCK_RESPONSES.gallery);
    }
    
    // Default responses
    return this.getRandomResponse(MOCK_RESPONSES.general);
  }

  private generateSuggestions(prompt: string, context?: any): string[] {
    const suggestions: string[] = [];
    
    if (prompt.toLowerCase().includes('improve') || prompt.toLowerCase().includes('better')) {
      suggestions.push("Add more visual elements", "Improve text clarity", "Consider user flow");
    }
    
    if (prompt.toLowerCase().includes('color') || prompt.toLowerCase().includes('theme')) {
      suggestions.push("Try a complementary color scheme", "Ensure good contrast", "Consider brand colors");
    }
    
    if (prompt.toLowerCase().includes('layout')) {
      suggestions.push("Use consistent spacing", "Align elements properly", "Consider mobile layout");
    }
    
    return suggestions;
  }

  private getRandomResponse(responses: string[]): string {
    return responses[Math.floor(Math.random() * responses.length)];
  }
}

// =============================================================================
// EXPORTS
// =============================================================================

// Convenience functions for direct use
export const agentBridge = AgentBridge.getInstance();

export async function simulateDialog(input: DialogInput): Promise<DialogSimResponse> {
  return agentBridge.simulateDialog(input);
}

export async function suggestProps(input: PropSuggestInput): Promise<PropSuggestionsResponse> {
  return agentBridge.suggestProps(input);
}

export function getDialogHistory(boardId: string, frameId?: string): DialogSimResponse[] {
  return agentBridge.getDialogHistory(boardId, frameId);
}

export function clearDialogHistory(boardId: string, frameId?: string): void {
  return agentBridge.clearDialogHistory(boardId, frameId);
}

import React from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import { useAuth } from './context/AuthContext';


const ProtectedRoute: React.FC = () => {
  const { isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return <div>Loading...</div>; // Or a spinner component
  }

  return isAuthenticated ? <Outlet /> : <Navigate to="/login" replace />;
};

function App() {
  console.log('[app-old.tsx] This old app file is rendering!');
  
  return (
    <>
      <div className="h-screen w-screen bg-red-500 text-white flex items-center justify-center text-2xl font-bold">
        If you can see this red screen, Tailwind CSS is working.
      </div>
      
      {/* DEBUG BUTTON */}
      <button
        type="button"
        onClick={() => window.location.href = '/debug'}
        style={{
          position: 'fixed',
          bottom: '20px', 
          right: '20px',
          zIndex: 999999,
          background: 'blue',
          color: 'white',
          padding: '20px',
          fontSize: '20px',
          border: '5px solid green',
          borderRadius: '10px',
          cursor: 'pointer',
          fontWeight: 'bold'
        }}
      >
        DEBUG BUTTON (OLD APP)
      </button>
    </>
  );
}

export default App;

/**
 * Agent Board
 * ===========
 * 
 * Board component for agent configuration and management.
 * Uses dialogic engagement mode with agent preview, configuration, and interaction frames.
 */

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { 
  CpuChipIcon,
  PlusIcon,
  Cog6ToothIcon,
  ChatBubbleLeftRightIcon,
  TagIcon,
  DocumentTextIcon
} from '@heroicons/react/24/outline';
import { BoardRenderer } from '../components/boards/BoardRenderer';
import { useBoard, BoardInstance } from '../context/BoardContext';
import { useFrame } from '../context/FrameContext';
import { 
  ExtendedFrameInstance, 
  FrameInteraction 
} from '../types/frame';

// =============================================================================
// AGENT BOARD PROPS
// =============================================================================

interface AgentBoardProps {
  agentId?: string;
  className?: string;
  onAgentUpdate?: (agentId: string, updates: any) => void;
  showControls?: boolean;
}

// =============================================================================
// MOCK DATA GENERATORS
// =============================================================================

const createMockAgentBoard = (agentId: string): BoardInstance => ({
  id: `agent-board-${agentId}`,
  config: {
    id: `agent-board-config-${agentId}`,
    type: 'agent_board',
    name: 'Agent Configuration',
    description: 'Configure and interact with your AI agent',
    layout: 'column',
    engagementMode: 'dialogic',
    allowLayoutEditing: true,
    theme: {
      primaryColor: '#3B82F6',
      backgroundColor: '#F8FAFC',
      accentColor: '#1E40AF',
    }
  },
  frames: [],
  entityType: 'agent',
  entityId: agentId,
  createdAt: new Date(),
  updatedAt: new Date(),
});

const createAgentPreviewFrame = (agentId: string, agentData?: any): ExtendedFrameInstance => ({
  id: `agent-preview-${agentId}`,
  entityType: 'agent',
  entityId: agentId,
  configId: `agent-preview-config-${agentId}`,
  currentContentId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  data: agentData ? {
    agentName: agentData.name,
    description: agentData.purpose,
    status: agentData.status === 'ready' ? 'Active' : agentData.status,
    capabilities: agentData.tools || ['Conversation', 'Task Assistance'],
    lastActive: agentData.updated_at,
    model: agentData.model,
    provider: agentData.model_provider,
  } : undefined,
  FrameConfig: {
    id: `agent-preview-config-${agentId}`,
    name: 'Agent Overview',
    description: 'View agent identity and status',
    theme: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    frameType: 'agent_preview',
    engagementMode: 'dialogic',
  },
});

const createAgentDialogFrame = (agentId: string, agentData?: any): ExtendedFrameInstance => ({
  id: `agent-dialog-${agentId}`,
  entityType: 'agent',
  entityId: agentId,
  configId: `agent-dialog-config-${agentId}`,
  currentContentId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  data: agentData ? {
    agentName: agentData.name,
    messages: [
      { 
        role: 'assistant', 
        content: `Hello! I'm ${agentData.name}. ${agentData.purpose}` 
      },
    ],
    isActive: agentData.status === 'ready',
  } : undefined,
  FrameConfig: {
    id: `agent-dialog-config-${agentId}`,
    name: 'Agent Conversation',
    description: 'Interactive conversation with the agent',
    theme: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    frameType: 'dialog',
    engagementMode: 'dialogic',
  },
});

const createAgentConfigFrame = (agentId: string, agentData?: any): ExtendedFrameInstance => ({
  id: `agent-config-${agentId}`,
  entityType: 'agent',
  entityId: agentId,
  configId: `agent-config-config-${agentId}`,
  currentContentId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  data: agentData ? {
    settings: {
      model: agentData.model,
      model_provider: agentData.model_provider,
      visibility: agentData.visibility,
      agent_class: agentData.agent_class,
      tools: agentData.tools,
      permissions: agentData.permissions,
      ...agentData.config,
    },
    availableSettings: ['model', 'model_provider', 'visibility', 'agent_class', 'tools', 'permissions'],
  } : undefined,
  FrameConfig: {
    id: `agent-config-config-${agentId}`,
    name: 'Agent Settings',
    description: 'Configure agent parameters and behavior',
    theme: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    frameType: 'config_panel',
    engagementMode: 'dialogic',
  },
});

const createTopicsFrame = (agentId: string): ExtendedFrameInstance => ({
  id: `topics-${agentId}`,
  entityType: 'agent',
  entityId: agentId,
  configId: `topics-config-${agentId}`,
  currentContentId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  data: {
    view: 'list',
    showTags: true,
    groupBy: 'status'
  },
  FrameConfig: {
    id: `topics-config-${agentId}`,
    name: 'Topics',
    description: 'Manage topics and highlights for this agent',
    theme: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    frameType: 'topics',
    engagementMode: 'focus',
  },
});

const createDraftFrame = (agentId: string): ExtendedFrameInstance => ({
  id: `draft-${agentId}`,
  entityType: 'agent',
  entityId: agentId,
  configId: `draft-config-${agentId}`,
  currentContentId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  data: {
    tabs: ['Form', 'JSON', 'Diff', 'History']
  },
  FrameConfig: {
    id: `draft-config-${agentId}`,
    name: 'Draft',
    description: 'Edit and manage agent configuration drafts',
    theme: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    frameType: 'draft',
    engagementMode: 'canvas',
  },
});

// =============================================================================
// MAIN COMPONENT
// =============================================================================

export const AgentBoard: React.FC<AgentBoardProps> = ({
  agentId = 'demo-agent',
  className = '',
  onAgentUpdate,
  showControls = true,
}) => {
  const { 
    activeBoard, 
    loadBoard, 
    addFrame, 
    isLoading, 
    error 
  } = useBoard();
  const { handleFrameInteraction } = useFrame();
  
  const [isInitialized, setIsInitialized] = useState(false);
  const [availableFrameTypes, setAvailableFrameTypes] = useState<string[]>([
    'agent_preview',
    'dialog', 
    'config_panel',
    'topics',
    'draft'
  ]);

  // Initialize board with agent-specific frames using existing board-data API
  useEffect(() => {
    const initializeBoard = async () => {
      if (isInitialized) return;

      try {
        // First, ensure the agent has a home board
        const agentResponse = await fetch(`/api/agents/${agentId}/home-board`, {
          credentials: 'include',
        });

        if (!agentResponse.ok) {
          throw new Error(`Failed to ensure agent home board: ${agentResponse.statusText}`);
        }

        const agentData = await agentResponse.json();
        
        if (!agentData.success) {
          throw new Error(agentData.error || 'Failed to ensure agent home board');
        }

        const boardId = agentData.data.board.id;

        // Load the board via the existing board-data API
        await loadBoard(boardId);
        setIsInitialized(true);
        
      } catch (error) {
        console.error('Failed to initialize agent board:', error);
        // Fall back to mock data if API fails
        const mockBoard = createMockAgentBoard(agentId);
        const frames = [
          createAgentPreviewFrame(agentId),
          createAgentDialogFrame(agentId),
          createTopicsFrame(agentId),
          createDraftFrame(agentId),
          createAgentConfigFrame(agentId),
        ];
        mockBoard.frames = frames;
        await loadBoard(mockBoard.id);
        setIsInitialized(true);
      }
    };

    initializeBoard();
  }, [agentId, isInitialized, loadBoard]);

  // Handle frame interactions specific to agent board
  const handleAgentFrameInteraction = (interaction: FrameInteraction) => {
    console.log('Agent board interaction:', interaction);
    
    // Handle agent-specific interactions
    switch (interaction.data?.action) {
      case 'agent_select':
        console.log('Agent selected:', interaction.data.agentId);
        break;
        
      case 'chat':
        console.log('Starting chat with agent:', interaction.data.agentId);
        break;
        
      case 'configure':
        console.log('Configuring agent:', interaction.data.agentId);
        break;
        
      case 'save_config':
        console.log('Saving agent configuration:', interaction.data);
        onAgentUpdate?.(agentId, interaction.data);
        break;
        
      default:
        handleFrameInteraction(interaction);
    }
  };

  // Add new frame to the board
  const handleAddFrame = async (frameType: string) => {
    if (!activeBoard) return;

    let newFrame: ExtendedFrameInstance;

    switch (frameType) {
      case 'agent_preview':
        newFrame = createAgentPreviewFrame(agentId);
        break;
      case 'dialog':
        newFrame = createAgentDialogFrame(agentId);
        break;
      case 'config_panel':
        newFrame = createAgentConfigFrame(agentId);
        break;
      case 'topics':
        newFrame = createTopicsFrame(agentId);
        break;
      case 'draft':
        newFrame = createDraftFrame(agentId);
        break;
      default:
        console.warn('Unknown frame type:', frameType);
        return;
    }

    try {
      await addFrame(activeBoard.id, newFrame);
    } catch (error) {
      console.error('Failed to add frame:', error);
    }
  };

  if (!isInitialized && isLoading) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <div className="text-center">
          <CpuChipIcon className="w-12 h-12 text-blue-600 mx-auto mb-4 animate-pulse" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">Loading Agent Board</h3>
          <p className="text-gray-600">Setting up your agent workspace...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <div className="text-center">
          <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <CpuChipIcon className="w-6 h-6 text-red-600" />
          </div>
          <h3 className="text-lg font-medium text-gray-900 mb-2">Failed to Load Agent Board</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button
            onClick={() => setIsInitialized(false)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Agent Board Header */}
      <div className="mb-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
              <CpuChipIcon className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Agent Workspace</h1>
              <p className="text-gray-600">Configure and interact with Agent ID: {agentId}</p>
            </div>
          </div>

          {/* Quick Actions */}
          {showControls && (
            <div className="flex items-center space-x-2">
              <div className="relative group">
                <button className="flex items-center space-x-2 px-4 py-2 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">
                  <PlusIcon className="w-4 h-4" />
                  <span>Add Frame</span>
                </button>
                
                {/* Dropdown Menu */}
                <div className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-10">
                  {availableFrameTypes.map((frameType) => (
                    <button
                      key={frameType}
                      onClick={() => handleAddFrame(frameType)}
                      className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 first:rounded-t-lg last:rounded-b-lg transition-colors"
                    >
                      <div className="flex items-center space-x-2">
                        {frameType === 'agent_preview' && <CpuChipIcon className="w-4 h-4" />}
                        {frameType === 'dialog' && <ChatBubbleLeftRightIcon className="w-4 h-4" />}
                        {frameType === 'config_panel' && <Cog6ToothIcon className="w-4 h-4" />}
                        {frameType === 'topics' && <TagIcon className="w-4 h-4" />}
                        {frameType === 'draft' && <DocumentTextIcon className="w-4 h-4" />}
                        <span className="capitalize">{frameType.replace('_', ' ')}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Board Renderer */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
      >
        <BoardRenderer
          boardInstance={activeBoard || undefined}
          onFrameInteraction={handleAgentFrameInteraction}
          showLayoutControls={showControls}
          className="min-h-[600px]"
        />
      </motion.div>

