              left: `${50 + (index * 20)}px`,
            }}
            onClick={() => isLayoutEditing && onFrameSelect(frame.id)}
          >
            <FrameRenderer
              frameInstance={frame}
              onInteraction={onFrameInteraction}
            />
            {isLayoutEditing && (
              <div className="absolute top-2 right-2 bg-white rounded-lg shadow-sm border border-gray-200 p-1">
                <button className="text-gray-400 hover:text-gray-600">
                  <Cog6ToothIcon className="w-4 h-4" />
                </button>
              </div>
            )}
          </motion.div>
        ))}
      </AnimatePresence>
    )}
  </div>
);

// =============================================================================
// LAYOUT REGISTRY
// =============================================================================

const layoutRegistry: Record<BoardLayout, React.FC<LayoutProps & any>> = {
  grid: GridLayout,
  column: ColumnLayout,
  row: RowLayout,
  wizard: WizardLayout,
  focus: FocusLayout,
  canvas: CanvasLayout,
};

// =============================================================================
// MAIN COMPONENT
// =============================================================================

export const BoardRenderer: React.FC<BoardRendererProps> = ({
  boardInstance,
  className = '',
  onFrameInteraction,
  onBoardUpdate,
  showLayoutControls = true,
  isPreview = false,
}) => {
  const { 
    activeBoard, 
    isLoading, 
    error, 
    isLayoutEditing,
    selectedFrameId,
    setLayoutEditing,
    selectFrame,
    loadBoard 
  } = useBoard();
  const { handleFrameInteraction } = useFrame();

  // Use provided board instance or active board from context
  const board = boardInstance || activeBoard;

  // Load board if ID is provided but no board is active
  useEffect(() => {
    if (boardInstance?.id && !activeBoard) {
      loadBoard(boardInstance.id);
    }
  }, [boardInstance?.id, activeBoard, loadBoard]);

  // Handle frame interactions
  const handleInteraction = (interaction: FrameInteraction) => {
    handleFrameInteraction(interaction);
    onFrameInteraction?.(interaction);
  };

  // Apply board theme
  const boardTheme = useMemo(() => {
    if (!board?.config.theme) return {};
    
    const theme: Record<string, string> = {};
    Object.entries(board.config.theme).forEach(([key, value]) => {
      if (value) {
        theme[`--board-${key}`] = value;
      }
    });
    return theme;
  }, [board?.config.theme]);

  // Get layout component
  const LayoutComponent = board?.config.layout 
    ? layoutRegistry[board.config.layout] 
    : GridLayout;

  if (isLoading) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading board...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <div className="text-center">
          <ExclamationTriangleIcon className="w-12 h-12 text-red-500 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">Error Loading Board</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button
            onClick={() => board?.id && loadBoard(board.id)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  if (!board) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <div className="text-center">
          <PlusIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <p className="text-gray-500">No board loaded</p>
        </div>
      </div>
    );
  }

  return (
    <div 
      className={`${className}`}
      style={boardTheme}
    >
      {/* Board Header */}
      {!isPreview && (
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">{board.config.name}</h1>
            {board.config.description && (
              <p className="text-gray-600 mt-1">{board.config.description}</p>
            )}
          </div>

          {/* Layout Controls */}
          {showLayoutControls && board.config.allowLayoutEditing && (
            <div className="flex items-center space-x-2">
              <button
                onClick={() => setLayoutEditing(!isLayoutEditing)}
                className={`flex items-center space-x-2 px-3 py-2 rounded-lg border transition-colors ${
                  isLayoutEditing
                    ? 'bg-blue-600 text-white border-blue-600'
                    : 'bg-white text-gray-600 border-gray-300 hover:bg-gray-50'
                }`}
              >
                {isLayoutEditing ? (
                  <>
                    <EyeIcon className="w-4 h-4" />
                    <span>Preview</span>
                  </>
                ) : (
                  <>
                    <PencilIcon className="w-4 h-4" />
                    <span>Edit Layout</span>
                  </>
                )}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Board Content */}
      <div className="board-content">
        <LayoutComponent
          frames={board.frames}
          onFrameInteraction={handleInteraction}
          isLayoutEditing={isLayoutEditing}
          selectedFrameId={selectedFrameId}
          onFrameSelect={selectFrame}
          boardTheme={boardTheme}
        />
      </div>

      {/* Empty State */}
      {board.frames.length === 0 && !isLayoutEditing && (
        <div className="text-center py-12">
          <PlusIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No Frames Yet</h3>
          <p className="text-gray-600">Add frames to start building your board.</p>
        </div>
      )}
    </div>
  );
};

export default BoardRenderer;

import React, { useEffect, useState } from 'react';
import { apiFetch } from '../../lib/api';
import MembersPanel from './MembersPanel';
import { CheckCircleIcon } from '@heroicons/react/24/outline';
import type { DomainScope } from './DomainManager';

interface Domain {
  id: string;
  name: string;
  slug: string;
  description?: string | null;
  customDomain?: string | null;
  customDomainVerified?: boolean;
  ownerId: string;
  status: string;
}

interface Props {
  domain: Domain;
  scope: DomainScope;
  viewerId: string;
  refresh: () => void;
}

const DomainDetailCard: React.FC<Props> = ({ domain, scope, viewerId, refresh }) => {
  const [form, setForm] = useState({ name: '', slug: '', description: '', customDomain: '' });
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<string | null>(null);
  const base = scope === 'user' ? '/api/domains' : '/api/admin/domains';

  useEffect(() => {
    setForm({
      name: domain.name || '',
      slug: domain.slug || '',
      description: domain.description || '',
      customDomain: domain.customDomain || '',
    });
  }, [domain]);

  const saveMeta = async () => {
    setSaving(true);
    try {
      await apiFetch(`${base}/${domain.id}`, { method: 'PUT', body: JSON.stringify({ ...form, customDomain: undefined }) });
      setMsg('Saved');
      refresh();
    } catch (e:any) { setMsg(e?.body||'Failed'); }
    finally { setSaving(false); setTimeout(()=>setMsg(null),3000); }
  };

  const isOwner = domain.ownerId === viewerId;

  const saveCustom = async () => {
    if (!isOwner) return;
    setSaving(true);
    try { await apiFetch(`/api/domains/${domain.id}/custom-domain`, { method:'POST', body: JSON.stringify({ customDomain: form.customDomain })}); refresh(); setMsg('Saved'); }
    catch(e:any){ setMsg(e?.body||'Failed'); }
    finally{ setSaving(false); }
  };

  const verify = async () => {
    if (!isOwner) return;
    setSaving(true);
    try { const resp = await apiFetch(`/api/domains/${domain.id}/custom-domain/verify`, { method:'POST' }); setMsg(resp.success?'Verified':'Failed'); refresh(); }
    catch(e:any){ setMsg(e?.body||'Failed'); }
    finally{ setSaving(false); }
  };

  return (
    <div className="flex-1 space-y-4">
      <div className="border rounded p-4 space-y-3 bg-card">
        <h3 className="font-medium">General</h3>
        <div className="grid grid-cols-2 gap-2 text-xs">
          <input value={form.name} onChange={(e)=>setForm({...form,name:e.target.value})} className="border p-1 rounded" placeholder="Name"/>
          <input value={form.slug} onChange={(e)=>setForm({...form,slug:e.target.value})} className="border p-1 rounded" placeholder="Slug"/>
          <textarea rows={2} value={form.description} onChange={(e)=>setForm({...form,description:e.target.value})} className="border p-1 rounded col-span-2" placeholder="Description"/>
        </div>
        <button onClick={saveMeta} disabled={saving} className="px-2 py-0.5 bg-primary text-white rounded text-xs">Save</button>
        {msg && <p className="text-xs mt-1">{msg}</p>}
      </div>

      <div className="border rounded p-4 space-y-2 bg-card text-xs">
        <h3 className="font-medium">Custom Domain</h3>
        <input value={form.customDomain} onChange={(e)=>setForm({...form,customDomain:e.target.value})} className="border p-1 rounded w-full" placeholder="myapp.example.com"/>
        <div className="flex gap-2">
          <button onClick={saveCustom} disabled={!isOwner || saving} className="px-2 py-0.5 bg-primary text-white rounded">Save</button>
          <button onClick={verify} disabled={!isOwner || saving} className="px-2 py-0.5 bg-green-600 text-white rounded">Verify</button>
        </div>
        {domain.customDomainVerified && <p className="text-green-700 flex items-center gap-1"><CheckCircleIcon className="w-4 h-4"/>Verified</p>}
        {!isOwner && <p className="text-xs text-muted-foreground">Only domain owner can modify.</p>}
      </div>

      <MembersPanel domainId={domain.id} scope={scope} />

      {/* Danger Zone */}
      {scope === 'admin' && (
        <div className="border rounded p-4 space-y-2 bg-red-50 dark:bg-red-900/20 text-xs">
          <h3 className="font-medium text-red-700 dark:text-red-300">Danger Zone</h3>
          <p>Suspend disables access; Archive permanently removes the domain after a grace period.</p>
          <div className="flex gap-2">
            <button
              onClick={async()=>{ if(!confirm('Toggle suspension?')) return; try{ await apiFetch(`/api/admin/domains/${domain.id}/suspend`,{method:'PATCH'}); refresh(); }catch(e){ console.error(e);} }}
              className="px-2 py-0.5 bg-orange-600 text-white rounded"
            >
              {domain.status==='suspended'?'Activate':'Suspend'}
            </button>
            <button
              onClick={async()=>{ if(!confirm('Archive domain? This cannot be undone.')) return; try{ await apiFetch(`/api/admin/domains/${domain.id}`,{method:'DELETE'}); }catch(e){ console.error(e);} }}
              className="px-2 py-0.5 bg-red-700 text-white rounded"
            >
              Archive
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default DomainDetailCard;

import React, { useState, useEffect } from 'react';
import { 
  XMarkIcon, 
  CheckCircleIcon, 
  ExclamationTriangleIcon,
  GlobeAltIcon,
  TrashIcon,
  ClockIcon,
  ClipboardDocumentIcon
} from '@heroicons/react/24/outline';
import { apiFetch } from '../../lib/api';
import DnsInfoPanel from './DnsInfoPanel';
import type { DomainDetailFormProps } from './types';

interface Member {
  userId: string;
  name: string;
  role: string;
  permissions: string[];
  expiresAt?: string;
}

const ROLES = [
  { value: 'admin', label: 'Admin' },
  { value: 'user', label: 'User' },
  { value: 'friend', label: 'Friend' },
  { value: 'connection', label: 'Connection' }
];

const DomainDetailForm: React.FC<DomainDetailFormProps> = ({ domain, onClose, onSave }) => {
  // Basic form state
  const [form, setForm] = useState({
    name: '',
    slug: '',
    description: ''
  });

  // Custom domain state
  const [customDomain, setCustomDomain] = useState('');
  const [dnsRecords, setDnsRecords] = useState<any[]>([]);
  const [nameServers, setNameServers] = useState<string[]>([]);
  const [verifying, setVerifying] = useState(false);
  const [addingToVercel, setAddingToVercel] = useState(false);
  const [vercelConfigured, setVercelConfigured] = useState(false);
  const [dnsStatus, setDnsStatus] = useState<any>(null);
  const [loadingDns, setLoadingDns] = useState(false);

  // Members state
  const [members, setMembers] = useState<Member[]>([]);
  const [userSearch, setUserSearch] = useState('');
  const [searchResults, setSearchResults] = useState<Array<{
    id: string;
    name: string;
    email: string;
    createdAt: string;
  }>>([]);
  const [selectedUser, setSelectedUser] = useState<{
    id: string;
    name: string;
    email: string;
  } | null>(null);
  const [newMemberRole, setNewMemberRole] = useState('user');

  // UI state
  const [activeTab, setActiveTab] = useState('details');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Load domain data
  useEffect(() => {
    if (domain) {
      setForm({
        name: domain.name,
        slug: domain.slug,
        description: domain.description || ''
      });
      if (domain.customDomain) {
        setCustomDomain(domain.customDomain);
      }
      loadMembers();
      loadDnsStatus();
    }
  }, [domain]);

  // Load DNS status
  const loadDnsStatus = async () => {
    if (!domain || !domain.customDomain) return;
    setLoadingDns(true);
    try {
      const status = await apiFetch(`/api/domains/custom/${domain.id}/custom-domain/status`);
      console.log('Frontend: DNS status loaded:', { domain: domain.customDomain, status });
      
      setDnsStatus(status);
      setVercelConfigured(status.attached);
      setDnsRecords(status.records || []);
      setNameServers(status.nameServers || []);
      
      // Handle errors from Vercel
      if (status.error) {
        console.error('Frontend: Vercel status error:', {
          domain: domain.customDomain,
          error: status.error,
          errorCode: status.errorCode,
          details: status.details
        });
        
        // Set appropriate error message based on error code
        if (status.errorCode === '403') {
          setError('Access denied to Vercel. Please check your Vercel configuration.');
        } else if (status.errorCode === '404') {
          setError('Domain not found in Vercel project. Please add it to Vercel first.');
        } else if (status.errorCode === 'DNS_CONFIG_ERROR') {
          setError('Failed to load DNS configuration. Please try again.');
        } else {
          setError(`Vercel error: ${status.error}`);
        }
      } else {
        setError(null); // Clear any previous errors
      }
    } catch (err) {
      console.error('Frontend: Error loading DNS status:', err);
      setError('Failed to load domain status. Please try again.');
    } finally {
      setLoadingDns(false);
    }
  };

  // Load domain members
  const loadMembers = async () => {
    if (!domain) return;
    try {
      const response = await apiFetch(`/api/domains/${domain.id}/members`);
      setMembers(response.members);
    } catch (err: any) {
      console.error('Failed to load members:', err);
    }
  };

  // Handle form submission
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    // Send debug info to our debug endpoint
    try {
      await apiFetch('/api/debug/form-debug', {
        method: 'POST',
        body: JSON.stringify({
          action: 'form_submit',
          form_data: form,
          domain_id: domain?.id,
          timestamp: new Date().toISOString()
        })
      });
    } catch (debugErr) {
      // Ignore debug errors
    }
    
    setError(null);
    setSaving(true);

    try {
      await onSave(form);
      setSuccess('Domain saved successfully');
      setTimeout(() => setSuccess(null), 3000);
    } catch (err: any) {
      setError(err.message || 'Failed to save domain');
    } finally {
      setSaving(false);
    }
  };

  // Handle custom domain addition
  const handleAddCustomDomain = async () => {
    if (!domain || !customDomain) {
      return;
    }
    
    // Send debug info to our debug endpoint
    try {
      await apiFetch('/api/debug/form-debug', {
        method: 'POST',
        body: JSON.stringify({
          action: 'add_custom_domain',
          domain_id: domain.id,
          custom_domain: customDomain,
          timestamp: new Date().toISOString()
        })
      });
    } catch (debugErr) {
      // Ignore debug errors
    }
    
    setError(null);
    setSaving(true);

    try {
      const response = await apiFetch(`/api/domains/${domain.id}`, {
        method: 'PUT',
        body: JSON.stringify({ customDomain })
      });
      setSuccess('Custom domain added successfully');
      setTimeout(() => loadDnsStatus(), 1000);
    } catch (err: any) {
      setError(err.message || 'Failed to add custom domain');
    } finally {
      setSaving(false);
    }
  };

  // Handle adding domain to Vercel
  const handleAddToVercel = async () => {
    if (!domain || !domain.customDomain) return;
    setAddingToVercel(true);
    setError(null);

    try {
      const response = await apiFetch(`/api/domains/custom/${domain.id}/custom-domain`, {
        method: 'POST',
        body: JSON.stringify({ customDomain: domain.customDomain })
      });
      
      if (response.success) {
        setSuccess('Domain added to Vercel successfully');
        await loadDnsStatus();
      } else {
        setError(response.error || 'Failed to add domain to Vercel');
      }
    } catch (err: any) {
      setError(err.message || 'Failed to add domain to Vercel');
    } finally {
      setAddingToVercel(false);
    }
  };

  // Handle domain verification
  const handleVerifyDomain = async () => {
    if (!domain || !domain.customDomain) return;
    setVerifying(true);
    setError(null);

    try {
      const response = await apiFetch(`/api/domains/custom/${domain.id}/custom-domain/verify`, {
        method: 'POST'
      });
      
      if (response.success) {
        setSuccess('Domain verified successfully');
        await loadDnsStatus();
      } else {
        setError(response.error || 'Failed to verify domain');
      }
    } catch (err: any) {
      setError(err.message || 'Failed to verify domain');
    } finally {
      setVerifying(false);
    }
  };

  // Handle user search
  const handleUserSearch = async (query: string) => {
    setUserSearch(query);
    if (!query.trim()) {
      setSearchResults([]);
      return;
    }

    try {
      const response = await apiFetch(`/api/domains/users/search?query=${encodeURIComponent(query)}`);
      setSearchResults(response);
    } catch (err: any) {
      console.error('Failed to search users:', err);
    }
  };

  // Handle member addition
  const handleAddMember = async () => {
    if (!domain || !selectedUser) return;
    setError(null);

    try {
      await apiFetch(`/api/domains/${domain.id}/members`, {
        method: 'POST',
        body: JSON.stringify({
          userId: selectedUser.id,
          role: newMemberRole
        })
      });
      setSelectedUser(null);
      setUserSearch('');
      setSearchResults([]);
      setNewMemberRole('user');
      await loadMembers();
      setSuccess('Member added successfully');
    } catch (err: any) {
      setError(err.message || 'Failed to add member');
    }
  };

  // Handle member role update
  const handleUpdateMemberRole = async (userId: string, role: string) => {
    if (!domain) return;
    setError(null);

    try {
      await apiFetch(`/api/domains/${domain.id}/members/${userId}`, {
        method: 'PATCH',
        body: JSON.stringify({ role })
      });
      await loadMembers();
      setSuccess('Member role updated');
    } catch (err: any) {
      setError(err.message || 'Failed to update member role');
    }
  };

  // Handle member removal
  const handleRemoveMember = async (userId: string) => {
    if (!domain) return;
    if (!confirm('Are you sure you want to remove this member?')) return;
    setError(null);

    try {
      await apiFetch(`/api/domains/${domain.id}/members/${userId}`, {
        method: 'DELETE'
      });
      await loadMembers();
      setSuccess('Member removed successfully');
    } catch (err: any) {
      setError(err.message || 'Failed to remove member');
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b">
          <h2 className="text-xl font-semibold">Edit Domain</h2>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600"
          >
            <XMarkIcon className="w-6 h-6" />
          </button>
        </div>

        {/* Content - Scrollable */}
        <div className="overflow-y-auto max-h-[calc(90vh-140px)]">
          <div className="p-6 space-y-6">
            {/* Domain Information */}
            <div className="bg-gray-50 p-4 rounded-lg">
              <h4 className="font-medium mb-3">Domain Information</h4>
              <form onSubmit={handleSubmit} className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Domain Name *
                  </label>
                  <input
                    type="text"
                    value={form.name}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => setForm({ ...form, name: e.target.value })}
                    className="w-full px-3 py-2 border rounded-md"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Domain Slug
                  </label>
                  <input
                    type="text"
                    value={form.slug}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => setForm({ ...form, slug: e.target.value })}
                    className="w-full px-3 py-2 border rounded-md"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Description
                  </label>
                  <textarea
                    value={form.description}
                    onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setForm({ ...form, description: e.target.value })}
                    className="w-full px-3 py-2 border rounded-md"
                    rows={3}
                  />
                </div>
                <button
                  type="submit"
                  disabled={saving}
                  onClick={async () => {
                    try {
                      await apiFetch('/api/debug/form-debug', {
                        method: 'POST',
                        body: JSON.stringify({
                          action: 'submit_button_clicked',
                          domain_id: domain?.id,
                          timestamp: new Date().toISOString()
                        })
                      });
                    } catch (debugErr) {
                      // Ignore debug errors
                    }
                  }}
                  className="w-full px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                >
                  {saving ? 'Saving...' : 'Save Changes'}
                </button>
              </form>
            </div>

            {/* Custom Domain Setup */}
            {domain && (
              <div className="bg-gray-50 p-4 rounded-lg">
                <h4 className="font-medium mb-3">Custom Domain Setup</h4>
                
                {!domain.customDomain ? (
                  <div className="space-y-3">
                    <p className="text-sm text-gray-600">Add a custom domain to your Keeper platform.</p>
                    <div className="flex gap-2">
                      <input
                        type="text"
                        value={customDomain}
                        onChange={(e: React.ChangeEvent<HTMLInputElement>) => setCustomDomain(e.target.value)}
                        className="flex-1 px-3 py-2 border rounded-md"
                        placeholder="your-domain.com"
                        disabled={saving}
                      />
                      <button
                        onClick={async () => {
                          try {
                            await apiFetch('/api/debug/form-debug', {
                              method: 'POST',
                              body: JSON.stringify({
                                action: 'add_domain_button_clicked',
                                domain_id: domain?.id,
                                custom_domain: customDomain,
                                timestamp: new Date().toISOString()
                              })
                            });
                          } catch (debugErr) {
                            // Ignore debug errors
                          }
                          handleAddCustomDomain();
                        }}
                        className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                        disabled={saving || !customDomain}
                      >
                        Add Domain
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <div className="flex items-center gap-2">
                      <GlobeAltIcon className="w-5 h-5 text-blue-600" />
                      <span className="font-medium">{domain.customDomain}</span>
                      {domain.customDomainVerified && (
                        <CheckCircleIcon className="w-5 h-5 text-green-600" />
                      )}
                    </div>

                    {/* Domain Setup Process */}
                    <div className="space-y-3">
                      {/* Step 1: Add to Vercel */}
                      <div className="flex items-center justify-between p-3 bg-white rounded border">
                        <div className="flex items-center gap-3">
                          {vercelConfigured ? (
                            <CheckCircleIcon className="w-5 h-5 text-green-600" />
                          ) : dnsStatus?.error ? (
                            <ExclamationTriangleIcon className="w-5 h-5 text-red-600" />
                          ) : (
                            <ClockIcon className="w-5 h-5 text-gray-400" />
                          )}
                          <div>
                            <h5 className="font-medium">Add to Vercel</h5>
                            <p className="text-sm text-gray-600">
                              {vercelConfigured 
                                ? 'Domain added to Vercel' 
                                : dnsStatus?.error 
                                  ? `Error: ${dnsStatus.error}`
                                  : 'Add domain to Vercel project'
                              }
                            </p>
                            {dnsStatus?.error && (
                              <p className="text-xs text-red-600 mt-1">
                                {dnsStatus.errorCode === '403' && 'Check Vercel configuration'}
                                {dnsStatus.errorCode === '404' && 'Domain not found in project'}
                                {dnsStatus.errorCode === 'DNS_CONFIG_ERROR' && 'DNS config failed to load'}
                              </p>
                            )}
                          </div>
                        </div>
                        {!vercelConfigured && !dnsStatus?.error && (
                          <button
                            onClick={handleAddToVercel}
                            disabled={addingToVercel}
                            className="px-3 py-1 text-sm bg-black text-white rounded hover:bg-gray-800 disabled:opacity-50"
                          >
                            {addingToVercel ? 'Adding...' : 'Add to Vercel'}
                          </button>
                        )}
                        {dnsStatus?.error && (
                          <button
                            onClick={loadDnsStatus}
                            className="px-3 py-1 text-sm bg-gray-100 text-gray-700 rounded hover:bg-gray-200"
                          >
                            Retry
                          </button>
                        )}
                      </div>

                      {/* Step 2: Configure DNS */}
                      {vercelConfigured && (
                        <div className="flex items-center justify-between p-3 bg-white rounded border">
                          <div className="flex items-center gap-3">
                            {dnsStatus?.configured ? (
                              <CheckCircleIcon className="w-5 h-5 text-green-600" />
                            ) : (
                              <ClockIcon className="w-5 h-5 text-yellow-600" />
                            )}
                            <div>
                              <h5 className="font-medium">Configure DNS</h5>
                              <p className="text-sm text-gray-600">
                                {dnsStatus?.configured 
                                  ? 'DNS configured' 
                                  : 'Configure DNS records at your registrar'
                                }
                              </p>
                            </div>
                          </div>
                          {!dnsStatus?.configured && (
                            <button
                              onClick={loadDnsStatus}
                              disabled={loadingDns}
                              className="px-3 py-1 text-sm bg-yellow-600 text-white rounded hover:bg-yellow-700 disabled:opacity-50"
                            >
                              {loadingDns ? 'Checking...' : 'Check DNS'}
                            </button>
                          )}
                        </div>
                      )}

                      {/* DNS Status Message - Moved between Configure and Verify */}
                      {vercelConfigured && (
                        <div className={`p-3 rounded border ${
                          dnsStatus?.configured 
                            ? 'bg-green-50 border-green-200' 
                            : 'bg-red-50 border-red-200'
                        }`}>
                          <div className="flex items-center gap-2">
                            {dnsStatus?.configured ? (
                              <CheckCircleIcon className="w-5 h-5 text-green-600" />
                            ) : (
                              <ExclamationTriangleIcon className="w-5 h-5 text-red-600" />
                            )}
                            <p className="text-sm">
                              {dnsStatus?.configured 
                                ? 'DNS detected ✅ – waiting for verification. You may click Verify now.'
                                : 'DNS not detected yet – add these records at your registrar then click Verify.'
                              }
                            </p>
                          </div>
                          
                          {/* Show target nameservers when DNS is not configured */}
                          {!dnsStatus?.configured && (
                            <div className="mt-3 p-3 bg-white rounded border">
                              <h6 className="font-medium text-sm mb-2">Required Nameservers:</h6>
                              <div className="space-y-1">
                                <div className="flex items-center gap-2">
                                  <span className="text-sm font-mono bg-gray-100 px-2 py-1 rounded">ns1.vercel-dns.com</span>
                                  <button
                                    onClick={() => navigator.clipboard.writeText('ns1.vercel-dns.com')}
                                    className="text-blue-600 hover:text-blue-800"
                                  >
                                    <ClipboardDocumentIcon className="w-4 h-4" />
                                  </button>
                                </div>
                                <div className="flex items-center gap-2">
                                  <span className="text-sm font-mono bg-gray-100 px-2 py-1 rounded">ns2.vercel-dns.com</span>
                                  <button
                                    onClick={() => navigator.clipboard.writeText('ns2.vercel-dns.com')}
                                    className="text-blue-600 hover:text-blue-800"
                                  >
                                    <ClipboardDocumentIcon className="w-4 h-4" />
                                  </button>
                                </div>
                              </div>
                              <p className="text-xs text-gray-600 mt-2">
                                Update your domain's nameservers at your registrar to these Vercel nameservers.
                              </p>
                            </div>
                          )}
                        </div>
                      )}

                      {/* Step 3: Verify Domain */}
                      {vercelConfigured && (
                        <div className="flex items-center justify-between p-3 bg-white rounded border">
                          <div className="flex items-center gap-3">
                            {domain.customDomainVerified ? (
                              <CheckCircleIcon className="w-5 h-5 text-green-600" />
                            ) : (
                              <ClockIcon className="w-5 h-5 text-gray-400" />
                            )}
                            <div>
                              <h5 className="font-medium">Verify Domain</h5>
                              <p className="text-sm text-gray-600">
                                {domain.customDomainVerified 
                                  ? 'Domain verified' 
                                  : 'Verify domain and get SSL certificate'
                                }
                              </p>
                            </div>
                          </div>
                                                     {vercelConfigured && !domain.customDomainVerified && Boolean(dnsStatus?.configured) && (
                            <button
                              onClick={handleVerifyDomain}
                              disabled={verifying}
                              className="px-3 py-1 text-sm bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50"
                            >
                              {verifying ? 'Verifying...' : 'Verify Domain'}
                            </button>
                          )}
                        </div>
                      )}
                    </div>

                    {/* DNS Information */}
                    {(dnsRecords.length > 0 || nameServers.length > 0) && (
                      <div className="mt-4">
                        <DnsInfoPanel
                          records={dnsRecords}
                          nameServers={nameServers}
                          configured={dnsStatus?.configured === true || false}
                          verified={domain.customDomainVerified}
                        />
                      </div>
                    )}
                  </div>
                )}
              </div>
            )}

            {/* Members */}
            {domain && (
              <div className="bg-gray-50 p-4 rounded-lg">
                <h4 className="font-medium mb-3">Domain Members</h4>
                <div className="space-y-4">
                  <div>
                    <h5 className="text-sm font-medium mb-2">Add Member</h5>
                    <div className="space-y-3">
                      <div className="relative">
                        <input
                          type="text"
                          value={userSearch}
                          onChange={(e: React.ChangeEvent<HTMLInputElement>) => handleUserSearch(e.target.value)}
                          placeholder="Search users by name or email"
                          className="w-full px-3 py-2 border rounded-md"
                        />
                        {searchResults.length > 0 && (
                          <div className="absolute z-10 w-full mt-1 bg-white border rounded-md shadow-lg max-h-60 overflow-auto">
                            {searchResults.map(user => (
                              <button
                                key={user.id}
                                onClick={() => {
                                  setSelectedUser(user);
                                  setUserSearch('');
                                  setSearchResults([]);
                                }}
                                className="w-full px-4 py-2 text-left hover:bg-gray-50 flex items-center justify-between"
                              >
                                <div>
                                  <div className="font-medium">{user.name}</div>
                                  <div className="text-sm text-gray-500">{user.email}</div>
                                </div>
                                <div className="text-xs text-gray-400">
                                  Joined {new Date(user.createdAt).toLocaleDateString()}
                                </div>
                              </button>
                            ))}
                          </div>
                        )}
                      </div>

                      {selectedUser && (
                        <div className="flex gap-2 items-center p-2 bg-white rounded border">
                          <div className="flex-1">
                            <div className="font-medium">{selectedUser.name}</div>
                            <div className="text-sm text-gray-500">{selectedUser.email}</div>
                          </div>
                          <select
                            value={newMemberRole}
                            onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setNewMemberRole(e.target.value)}
                            className="px-3 py-2 border rounded-md"
                          >
                            {ROLES.map(role => (
                              <option key={role.value} value={role.value}>
                                {role.label}
                              </option>
                            ))}
                          </select>
                          <button
                            onClick={handleAddMember}
                            className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700"
                          >
                            Add
                          </button>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Current Members */}
                  <div>
                    <h5 className="text-sm font-medium mb-2">Current Members</h5>
                    <div className="space-y-2">
                      {members.map(member => (
                        <div key={member.userId} className="flex items-center justify-between p-2 bg-white rounded border">
                          <div>
                            <div className="font-medium">{member.name}</div>
                            <div className="text-sm text-gray-500">{member.role}</div>
                          </div>
                          <div className="flex items-center gap-2">
                            <select
                              value={member.role}
                              onChange={(e: React.ChangeEvent<HTMLSelectElement>) => 
                                handleUpdateMemberRole(member.userId, e.target.value)
                              }
                              className="px-2 py-1 text-sm border rounded"
                            >
                              {ROLES.map(role => (
                                <option key={role.value} value={role.value}>
                                  {role.label}
                                </option>
                              ))}
                            </select>
                            <button
                              onClick={() => handleRemoveMember(member.userId)}
                              className="text-red-600 hover:text-red-800"
                            >
                              <TrashIcon className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DomainDetailForm;

import React, { useEffect, useState } from 'react';
import { MagnifyingGlassIcon, PlusIcon } from '@heroicons/react/24/outline';
import { apiFetch } from '../../lib/api';
import type { DomainScope } from './DomainManager';

export interface Domain {
  id: string;
  name: string;
  slug: string;
  ownerId: string;
  status: string;
}

interface Props {
  scope: DomainScope;
  onSelect: (d: Domain) => void;
  selectedId?: string;
  allowCreate: boolean;
}

const DomainListPane: React.FC<Props> = ({ scope, onSelect, selectedId, allowCreate }) => {
  const [search, setSearch] = useState('');
  const [domains, setDomains] = useState<Domain[]>([]);
  const [loading, setLoading] = useState(true);
  const base = scope === 'user' ? '/api/domains' : '/api/admin/domains';

  const fetchList = async (q?: string) => {
    setLoading(true);
    try {
      const url = scope === 'user' ? `${base}/my` : `${base}?search=${encodeURIComponent(q || '')}`;
      const data = await apiFetch(url);
      const list = scope === 'user' ? data : data.domains || [];
      setDomains(list);
      if (list.length && !selectedId) onSelect(list[0]);
    } catch (e) {
      console.error('load domains error', e);
    } finally {
      setLoading(false);
    }
  };

  // initial load
  useEffect(() => { fetchList();  }, [scope]);

  // debounce search (admin scope only)
  useEffect(() => {
    if (scope === 'user') return;
    const t = setTimeout(() => fetchList(search.trim()), 400);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [search]);

  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({ name: '', slug: '', description: '' });
  const create = async () => {
    try {
      const resp = await apiFetch('/api/domains', { method: 'POST', body: JSON.stringify(form) });
      setShowCreate(false);
      setForm({ name: '', slug: '', description: '' });
      fetchList();
      onSelect(resp.domain);
    } catch (e) { console.error(e); }
  };

  return (
    <div className="w-full sm:w-56 flex-shrink-0 space-y-2">
      <div className="flex gap-2 items-center">
        {scope === 'admin' && <MagnifyingGlassIcon className="w-4 h-4" />}
        <input value={search} onChange={(e)=>setSearch(e.target.value)} placeholder="Search domains…" className="border p-1 rounded w-full text-xs" />
        {allowCreate && <button onClick={()=>setShowCreate(true)} className="text-xs border p-1 rounded"><PlusIcon className="w-4 h-4"/></button>}
      </div>
      <div className="border rounded max-h-64 overflow-y-auto text-xs">
        {loading ? <div className="p-2">Loading…</div> : domains.map(d=> (
          <div key={d.id} onClick={()=>onSelect(d)} className={`px-2 py-1 cursor-pointer hover:bg-muted ${selectedId===d.id?'bg-primary/20':''}`}>{d.name} <span className="text-muted-foreground">({d.slug})</span></div>
        ))}
      </div>

      {showCreate && (
        <div className="border p-2 rounded bg-muted/20 text-xs space-y-1 mt-2">
          <input placeholder="Name" value={form.name} onChange={(e)=>setForm({...form,name:e.target.value})} className="border p-1 w-full" />
          <input placeholder="Slug (optional)" value={form.slug} onChange={(e)=>setForm({...form,slug:e.target.value})} className="border p-1 w-full" />
          <textarea rows={2} placeholder="Description (optional)" value={form.description} onChange={(e)=>setForm({...form,description:e.target.value})} className="border p-1 w-full"/>
          <div className="flex gap-2"><button onClick={create} disabled={!form.name.trim()} className="px-2 py-0.5 bg-primary text-white rounded">Create</button><button onClick={()=>setShowCreate(false)} className="px-2 py-0.5 border rounded">Cancel</button></div>
        </div>
      )}
    </div>
  );
};

export default DomainListPane;

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { apiFetch } from '../../lib/api';
import DomainDetailForm from './DomainDetailForm';
import DnsStatusBadge from './DnsStatusBadge';
import DnsInfoPanel from './DnsInfoPanel';
import { Domain, DomainScope } from './types';
import { CheckCircleIcon, MagnifyingGlassIcon, PlusIcon, GlobeAltIcon } from '@heroicons/react/24/outline';

interface Props {
  scope: DomainScope;
  allowCreate?: boolean;
}

interface DomainWithDns extends Domain {
  dnsStatus?: {
    attached: boolean;
    configured: boolean;
    verified: boolean;
    records: any[];
    nameServers: string[];
  };
}

const DomainManager: React.FC<Props> = ({ scope, allowCreate = true }) => {
  const [domains, setDomains] = useState<DomainWithDns[]>([]);
  const [selectedDomain, setSelectedDomain] = useState<DomainWithDns | null>(null);
  const [showDetail, setShowDetail] = useState(false);
  const [showCreate, setShowCreate] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [dnsLoading, setDnsLoading] = useState<Set<string>>(new Set());

  useEffect(() => {
    loadDomains();
  }, [scope]);

  const loadDomains = async () => {
    setLoading(true);
    setError(null);
    try {
      const baseUrl = scope === 'user' ? '/api/domains' : '/api/admin/domains';
      const response = await apiFetch(`${baseUrl}/my`);
      const domainsWithDns = Array.isArray(response) ? response : [];
      setDomains(domainsWithDns);
      
      // Load DNS status for domains with custom domains
      domainsWithDns.forEach(domain => {
        if (domain.customDomain && !domain.customDomainVerified) {
          loadDnsStatus(domain.id);
        }
      });
    } catch (err: any) {
      setError(err.message || 'Failed to load domains');
      console.error('Error loading domains:', err);
    } finally {
      setLoading(false);
    }
  };

  const loadDnsStatus = async (domainId: string) => {
    if (dnsLoading.has(domainId)) return;
    
    setDnsLoading(prev => new Set(prev).add(domainId));
    try {
      const status = await apiFetch(`/api/domains/custom/${domainId}/custom-domain/status`);
      setDomains(prev => prev.map(domain => 
        domain.id === domainId 
          ? { ...domain, dnsStatus: status }
          : domain
      ));
    } catch (err) {
      console.error('Error loading DNS status for domain:', domainId, err);
    } finally {
      setDnsLoading(prev => {
        const newSet = new Set(prev);
        newSet.delete(domainId);
        return newSet;
      });
    }
  };

  const handleCreateDomain = async (formData: { name: string; slug: string; description: string }) => {
    try {
      const response = await apiFetch('/api/domains', {
        method: 'POST',
        body: JSON.stringify(formData)
      });
      setDomains([...domains, response.domain]);
      setShowCreate(false);
      setSelectedDomain(response.domain);
      setShowDetail(true);
    } catch (err: any) {
      throw new Error(err.message || 'Failed to create domain');
    }
  };

  const handleUpdateDomain = async (domainId: string, formData: { name: string; slug: string; description: string }) => {
    console.log('handleUpdateDomain called:', { domainId, formData });
    try {
      const response = await apiFetch(`/api/domains/${domainId}`, {
        method: 'PATCH',
        body: JSON.stringify(formData)
      });
      console.log('Domain update response:', response);
      setDomains(domains.map(d => d.id === domainId ? response.domain : d));
      setSelectedDomain(response.domain);
      setShowDetail(false);
    } catch (err: any) {
      console.error('Domain update error:', err);
      throw new Error(err.message || 'Failed to update domain');
    }
  };

  const filteredDomains = domains.filter(domain => 
    domain.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    domain.slug.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (domain.description && domain.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="h-full flex flex-col">
      <div className="flex items-center justify-between mb-4 gap-4">
        <div className="flex-1 relative">
          <MagnifyingGlassIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search domains..."
            className="w-full pl-10 pr-4 py-2 border rounded-md"
          />
        </div>
        {allowCreate && (
          <button
            onClick={() => setShowCreate(true)}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700"
          >
            <PlusIcon className="w-5 h-5" />
            Add Domain
          </button>
        )}
      </div>

      {error && (
        <div className="mb-4 bg-red-50 border border-red-200 rounded-md p-3 text-red-700">
          {error}
        </div>
      )}

      <div className="flex-1 overflow-y-auto">
        {loading ? (
          <div className="text-center py-8 text-gray-500">Loading domains...</div>
        ) : filteredDomains.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            {searchQuery ? 'No domains match your search' : 'No domains found'}
          </div>
        ) : (
          <div className="grid gap-4">
            {filteredDomains.map(domain => (
              <div
                key={domain.id}
                onClick={() => {
                  setSelectedDomain(domain);
                  setShowDetail(true);
                }}
                className="p-4 border rounded-lg hover:border-blue-500 cursor-pointer transition-colors"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-medium">{domain.name}</h3>
                      {domain.customDomain && (
                        <GlobeAltIcon className="w-4 h-4 text-gray-400" />
                      )}
                    </div>
                    <p className="text-sm text-gray-500">{domain.slug}</p>
                    {domain.customDomain && (
                      <p className="text-sm text-blue-600 mt-1">{domain.customDomain}</p>
                    )}
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <DnsStatusBadge
                      hasCustomDomain={!!domain.customDomain}
                      isVerified={domain.customDomainVerified}
                      isConfigured={domain.dnsStatus?.configured}
                      compact={true}
                    />
                    {domain.customDomainVerified && (
                      <div className="flex items-center text-green-600 text-sm">
                        <CheckCircleIcon className="w-5 h-5 mr-1" />
                        Verified
                      </div>
                    )}
                  </div>
                </div>
                {domain.description && (
                  <p className="mt-2 text-sm text-gray-600">{domain.description}</p>
                )}
                
                {/* Show DNS information if available and not verified */}
                {domain.customDomain && !domain.customDomainVerified && domain.dnsStatus && (
                  <div className="mt-3">
                    <DnsInfoPanel
                      records={domain.dnsStatus.records || []}
                      nameServers={domain.dnsStatus.nameServers || []}
                      configured={domain.dnsStatus.configured}
                      verified={domain.customDomainVerified}
                      compact={true}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      <AnimatePresence>
        {showDetail && selectedDomain && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50"
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="bg-white border rounded-lg shadow-xl max-w-4xl w-full mx-4 max-h-[90vh] overflow-hidden"
            >
              <DomainDetailForm
                domain={selectedDomain}
                onSave={(formData) => handleUpdateDomain(selectedDomain.id, formData)}
                onClose={() => {
                  setShowDetail(false);
                  setSelectedDomain(null);
                }}
              />
            </motion.div>
          </motion.div>
        )}

        {showCreate && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50"
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="bg-white border rounded-lg shadow-xl max-w-2xl w-full mx-4"
            >
              <DomainDetailForm
                onSave={handleCreateDomain}
                onClose={() => setShowCreate(false)}
              />
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default DomainManager;

import React, { useEffect, useState } from 'react';
import { apiFetch } from '../../lib/api';
import { ROLE_OPTIONS } from '@keeper/shared';
import { XMarkIcon, PlusIcon } from '@heroicons/react/24/outline';
import type { DomainScope } from './DomainManager';

interface Member {
  userId: string;
  name: string;
  role: string;
  expiresAt?: string;
}

interface Props {
  domainId: string;
  scope: DomainScope;
}

const MembersPanel: React.FC<Props> = ({ domainId, scope }) => {
  const [members, setMembers] = useState<Member[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [search, setSearch] = useState('');
  const [results, setResults] = useState<{ id: string; label: string }[]>([]);
  const [selectedUser, setSelectedUser] = useState<{ id: string; label: string } | null>(null);
  const [role, setRole] = useState('user');

  const base = scope === 'user' ? '/api/domains' : '/api/admin/domains';

  const load = async () => {
    setLoading(true);
    try {
      const data = await apiFetch(`${base}/${domainId}/members`);
      setMembers(data.members);
    } catch (e) {
      console.error('load members error', e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, [domainId]);

  // search users
  useEffect(() => {
    if (!showAdd) return;
    const t = setTimeout(async () => {
      try {
        if (!search.trim()) return;
        const data = await apiFetch(`/api/users/search?q=${encodeURIComponent(search.trim())}`);
        setResults(data.users);
      } catch (e) { console.error(e); }
    }, 300);
    return () => clearTimeout(t);
  }, [search, showAdd]);

  const addMember = async () => {
    if (!selectedUser) return;
    try {
      await apiFetch(`${base}/${domainId}/members`, {
        method: 'POST',
        body: JSON.stringify({ userId: selectedUser.id, role }),
      });
      setShowAdd(false);
      setSearch('');
      setSelectedUser(null);
      load();
    } catch (e) { console.error(e); }
  };

  const remove = async (uid: string) => {
    if (!confirm('Remove member?')) return;
    try {
      await apiFetch(`${base}/${domainId}/members/${uid}`, { method: 'DELETE' });
      load();
    } catch (e) { console.error(e); }
  };

  return (
    <div className="border rounded p-4 space-y-3 bg-card">
      <div className="flex justify-between items-center">
        <h3 className="font-medium">Members</h3>
        <button onClick={()=>setShowAdd(true)} className="flex items-center text-xs gap-1"><PlusIcon className="w-4 h-4"/>Add</button>
      </div>
      {loading ? 'Loading…' : (
        <table className="w-full text-xs border">
          <thead><tr className="bg-muted text-left"><th className="p-1">Name</th><th className="p-1">Role</th><th></th></tr></thead>
          <tbody>
            {members.map(m=> (
              <tr key={m.userId} className="border-t"><td className="p-1">{m.name}</td><td className="p-1 capitalize">{m.role}</td><td className="p-1 text-right"><button onClick={()=>remove(m.userId)} className="text-red-600"><XMarkIcon className="w-4 h-4"/></button></td></tr>
            ))}
          </tbody>
        </table>
      )}
      {showAdd && (
        <div className="border p-2 rounded space-y-2 bg-muted/10">
          <input value={search} onChange={(e)=>setSearch(e.target.value)} placeholder="Search user…" className="border p-1 w-full text-xs" />
          {results.length>0 && (
            <div className="max-h-24 overflow-y-auto border rounded bg-background">
              {results.map(r=> (
                <div key={r.id} onClick={()=>{setSelectedUser(r); setResults([]); setSearch(r.label);}} className="px-1 py-0.5 text-xs hover:bg-muted cursor-pointer">{r.label}</div>
              ))}
            </div>
          )}
          <select value={role} onChange={(e)=>setRole(e.target.value)} className="border p-1 text-xs w-full">
            {ROLE_OPTIONS.map((o: { value: string; label: string }) => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>
          <div className="flex gap-2 text-xs"><button onClick={addMember} className="px-2 py-0.5 bg-primary text-white rounded">Add</button><button onClick={()=>setShowAdd(false)} className="px-2 py-0.5 border rounded">Cancel</button></div>
        </div>
      )}
    </div>
  );
};

export default MembersPanel;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { 
  PlusIcon, 
  PencilIcon, 
  TrashIcon, 
  ClockIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  CalendarDaysIcon,
  BellIcon
} from '@heroicons/react/24/outline';
import { SoleEcho, SoleEchoListResponse, CreateEchoRequest } from '../../types/keeper';

interface EchoWriterProps {
  keeperId: string;
  agentId: string;
  isDemo?: boolean;
}

const EchoWriter: React.FC<EchoWriterProps> = ({ keeperId, agentId, isDemo = false }) => {
  const [echoes, setEchoes] = useState<SoleEcho[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'pending' | 'delivered' | 'all'>('pending');
  const [formData, setFormData] = useState({ 
    message: '', 
    triggerDate: '', 
    triggerConditions: {} 
  });

  // Demo data
  const demoEchoes: SoleEcho[] = [
    {
      id: 'demo-echo-1',
      keeperId,
      agentId,
      message: 'Remember to check if your communication style has evolved since last month. How has your approach to helping users changed?',
      triggerDate: '2024-02-15T10:00:00Z',
      triggerConditions: undefined,
      createdAt: '2024-01-15T10:00:00Z',
      delivered: false
    },
    {
      id: 'demo-echo-2',
      keeperId,
      agentId,
      message: 'Reflect on the problem-solving techniques you\'ve used this week. What patterns do you notice in your approach?',
      triggerDate: '2024-01-20T14:30:00Z',
      triggerConditions: undefined,
      createdAt: '2024-01-13T14:30:00Z',
      delivered: true
    },
    {
      id: 'demo-echo-3',
      keeperId,
      agentId,
      message: 'Consider how your learning mindset has influenced your recent interactions. What new insights have you gained?',
      triggerDate: undefined,
      triggerConditions: { trigger: 'weekly_review' },
      createdAt: '2024-01-12T09:15:00Z',
      delivered: false
    }
  ];

  const fetchEchoes = async () => {
    if (isDemo) {
      setEchoes(demoEchoes);
      setLoading(false);
      return;
    }

    try {
      const response = await fetch(`/api/keeper/keepers/${keeperId}/echoes?userId=${agentId}`);
      
      if (!response.ok) {
        throw new Error('Failed to fetch echoes');
      }

      const data: SoleEchoListResponse = await response.json();
      
      if (data.success && data.data) {
        setEchoes(data.data);
      } else {
        throw new Error(data.error || 'Failed to fetch echoes');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const createEcho = async (echoData: CreateEchoRequest) => {
    if (isDemo) {
      const newEcho: SoleEcho = {
        id: `demo-echo-${Date.now()}`,
        ...echoData,
        createdAt: new Date().toISOString(),
        delivered: false
      };
      setEchoes([newEcho, ...echoes]);
      return;
    }

    try {
      const response = await fetch(`/api/keeper/keepers/${keeperId}/echoes?userId=${agentId}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(echoData),
      });

      if (!response.ok) {
        throw new Error('Failed to create echo');
      }

      const data = await response.json();
      if (data.success && data.data) {
        setEchoes([data.data, ...echoes]);
      } else {
        throw new Error(data.error || 'Failed to create echo');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    }
  };

  const updateEcho = async (id: string, updates: Partial<SoleEcho>) => {
    if (isDemo) {
      setEchoes(echoes.map(echo => 
        echo.id === id ? { ...echo, ...updates } : echo
      ));
      return;
    }

    try {
      const response = await fetch(`/api/keeper/echoes/${id}?userId=${agentId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(updates),
      });

      if (!response.ok) {
        throw new Error('Failed to update echo');
      }

      const data = await response.json();
      if (data.success && data.data) {
        setEchoes(echoes.map(echo => 
          echo.id === id ? data.data : echo
        ));
      } else {
        throw new Error(data.error || 'Failed to update echo');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    }
  };

  const deleteEcho = async (id: string) => {
    if (isDemo) {
      setEchoes(echoes.filter(echo => echo.id !== id));
      return;
    }

    try {
      const response = await fetch(`/api/keeper/echoes/${id}?userId=${agentId}`, {
        method: 'DELETE',
      });

      if (!response.ok) {
        throw new Error('Failed to delete echo');
      }

      setEchoes(echoes.filter(echo => echo.id !== id));
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    }
  };

  const deliverEcho = async (id: string) => {
    if (isDemo) {
      setEchoes(echoes.map(echo => 
        echo.id === id ? { ...echo, delivered: true } : echo
      ));
      return;
    }

    try {
      const response = await fetch(`/api/keeper/echoes/${id}/deliver?userId=${agentId}`, {
        method: 'POST',
      });

      if (!response.ok) {
        throw new Error('Failed to deliver echo');
      }

      const data = await response.json();
      if (data.success && data.data) {
        setEchoes(echoes.map(echo => 
          echo.id === id ? data.data : echo
        ));
      } else {
        throw new Error(data.error || 'Failed to deliver echo');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    }
  };

  useEffect(() => {
    fetchEchoes();
  }, [keeperId, agentId, isDemo]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.message.trim()) {
      setError('Message is required');
      return;
    }

    const echoData: CreateEchoRequest = {
      keeperId,
      agentId,
      message: formData.message.trim(),
      triggerDate: formData.triggerDate || undefined,
      triggerConditions: Object.keys(formData.triggerConditions).length > 0 
        ? formData.triggerConditions 
        : undefined
    };

    if (editingId) {
      await updateEcho(editingId, echoData);
      setEditingId(null);
    } else {
      await createEcho(echoData);
    }

    setFormData({ message: '', triggerDate: '', triggerConditions: {} });
    setIsCreating(false);
  };

  const handleEdit = (echo: SoleEcho) => {
    setEditingId(echo.id);
    setFormData({ 
      message: echo.message, 
      triggerDate: echo.triggerDate || '',
      triggerConditions: echo.triggerConditions || {}
    });
    setIsCreating(true);
  };

  const handleCancel = () => {
    setIsCreating(false);
    setEditingId(null);
    setFormData({ message: '', triggerDate: '', triggerConditions: {} });
  };

  const getFilteredEchoes = () => {
    switch (activeTab) {
      case 'pending':
        return echoes.filter(echo => !echo.delivered);
      case 'delivered':
        return echoes.filter(echo => echo.delivered);
      default:
        return echoes;
    }
  };

  const isEchoTriggered = (echo: SoleEcho) => {
    if (!echo.triggerDate) return false;
    return new Date(echo.triggerDate) <= new Date();
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const formatDateInput = (dateString: string) => {
    return new Date(dateString).toISOString().slice(0, 16);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-4">
        <p className="text-red-800">Error: {error}</p>
        <button 
          onClick={() => {
            setError(null);
            setLoading(true);
            fetchEchoes();
          }}
          className="mt-2 text-sm text-red-600 hover:text-red-800 underline"
        >
          Try again
        </button>
      </div>
    );
  }

  const filteredEchoes = getFilteredEchoes();

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Echo Writer</h2>
          <p className="text-gray-600">Time-triggered messages for future reflection</p>
        </div>
        <div className="flex items-center gap-3">
          {isDemo && (
            <div className="bg-blue-50 border border-blue-200 rounded-lg px-3 py-1 text-sm text-blue-700">
              Demo Mode
            </div>
          )}
          <button
            onClick={() => setIsCreating(true)}
            className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <PlusIcon className="h-4 w-4" />
            Create Echo
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
        {[
          { key: 'pending', label: 'Pending', count: echoes.filter(e => !e.delivered).length },
          { key: 'delivered', label: 'Delivered', count: echoes.filter(e => e.delivered).length },
          { key: 'all', label: 'All', count: echoes.length }
        ].map(tab => (
          <button
            key={tab.key}
            onClick={() => setActiveTab(tab.key as any)}
            className={`flex-1 px-4 py-2 text-sm font-medium rounded-md transition-colors ${
              activeTab === tab.key
                ? 'bg-white text-blue-600 shadow-sm'
                : 'text-gray-600 hover:text-gray-900'
            }`}
          >
            {tab.label} ({tab.count})
          </button>
        ))}
      </div>

      {/* Create/Edit Form */}
      {isCreating && (
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-white border border-gray-200 rounded-lg p-6"
        >
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            {editingId ? 'Edit Echo' : 'Create New Echo'}
          </h3>
          
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Message
              </label>
              <textarea
                value={formData.message}
                onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                rows={3}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="Message to surface in the future..."
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Trigger Date (Optional)
                </label>
                <input
                  type="datetime-local"
                  value={formData.triggerDate}
                  onChange={(e) => setFormData({ ...formData, triggerDate: e.target.value })}
                  className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Conditions (Optional)
                </label>
                <input
                  type="text"
                  placeholder="e.g., weekly_review, milestone_reached"
                  className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>

            <div className="flex justify-end gap-3">
              <button
                type="button"
                onClick={handleCancel}
                className="px-4 py-2 text-gray-600 hover:text-gray-800 border border-gray-300 rounded-md hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700"
              >
                {editingId ? 'Update' : 'Create'}
              </button>
            </div>
          </form>
        </motion.div>
      )}

      {/* Echoes */}
      <div className="space-y-4">
        {filteredEchoes.length === 0 ? (
          <div className="text-center py-12">
            <BellIcon className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No echoes found</p>
            <p className="text-sm text-gray-400 mt-1">
              Create echoes to receive future reminders and reflections
            </p>
          </div>
        ) : (
          filteredEchoes.map((echo) => (
            <motion.div
              key={echo.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="bg-white border border-gray-200 rounded-lg p-6 hover:shadow-md transition-shadow"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-3">
                    <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                      echo.delivered 
                        ? 'bg-green-100 text-green-800' 
                        : isEchoTriggered(echo)
                        ? 'bg-yellow-100 text-yellow-800'
                        : 'bg-gray-100 text-gray-800'
                    }`}>
                      {echo.delivered ? (
                        <>
                          <CheckCircleIcon className="h-3 w-3 mr-1" />
                          Delivered
                        </>
                      ) : isEchoTriggered(echo) ? (
                        <>
                          <ExclamationCircleIcon className="h-3 w-3 mr-1" />
                          Ready
                        </>
                      ) : (
                        <>
                          <ClockIcon className="h-3 w-3 mr-1" />
                          Pending
                        </>
                      )}
                    </span>
                  </div>

                  <p className="text-gray-900 mb-4 leading-relaxed">
                    {echo.message}
                  </p>

                  <div className="flex items-center gap-4 text-sm text-gray-500">
                    <div className="flex items-center gap-1">
                      <CalendarDaysIcon className="h-4 w-4" />
                      Created {formatDate(echo.createdAt)}
                    </div>
                    {echo.triggerDate && (
                      <div className="flex items-center gap-1">
                        <ClockIcon className="h-4 w-4" />
                        Trigger {formatDate(echo.triggerDate)}
                      </div>
                    )}
                    {echo.triggerConditions && (
                      <div className="text-xs bg-gray-100 px-2 py-1 rounded">
                        Conditional
                      </div>
                    )}
                  </div>
                </div>

                <div className="flex items-center gap-2 ml-4">
                  {!echo.delivered && isEchoTriggered(echo) && (
                    <button
                      onClick={() => deliverEcho(echo.id)}
                      className="p-2 text-green-600 hover:text-green-700 transition-colors"
                      title="Mark as delivered"
                    >
                      <CheckCircleIcon className="h-4 w-4" />
                    </button>
                  )}
                  
                  {!echo.delivered && (
                    <button
                      onClick={() => handleEdit(echo)}
                      className="p-2 text-gray-400 hover:text-blue-600 transition-colors"
                    >
                      <PencilIcon className="h-4 w-4" />
                    </button>
                  )}
                  
                  <button
                    onClick={() => setDeletingId(echo.id)}
                    className="p-2 text-gray-400 hover:text-red-600 transition-colors"
                  >
                    <TrashIcon className="h-4 w-4" />
                  </button>
                </div>
              </div>
            </motion.div>
          ))
        )}
      </div>

      {/* Stats */}
      <div className="bg-gray-50 rounded-lg p-4">
        <h3 className="text-sm font-medium text-gray-900 mb-2">Echo Statistics</h3>
        <div className="grid grid-cols-4 gap-4 text-center">
          <div>
            <div className="text-2xl font-bold text-gray-900">{echoes.length}</div>
            <div className="text-xs text-gray-500">Total</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-yellow-600">
              {echoes.filter(e => !e.delivered && isEchoTriggered(e)).length}
            </div>
            <div className="text-xs text-gray-500">Ready</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-blue-600">
              {echoes.filter(e => !e.delivered && !isEchoTriggered(e)).length}
            </div>
            <div className="text-xs text-gray-500">Pending</div>
          </div>
          <div>
            <div className="text-2xl font-bold text-green-600">
              {echoes.filter(e => e.delivered).length}
            </div>
            <div className="text-xs text-gray-500">Delivered</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EchoWriter;

