/**
 * Process Frame
 * =============
 * 
 * Frame component for step-based UI flows and wizard-like processes.
 * Supports multi-step workflows with progress tracking.
 */

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeftIcon,
  ArrowRightIcon,
  CheckIcon,
  ClockIcon
} from '@heroicons/react/24/outline';
import { BaseFrameProps } from '../../types/frame';
import { useFrame } from '../../context/FrameContext';

interface ProcessStep {
  id: string;
  title: string;
  description?: string;
  content: React.ReactNode;
  isComplete?: boolean;
  isOptional?: boolean;
  validation?: () => boolean;
}

interface ProcessFrameProps extends BaseFrameProps {
  steps?: ProcessStep[];
  currentStep?: number;
  onStepChange?: (stepIndex: number) => void;
  onComplete?: () => void;
  allowSkipSteps?: boolean;
}

const ProcessFrame: React.FC<ProcessFrameProps> = ({
  frameInstance,
  className = '',
  onInteraction,
  isPreview = false,
  steps = [],
  currentStep = 0,
  onStepChange,
  onComplete,
  allowSkipSteps = false,
}) => {
  const { handleFrameInteraction } = useFrame();
  const [activeStep, setActiveStep] = useState(currentStep);
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());
  const [isLoading, setIsLoading] = useState(false);

  // Default steps if none provided
  const defaultSteps: ProcessStep[] = [
    {
      id: 'step1',
      title: 'Getting Started',
      description: 'Initial configuration and setup',
      content: (
        <div className="space-y-4">
          <p className="text-gray-600">Welcome to the setup process.</p>
          <div className="bg-blue-50 p-4 rounded-lg">
            <p className="text-sm text-blue-800">
              This is a sample process frame. Replace with your actual content.
            </p>
          </div>
        </div>
      )
    },
    {
      id: 'step2',
      title: 'Configuration',
      description: 'Set up your preferences',
      content: (
        <div className="space-y-4">
          <p className="text-gray-600">Configure your settings here.</p>
          <div className="space-y-2">
            <label className="flex items-center">
              <input type="checkbox" className="mr-2" />
              <span className="text-sm">Enable notifications</span>
            </label>
            <label className="flex items-center">
              <input type="checkbox" className="mr-2" />
              <span className="text-sm">Auto-save changes</span>
            </label>
          </div>
        </div>
      )
    },
    {
      id: 'step3',
      title: 'Review',
      description: 'Confirm your settings',
      content: (
        <div className="space-y-4">
          <p className="text-gray-600">Review your configuration before completing.</p>
          <div className="bg-gray-50 p-4 rounded-lg">
            <h4 className="font-medium mb-2">Summary</h4>
            <ul className="text-sm text-gray-600 space-y-1">
              <li>• Initial setup completed</li>
              <li>• Configuration applied</li>
              <li>• Ready to proceed</li>
            </ul>
          </div>
        </div>
      )
    }
  ];

  const displaySteps = steps.length > 0 ? steps : defaultSteps;
  const canGoNext = activeStep < displaySteps.length - 1;
  const canGoPrevious = activeStep > 0;
  const isLastStep = activeStep === displaySteps.length - 1;

  const handleNext = async () => {
    const currentStepData = displaySteps[activeStep];
    
    // Validate current step if validation function exists
    if (currentStepData.validation && !currentStepData.validation()) {
      return;
    }

    setIsLoading(true);

    try {
      // Mark current step as completed
      setCompletedSteps(prev => new Set([...prev, activeStep]));

      // Handle interaction
      handleFrameInteraction({
        type: 'navigate',
        frameId: frameInstance.id,
        data: { action: 'next_step', fromStep: activeStep, toStep: activeStep + 1 },
        timestamp: new Date(),
      });

      if (isLastStep) {
        // Complete the process
        onComplete?.();
        handleFrameInteraction({
          type: 'submit',
          frameId: frameInstance.id,
          data: { action: 'process_complete' },
          timestamp: new Date(),
        });
      } else {
        // Move to next step
        const nextStep = activeStep + 1;
        setActiveStep(nextStep);
        onStepChange?.(nextStep);
      }
    } catch (error) {
      console.error('Error proceeding to next step:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePrevious = () => {
    if (canGoPrevious) {
      const prevStep = activeStep - 1;
      setActiveStep(prevStep);
      onStepChange?.(prevStep);
      
      handleFrameInteraction({
        type: 'navigate',
        frameId: frameInstance.id,
        data: { action: 'previous_step', fromStep: activeStep, toStep: prevStep },
        timestamp: new Date(),
      });
    }
  };

  const handleStepClick = (stepIndex: number) => {
    if (!allowSkipSteps && stepIndex > activeStep) {
      return; // Can't skip ahead
    }

    setActiveStep(stepIndex);
    onStepChange?.(stepIndex);
    
    handleFrameInteraction({
      type: 'click',
      frameId: frameInstance.id,
      data: { action: 'jump_to_step', step: stepIndex },
      timestamp: new Date(),
    });
  };

  if (isPreview) {
    return (
      <div className={`bg-white border border-gray-200 rounded-lg p-4 ${className}`}>
        <div className="flex items-center space-x-2 mb-2">
          <ClockIcon className="w-5 h-5 text-blue-600" />
          <h3 className="font-medium text-gray-900">Process Frame</h3>
        </div>
        <p className="text-sm text-gray-600">
          Step-based workflow interface with progress tracking.
        </p>
        <div className="mt-3 flex space-x-2">
          {[0, 1, 2].map((i) => (
            <div
              key={i}
              className={`w-8 h-2 rounded-full ${
                i === 0 ? 'bg-blue-600' : 'bg-gray-200'
              }`}
            />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className={`bg-white border border-gray-200 rounded-lg overflow-hidden ${className}`}>
      {/* Header with Progress */}
      <div className="bg-gray-50 px-6 py-4 border-b border-gray-200">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-medium text-gray-900">
            {frameInstance.FrameConfig?.name || 'Process Workflow'}
          </h3>
          <span className="text-sm text-gray-500">
            Step {activeStep + 1} of {displaySteps.length}
          </span>
        </div>

        {/* Progress Bar */}
        <div className="relative">
          <div className="flex items-center">
            {displaySteps.map((step, index) => (
              <React.Fragment key={step.id}>
                <button
                  onClick={() => handleStepClick(index)}
                  disabled={!allowSkipSteps && index > activeStep}
                  className={`relative flex items-center justify-center w-8 h-8 rounded-full border-2 transition-colors ${
                    completedSteps.has(index)
                      ? 'bg-green-500 border-green-500 text-white'
                      : index === activeStep
                      ? 'bg-blue-600 border-blue-600 text-white'
                      : index < activeStep || allowSkipSteps
                      ? 'border-gray-300 text-gray-500 hover:border-gray-400'
                      : 'border-gray-200 text-gray-300 cursor-not-allowed'
                  }`}
                >
                  {completedSteps.has(index) ? (
                    <CheckIcon className="w-4 h-4" />
                  ) : (
                    <span className="text-sm font-medium">{index + 1}</span>
                  )}
                </button>
                
                {index < displaySteps.length - 1 && (
                  <div
                    className={`flex-1 h-1 mx-2 rounded-full transition-colors ${
                      index < activeStep ? 'bg-blue-600' : 'bg-gray-200'
                    }`}
                  />
                )}
              </React.Fragment>
            ))}
          </div>
        </div>

        {/* Step Labels */}
        <div className="flex justify-between mt-2">
          {displaySteps.map((step, index) => (
            <div
              key={step.id}
              className={`text-xs text-center ${
                index === activeStep ? 'text-blue-600 font-medium' : 'text-gray-500'
              }`}
              style={{ width: `${100 / displaySteps.length}%` }}
            >
              {step.title}
            </div>
          ))}
        </div>
      </div>

      {/* Step Content */}
      <div className="p-6">
        <AnimatePresence mode="wait">
          <motion.div
            key={activeStep}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.3 }}
          >
            <div className="mb-4">
              <h2 className="text-xl font-semibold text-gray-900 mb-2">
                {displaySteps[activeStep].title}
              </h2>
              {displaySteps[activeStep].description && (
                <p className="text-gray-600">
                  {displaySteps[activeStep].description}
                </p>
              )}
            </div>
            
            <div className="min-h-[200px]">
              {displaySteps[activeStep].content}
            </div>
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Navigation */}
      <div className="bg-gray-50 px-6 py-4 border-t border-gray-200 flex items-center justify-between">
        <button
          onClick={handlePrevious}
          disabled={!canGoPrevious || isLoading}
          className="flex items-center space-x-2 px-4 py-2 text-sm text-gray-600 hover:text-gray-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          <ArrowLeftIcon className="w-4 h-4" />
          <span>Previous</span>
        </button>

        <div className="flex items-center space-x-2">
          {displaySteps[activeStep].isOptional && (
            <button
              onClick={handleNext}
              disabled={isLoading}
              className="px-4 py-2 text-sm text-gray-600 hover:text-gray-800 disabled:opacity-50 transition-colors"
            >
              Skip
            </button>
          )}
          
          <button
            onClick={handleNext}
            disabled={isLoading}
            className="flex items-center space-x-2 px-6 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            {isLoading ? (
              <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <>
                <span>{isLastStep ? 'Complete' : 'Next'}</span>
                {!isLastStep && <ArrowRightIcon className="w-4 h-4" />}
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProcessFrame;

/**
 * Setup Steps Frame
 * =================
 * 
 * Process frame component for displaying domain setup progress.
 * Shows step-by-step configuration with completion status.
 */

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  CheckCircleIcon,
  ClockIcon,
  ExclamationCircleIcon,
  ArrowRightIcon,
  Cog6ToothIcon,
  GlobeAltIcon,
  UserGroupIcon,
  ShieldCheckIcon
} from '@heroicons/react/24/outline';
import { BaseFrameProps } from '../../types/frame';
import { useFrame } from '../../context/FrameContext';

interface SetupStep {
  id: string;
  title: string;
  description: string;
  status: 'completed' | 'current' | 'pending' | 'error';
  icon: React.ReactNode;
  estimatedTime?: string;
  actionLabel?: string;
}

const SetupStepsFrame: React.FC<BaseFrameProps> = ({
  frameInstance,
  className = '',
  onInteraction,
  isPreview = false,
}) => {
  const { handleFrameInteraction } = useFrame();
  const [currentStep, setCurrentStep] = useState(1);

  // Mock setup steps data
  const setupSteps: SetupStep[] = [
    {
      id: 'domain-info',
      title: 'Domain Information',
      description: 'Configure basic domain settings and branding',
      status: 'completed',
      icon: <GlobeAltIcon className="w-5 h-5" />,
      estimatedTime: '2 min',
      actionLabel: 'Edit Info'
    },
    {
      id: 'team-setup',
      title: 'Team Setup',
      description: 'Invite team members and assign roles',
      status: 'current',
      icon: <UserGroupIcon className="w-5 h-5" />,
      estimatedTime: '5 min',
      actionLabel: 'Add Members'
    },
    {
      id: 'custom-domain',
      title: 'Custom Domain',
      description: 'Configure DNS settings and custom domain',
      status: 'pending',
      icon: <Cog6ToothIcon className="w-5 h-5" />,
      estimatedTime: '3 min',
      actionLabel: 'Configure DNS'
    },
    {
      id: 'security',
      title: 'Security & Permissions',
      description: 'Set up authentication and access controls',
      status: 'pending',
      icon: <ShieldCheckIcon className="w-5 h-5" />,
      estimatedTime: '4 min',
      actionLabel: 'Configure Security'
    }
  ];

  const getStatusIcon = (status: SetupStep['status']) => {
    switch (status) {
      case 'completed':
        return <CheckCircleIcon className="w-6 h-6 text-green-500" />;
      case 'current':
        return <ClockIcon className="w-6 h-6 text-blue-500 animate-pulse" />;
      case 'error':
        return <ExclamationCircleIcon className="w-6 h-6 text-red-500" />;
      default:
        return <div className="w-6 h-6 rounded-full border-2 border-gray-300" />;
    }
  };

  const getStepColor = (status: SetupStep['status']) => {
    switch (status) {
      case 'completed':
        return 'border-green-200 bg-green-50';
      case 'current':
        return 'border-blue-200 bg-blue-50 ring-2 ring-blue-500 ring-opacity-20';
      case 'error':
        return 'border-red-200 bg-red-50';
      default:
        return 'border-gray-200 bg-white';
    }
  };

  const handleStepAction = (step: SetupStep) => {
    const interaction = {
      type: 'click' as const,
      frameId: frameInstance.id,
      data: { 
        action: 'step_action', 
        stepId: step.id,
        stepTitle: step.title 
      },
      timestamp: new Date(),
    };
    
    handleFrameInteraction(interaction);
    onInteraction?.(interaction);

    // Update current step for demo purposes
    const stepIndex = setupSteps.findIndex(s => s.id === step.id);
    if (stepIndex !== -1) {
      setCurrentStep(stepIndex);
    }
  };

  const completedSteps = setupSteps.filter(step => step.status === 'completed').length;
  const totalSteps = setupSteps.length;
  const progressPercentage = Math.round((completedSteps / totalSteps) * 100);

  if (isPreview) {
    return (
      <div className={`bg-white border border-gray-200 rounded-lg p-4 ${className}`}>
        <div className="flex items-center space-x-2 mb-2">
          <ClockIcon className="w-5 h-5 text-blue-600" />
          <h3 className="font-medium text-gray-900">Setup Steps</h3>
        </div>
        <p className="text-sm text-gray-600">
          Track domain configuration progress with step-by-step guidance.
        </p>
      </div>
    );
  }

  return (
    <div className={`bg-white border border-gray-200 rounded-lg overflow-hidden ${className}`}>
      {/* Header */}
      <div className="bg-gray-50 px-6 py-4 border-b border-gray-200">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-lg font-semibold text-gray-900">Setup Progress</h3>
            <p className="text-sm text-gray-600 mt-1">Complete these steps to finish your domain setup</p>
          </div>
          <div className="text-right">
            <div className="text-2xl font-bold text-blue-600">{progressPercentage}%</div>
            <div className="text-xs text-gray-500">{completedSteps} of {totalSteps} complete</div>
          </div>
        </div>

        {/* Progress Bar */}
        <div className="mt-4">
          <div className="w-full bg-gray-200 rounded-full h-2">
            <motion.div
              className="h-2 rounded-full bg-blue-600"
              initial={{ width: 0 }}
              animate={{ width: `${progressPercentage}%` }}
              transition={{ duration: 1, delay: 0.3 }}
            />
          </div>
        </div>
      </div>

      {/* Steps List */}
      <div className="p-6">
        <div className="space-y-4">
          <AnimatePresence>
            {setupSteps.map((step, index) => (
              <motion.div
                key={step.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: index * 0.1 }}
                className={`border rounded-lg p-4 transition-all duration-200 ${getStepColor(step.status)}`}
              >
                <div className="flex items-start space-x-4">
                  {/* Status Icon */}
                  <div className="flex-shrink-0 mt-1">
                    {getStatusIcon(step.status)}
                  </div>

                  {/* Step Content */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <h4 className="text-base font-medium text-gray-900 mb-1">
                          {step.title}
                        </h4>
                        <p className="text-sm text-gray-600 mb-2">
                          {step.description}
                        </p>
                        
                        {step.estimatedTime && (
                          <div className="flex items-center text-xs text-gray-500">
                            <ClockIcon className="w-3 h-3 mr-1" />
                            <span>Estimated time: {step.estimatedTime}</span>
                          </div>
                        )}
                      </div>

                      {/* Action Button */}
                      {step.status !== 'completed' && step.actionLabel && (
                        <button
                          onClick={() => handleStepAction(step)}
                          className={`ml-4 inline-flex items-center space-x-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                            step.status === 'current'
                              ? 'bg-blue-600 text-white hover:bg-blue-700'
                              : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                          }`}
                        >
                          <span>{step.actionLabel}</span>
                          <ArrowRightIcon className="w-4 h-4" />
                        </button>
                      )}

                      {step.status === 'completed' && (
                        <button
                          onClick={() => handleStepAction(step)}
                          className="ml-4 inline-flex items-center space-x-2 px-3 py-1.5 rounded-lg text-sm font-medium text-green-700 bg-green-100 hover:bg-green-200 transition-colors"
                        >
                          <span>Review</span>
                          <CheckCircleIcon className="w-4 h-4" />
                        </button>
                      )}
                    </div>
                  </div>
                </div>

                {/* Step Icon */}
                <div className="flex items-center justify-between mt-3 pt-3 border-t border-gray-200 border-opacity-50">
                  <div className="flex items-center space-x-2 text-gray-500">
                    {step.icon}
                    <span className="text-xs font-medium">Step {index + 1}</span>
                  </div>
                  
                  {step.status === 'current' && (
                    <div className="flex items-center space-x-1">
                      <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></div>
                      <span className="text-xs text-blue-600 font-medium">In Progress</span>
                    </div>
                  )}
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      </div>

      {/* Footer */}
      <div className="bg-gray-50 px-6 py-4 border-t border-gray-200">
        <div className="flex items-center justify-between">
          <p className="text-sm text-gray-600">
            Need help? <a href="#" className="text-blue-600 hover:text-blue-700">View setup guide</a>
          </p>
          <div className="text-xs text-gray-500">
            {completedSteps === totalSteps ? 'Setup complete! 🎉' : `${totalSteps - completedSteps} steps remaining`}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SetupStepsFrame;

/**
 * Topics Frame
 * ============
 * 
 * Frame component for managing topics in Agent Home Boards.
 * Supports creating, editing, archiving topics and adding highlights.
 */

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  PlusIcon,
  TagIcon,
  ArchiveBoxIcon,
  ChatBubbleLeftRightIcon,
  DocumentTextIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  ClockIcon
} from '@heroicons/react/24/outline';
import { BaseFrameProps } from '../../types/frame';
import { Topic, TopicHighlight, CreateTopicRequest, CreateTopicHighlightRequest } from '../../types/keeper';
import { useFrame } from '../../context/FrameContext';

interface TopicsFrameProps extends BaseFrameProps {
  boardId?: string;
  view?: 'list' | 'grid' | 'compact';
  showTags?: boolean;
  groupBy?: 'status' | 'tags' | 'date';
  allowCreate?: boolean;
  allowEdit?: boolean;
}

const TopicsFrame: React.FC<TopicsFrameProps> = ({
  frameInstance,
  className = '',
  onInteraction,
  isPreview = false,
  boardId,
  view = 'list',
  showTags = true,
  groupBy = 'status',
  allowCreate = true,
  allowEdit = true,
}) => {
  const { handleFrameInteraction } = useFrame();
  const [topics, setTopics] = useState<Topic[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [editingTopic, setEditingTopic] = useState<Topic | null>(null);
  const [newTopicTitle, setNewTopicTitle] = useState('');
  const [newTopicTags, setNewTopicTags] = useState('');
  const [selectedTopic, setSelectedTopic] = useState<Topic | null>(null);
  const [showHighlightForm, setShowHighlightForm] = useState(false);
  const [newHighlight, setNewHighlight] = useState({
    kind: 'fact' as const,
    text: ''
  });

  // Load topics from API
  useEffect(() => {
    if (!boardId) return;

    const loadTopics = async () => {
      try {
        setIsLoading(true);
        setError(null);

        // TODO: Replace with actual API call
        const response = await fetch(`/api/board-data/${boardId}/topics`, {
          credentials: 'include'
        });

        if (!response.ok) {
          throw new Error('Failed to load topics');
        }

        const data = await response.json();
        setTopics(data.data || []);
      } catch (err) {
        console.error('Error loading topics:', err);
        setError(err instanceof Error ? err.message : 'Failed to load topics');
        
        // Mock data for development
        setTopics([
          {
            id: '1',
            boardId: boardId,
            title: 'Agent Configuration Best Practices',
            essence: 'Key principles for setting up effective AI agents',
            tags: ['configuration', 'best-practices'],
            status: 'active',
            lastActiveAt: new Date().toISOString(),
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            highlights: [
              {
                id: '1-1',
                topicId: '1',
                kind: 'fact',
                text: 'Clear purpose statements improve agent performance by 40%',
                createdAt: new Date().toISOString()
              }
            ]
          },
          {
            id: '2',
            boardId: boardId,
            title: 'Model Selection Strategy',
            tags: ['models', 'performance'],
            status: 'active',
            lastActiveAt: new Date(Date.now() - 86400000).toISOString(),
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            highlights: []
          }
        ]);
      } finally {
        setIsLoading(false);
      }
    };

    loadTopics();
  }, [boardId]);

  // Handle topic creation
  const handleCreateTopic = async () => {
    if (!newTopicTitle.trim() || !boardId) return;

    try {
      const request: CreateTopicRequest = {
        title: newTopicTitle.trim(),
        tags: newTopicTags.split(',').map(t => t.trim()).filter(t => t)
      };

      // TODO: Replace with actual API call
      const response = await fetch(`/api/board-data/${boardId}/topics`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(request)
      });

      if (!response.ok) {
        throw new Error('Failed to create topic');
      }

      const data = await response.json();
      const newTopic: Topic = data.data;
      
      setTopics(prev => [newTopic, ...prev]);
      setNewTopicTitle('');
      setNewTopicTags('');
      setShowCreateForm(false);

      handleFrameInteraction({
        type: 'submit',
        frameId: frameInstance.id,
        data: { action: 'create_topic', topicId: newTopic.id },
        timestamp: new Date(),
      });
    } catch (err) {
      console.error('Error creating topic:', err);
      setError(err instanceof Error ? err.message : 'Failed to create topic');
    }
  };

  // Handle topic archiving
  const handleArchiveTopic = async (topicId: string) => {
    try {
      // TODO: Replace with actual API call
      const response = await fetch(`/api/topics/${topicId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ status: 'archived' })
      });

      if (!response.ok) {
        throw new Error('Failed to archive topic');
      }

      setTopics(prev => prev.map(topic => 
        topic.id === topicId ? { ...topic, status: 'archived' } : topic
      ));

      handleFrameInteraction({
        type: 'click',
        frameId: frameInstance.id,
        data: { action: 'archive_topic', topicId },
        timestamp: new Date(),
      });
    } catch (err) {
      console.error('Error archiving topic:', err);
      setError(err instanceof Error ? err.message : 'Failed to archive topic');
    }
  };

  // Handle adding highlight
  const handleAddHighlight = async () => {
    if (!newHighlight.text.trim() || !selectedTopic) return;

    try {
      const request: CreateTopicHighlightRequest = {
        kind: newHighlight.kind,
        text: newHighlight.text.trim()
      };

      // TODO: Replace with actual API call
      const response = await fetch(`/api/topics/${selectedTopic.id}/highlights`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(request)
      });

      if (!response.ok) {
        throw new Error('Failed to add highlight');
      }

      const data = await response.json();
      const highlight: TopicHighlight = data.data;

      setTopics(prev => prev.map(topic => 
        topic.id === selectedTopic.id 
          ? { ...topic, highlights: [...(topic.highlights || []), highlight] }
          : topic
      ));

      setNewHighlight({ kind: 'fact', text: '' });
      setShowHighlightForm(false);
      setSelectedTopic(null);

      handleFrameInteraction({
        type: 'submit',
        frameId: frameInstance.id,
        data: { action: 'add_highlight', topicId: selectedTopic.id, highlightId: highlight.id },
        timestamp: new Date(),
      });
    } catch (err) {
      console.error('Error adding highlight:', err);
      setError(err instanceof Error ? err.message : 'Failed to add highlight');
    }
  };

  // Group topics by status
  const groupedTopics = React.useMemo(() => {
    if (groupBy === 'status') {
      const active = topics.filter(t => t.status === 'active');
      const archived = topics.filter(t => t.status === 'archived');
      return { active, archived };
    }
    return { all: topics };
  }, [topics, groupBy]);

  // Get icon for highlight kind
  const getHighlightIcon = (kind: TopicHighlight['kind']) => {
    switch (kind) {
      case 'fact': return <DocumentTextIcon className="w-4 h-4" />;
      case 'decision': return <CheckCircleIcon className="w-4 h-4" />;
      case 'task': return <ClockIcon className="w-4 h-4" />;
      case 'question': return <ChatBubbleLeftRightIcon className="w-4 h-4" />;
      case 'risk': return <ExclamationTriangleIcon className="w-4 h-4" />;
      default: return <DocumentTextIcon className="w-4 h-4" />;
    }
  };

  // Get color for highlight kind
  const getHighlightColor = (kind: TopicHighlight['kind']) => {
    switch (kind) {
      case 'fact': return 'text-blue-600 bg-blue-50';
      case 'decision': return 'text-green-600 bg-green-50';
      case 'task': return 'text-orange-600 bg-orange-50';
      case 'question': return 'text-purple-600 bg-purple-50';
      case 'risk': return 'text-red-600 bg-red-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  if (isLoading) {
    return (
      <div className={`p-6 ${className}`}>
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div>
        <p className="text-center text-gray-600 mt-4">Loading topics...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className={`p-6 ${className}`}>
        <div className="text-center">
          <ExclamationTriangleIcon className="w-12 h-12 text-red-500 mx-auto mb-4" />
          <p className="text-red-600">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`bg-white rounded-lg border border-gray-200 ${className}`}>
      {/* Header */}
      <div className="p-4 border-b border-gray-200">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <TagIcon className="w-5 h-5 text-gray-500" />
            <h3 className="text-lg font-medium text-gray-900">Topics</h3>
            <span className="text-sm text-gray-500">
              ({topics.filter(t => t.status === 'active').length} active)
            </span>
          </div>
          
          {allowCreate && !isPreview && (
            <button
              onClick={() => setShowCreateForm(true)}
              className="flex items-center space-x-1 px-3 py-1.5 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
            >
              <PlusIcon className="w-4 h-4" />
              <span>Add Topic</span>
            </button>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="p-4">
        {/* Create Form */}
        <AnimatePresence>
          {showCreateForm && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="mb-4 p-4 bg-gray-50 rounded-lg border"
            >
              <div className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Topic Title
                  </label>
                  <input
                    type="text"
                    value={newTopicTitle}
                    onChange={(e) => setNewTopicTitle(e.target.value)}
                    placeholder="Enter topic title..."
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    autoFocus
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Tags (comma-separated)
                  </label>
                  <input
                    type="text"
                    value={newTopicTags}
                    onChange={(e) => setNewTopicTags(e.target.value)}
                    placeholder="configuration, best-practices, ..."
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                </div>
                
                <div className="flex items-center space-x-2">
                  <button
                    onClick={handleCreateTopic}
                    disabled={!newTopicTitle.trim()}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                  >
                    Create Topic
                  </button>
                  <button
                    onClick={() => {
                      setShowCreateForm(false);
                      setNewTopicTitle('');
                      setNewTopicTags('');
                    }}
                    className="px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Topics List */}
        {groupBy === 'status' ? (
          <div className="space-y-6">
            {/* Active Topics */}
            {groupedTopics.active && groupedTopics.active.length > 0 && (
              <div>
                <h4 className="text-sm font-medium text-gray-900 mb-3 flex items-center">
                  <CheckCircleIcon className="w-4 h-4 text-green-500 mr-2" />
                  Active Topics ({groupedTopics.active.length})
                </h4>
                <div className="space-y-3">
                  {groupedTopics.active.map((topic) => (
                    <TopicCard
                      key={topic.id}
                      topic={topic}
                      showTags={showTags}
                      allowEdit={allowEdit}
                      onArchive={() => handleArchiveTopic(topic.id)}
                      onAddHighlight={() => {
                        setSelectedTopic(topic);
                        setShowHighlightForm(true);
                      }}
                      getHighlightIcon={getHighlightIcon}
                      getHighlightColor={getHighlightColor}
                    />
                  ))}
                </div>
              </div>
            )}

            {/* Archived Topics */}
            {groupedTopics.archived && groupedTopics.archived.length > 0 && (
              <div>
                <h4 className="text-sm font-medium text-gray-900 mb-3 flex items-center">
                  <ArchiveBoxIcon className="w-4 h-4 text-gray-500 mr-2" />
                  Archived Topics ({groupedTopics.archived.length})
                </h4>
                <div className="space-y-3">
                  {groupedTopics.archived.map((topic) => (
                    <TopicCard
                      key={topic.id}
                      topic={topic}
                      showTags={showTags}
                      allowEdit={false}
                      archived
                      getHighlightIcon={getHighlightIcon}
                      getHighlightColor={getHighlightColor}
                    />
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {topics.map((topic) => (
              <TopicCard
                key={topic.id}
                topic={topic}
                showTags={showTags}
                allowEdit={allowEdit}
                onArchive={() => handleArchiveTopic(topic.id)}
                onAddHighlight={() => {
                  setSelectedTopic(topic);
                  setShowHighlightForm(true);
                }}
                getHighlightIcon={getHighlightIcon}
                getHighlightColor={getHighlightColor}
              />
            ))}
          </div>
        )}

        {/* Empty State */}
        {topics.length === 0 && (
          <div className="text-center py-8">
            <TagIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No Topics Yet</h3>
            <p className="text-gray-600 mb-4">Create your first topic to start organizing your agent's knowledge.</p>
            {allowCreate && (
              <button
                onClick={() => setShowCreateForm(true)}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              >
                Create First Topic
              </button>
            )}
          </div>
        )}
      </div>

      {/* Highlight Form Modal */}
      <AnimatePresence>
        {showHighlightForm && selectedTopic && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
            onClick={() => setShowHighlightForm(false)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="bg-white rounded-lg p-6 max-w-md w-full mx-4"
              onClick={(e) => e.stopPropagation()}
            >
              <h3 className="text-lg font-medium text-gray-900 mb-4">
                Add Highlight to "{selectedTopic.title}"
              </h3>
              
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Highlight Type
                  </label>
                  <select
                    value={newHighlight.kind}
                    onChange={(e) => setNewHighlight(prev => ({ 
                      ...prev, 
                      kind: e.target.value as TopicHighlight['kind'] 
                    }))}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="fact">Fact</option>
                    <option value="decision">Decision</option>
                    <option value="task">Task</option>
                    <option value="question">Question</option>
                    <option value="risk">Risk</option>
                  </select>
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Highlight Text
                  </label>
                  <textarea
                    value={newHighlight.text}
                    onChange={(e) => setNewHighlight(prev => ({ ...prev, text: e.target.value }))}
                    placeholder="Enter the highlight text..."
                    rows={3}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                    autoFocus
                  />
                </div>
                
                <div className="flex items-center space-x-2">
                  <button
                    onClick={handleAddHighlight}
                    disabled={!newHighlight.text.trim()}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                  >
                    Add Highlight
                  </button>
                  <button
                    onClick={() => {
                      setShowHighlightForm(false);
                      setSelectedTopic(null);
                      setNewHighlight({ kind: 'fact', text: '' });
                    }}
                    className="px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

// Topic Card Component
interface TopicCardProps {
  topic: Topic;
  showTags: boolean;
  allowEdit: boolean;
  archived?: boolean;
  onArchive?: () => void;
  onAddHighlight?: () => void;
  getHighlightIcon: (kind: TopicHighlight['kind']) => React.ReactNode;
  getHighlightColor: (kind: TopicHighlight['kind']) => string;
}

const TopicCard: React.FC<TopicCardProps> = ({
  topic,
  showTags,
  allowEdit,
  archived = false,
  onArchive,
  onAddHighlight,
  getHighlightIcon,
  getHighlightColor,
}) => {
  return (
    <div className={`p-4 border rounded-lg ${archived ? 'bg-gray-50 border-gray-200' : 'bg-white border-gray-200 hover:border-gray-300'} transition-colors`}>
      <div className="flex items-start justify-between mb-2">
        <h4 className={`font-medium ${archived ? 'text-gray-600' : 'text-gray-900'}`}>
          {topic.title}
        </h4>
        
        {!archived && allowEdit && (
          <div className="flex items-center space-x-1 ml-2">
            {onAddHighlight && (
              <button
                onClick={onAddHighlight}
                className="p-1 text-gray-400 hover:text-blue-600 transition-colors"
                title="Add Highlight"
              >
                <PlusIcon className="w-4 h-4" />
              </button>
            )}
            {onArchive && (
              <button
                onClick={onArchive}
                className="p-1 text-gray-400 hover:text-orange-600 transition-colors"
                title="Archive Topic"
              >
                <ArchiveBoxIcon className="w-4 h-4" />
              </button>
            )}
          </div>
        )}
      </div>
      
      {topic.essence && (
        <p className={`text-sm mb-3 ${archived ? 'text-gray-500' : 'text-gray-600'}`}>
          {topic.essence}
        </p>
      )}
      
      {showTags && topic.tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-3">
          {topic.tags.map((tag) => (
            <span
              key={tag}
              className={`px-2 py-1 text-xs rounded-full ${
                archived 
                  ? 'bg-gray-100 text-gray-500' 
                  : 'bg-blue-100 text-blue-700'
              }`}
            >
              {tag}
            </span>
          ))}
        </div>
      )}
      
      {topic.highlights && topic.highlights.length > 0 && (
        <div className="space-y-2 mb-3">
          {topic.highlights.map((highlight) => (
            <div
              key={highlight.id}
              className={`flex items-start space-x-2 p-2 rounded text-xs ${getHighlightColor(highlight.kind)}`}
            >
              {getHighlightIcon(highlight.kind)}
              <span>{highlight.text}</span>
            </div>
          ))}
        </div>
      )}
      
      <div className="flex items-center justify-between text-xs text-gray-500">
        <span>
          {topic.highlights?.length || 0} highlight{(topic.highlights?.length || 0) !== 1 ? 's' : ''}
        </span>
        <span>
          Last active: {new Date(topic.lastActiveAt).toLocaleDateString()}
        </span>
      </div>
    </div>
  );
};

