                          <img src={person.avatar} alt={person.name} className="w-full h-full object-cover" />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center">
                            <UserIcon className="w-5 h-5 text-gray-400" />
                          </div>
                        )}
                      </div>
                      {person.isOnline && (
                        <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></div>
                      )}
                    </div>

                    {/* Person Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center space-x-2 mb-1">
                        <h4 className="font-medium text-gray-900 truncate">{person.name}</h4>
                        <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border ${getStatusColor(person.status)}`}>
                          {getStatusIcon(person.status)}
                          <span className="ml-1 capitalize">{person.status}</span>
                        </span>
                        <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border ${getRoleColor(person.role)}`}>
                          {person.role === 'owner' && <ShieldCheckIcon className="w-3 h-3 mr-1" />}
                          <span className="capitalize">{person.role}</span>
                        </span>
                      </div>
                      
                      <p className="text-sm text-gray-600 mb-2">{person.email}</p>

                      {/* Domains and Journeys */}
                      <div className="flex items-center space-x-4 text-xs text-gray-500 mb-2">
                        <div className="flex items-center space-x-1">
                          <span className="font-medium">Domains:</span>
                          <span>{person.domains.length > 0 ? person.domains.join(', ') : 'None'}</span>
                        </div>
                        <div className="flex items-center space-x-1">
                          <span className="font-medium">Journeys:</span>
                          <span>{person.journeys.length}</span>
                        </div>
                        <div className="flex items-center space-x-1">
                          <span className="font-medium">Contributions:</span>
                          <span>{person.totalContributions}</span>
                        </div>
                      </div>

                      {/* Activity Info */}
                      <div className="flex items-center justify-between text-xs text-gray-500">
                        <div className="flex items-center space-x-1">
                          <CalendarIcon className="w-3 h-3" />
                          <span>Joined {person.joinedAt.toLocaleDateString()}</span>
                        </div>
                        <div className="flex items-center space-x-1">
                          <ClockIcon className="w-3 h-3" />
                          <span>Last active: {person.lastActivity.toLocaleDateString()}</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex items-center space-x-1 ml-4">
                    <button
                      onClick={() => handlePersonAction('person_view', person.id)}
                      className="p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded transition-colors"
                      title="View Person"
                    >
                      <EyeIcon className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => handlePersonAction('person_edit', person.id)}
                      className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded transition-colors"
                      title="Edit Person"
                    >
                      <PencilIcon className="w-4 h-4" />
                    </button>
                    {person.status === 'pending' && (
                      <button
                        onClick={() => handlePersonAction('person_resend_invite', person.id)}
                        className="p-1.5 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded transition-colors"
                        title="Resend Invite"
                      >
                        <EnvelopeIcon className="w-4 h-4" />
                      </button>
                    )}
                    {person.role !== 'owner' && (
                      <button
                        onClick={() => handlePersonAction('person_remove', person.id)}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                        title="Remove Person"
                      >
                        <TrashIcon className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {/* Empty State */}
        {filteredPeople.length === 0 && (
          <div className="text-center py-12">
            <UserGroupIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">
              {searchTerm || statusFilter !== 'all' || roleFilter !== 'all' ? 'No matching people' : 'No people found'}
            </h3>
            <p className="text-gray-600 mb-4">
              {searchTerm || statusFilter !== 'all' || roleFilter !== 'all'
                ? 'Try adjusting your search or filter criteria.'
                : 'Start by inviting people to join your platform.'
              }
            </p>
            <button
              onClick={() => handlePersonAction('person_invite')}
              className="inline-flex items-center space-x-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors"
            >
              <PlusIcon className="w-4 h-4" />
              <span>Invite Your First Person</span>
            </button>
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="bg-gray-50 px-6 py-3 border-t border-gray-200">
        <div className="flex items-center justify-between text-sm">
          <span className="text-gray-600">
            Showing {filteredPeople.length} of {people.length} people
          </span>
          <div className="flex items-center space-x-4">
            <span className="text-gray-500">
              {people.filter(p => p.isOnline).length} online
            </span>
            <button
              onClick={() => handlePersonAction('people_export')}
              className="text-indigo-600 hover:text-indigo-700 font-medium"
            >
              Export List
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PeopleOverviewFrame;

/**
 * People Process Frame
 * ====================
 * 
 * Process frame component for guided people onboarding and invitation workflows.
 * Shows step-by-step process for inviting and managing people.
 */

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ClipboardDocumentListIcon,
  CheckCircleIcon,
  ClockIcon,
  ExclamationCircleIcon,
  ArrowRightIcon,
  ArrowLeftIcon,
  UserPlusIcon,
  EnvelopeIcon,
  ShieldCheckIcon,
  GlobeAltIcon,
  CheckIcon
} from '@heroicons/react/24/outline';
import { BaseFrameProps } from '../../types/frame';
import { useFrame } from '../../context/FrameContext';

interface ProcessStep {
  id: string;
  title: string;
  description: string;
  status: 'completed' | 'current' | 'pending' | 'error';
  icon: React.ReactNode;
  estimatedTime?: string;
  actionLabel?: string;
  requirements?: string[];
  isOptional?: boolean;
  formFields?: FormField[];
}

interface FormField {
  id: string;
  type: 'text' | 'email' | 'select' | 'multiselect' | 'checkbox';
  label: string;
  placeholder?: string;
  required: boolean;
  options?: { value: string; label: string }[];
  value?: any;
}

const PeopleProcessFrame: React.FC<BaseFrameProps> = ({
  frameInstance,
  className = '',
  onInteraction,
  isPreview = false,
}) => {
  const { handleFrameInteraction } = useFrame();
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<Record<string, any>>({});

  // Mock process steps data
  const [processSteps] = useState<ProcessStep[]>([
    {
      id: 'person-info',
      title: 'Person Information',
      description: 'Enter basic information for the person you want to invite',
      status: 'current',
      icon: <UserPlusIcon className="w-5 h-5" />,
      estimatedTime: '2 min',
      actionLabel: 'Continue',
      requirements: ['Valid email address', 'Full name'],
      formFields: [
        {
          id: 'fullName',
          type: 'text',
          label: 'Full Name',
          placeholder: 'Enter full name',
          required: true,
          value: formData.fullName || ''
        },
        {
          id: 'email',
          type: 'email',
          label: 'Email Address',
          placeholder: 'Enter email address',
          required: true,
          value: formData.email || ''
        },
        {
          id: 'title',
          type: 'text',
          label: 'Job Title',
          placeholder: 'Enter job title (optional)',
          required: false,
          value: formData.title || ''
        }
      ]
    },
    {
      id: 'role-assignment',
      title: 'Role Assignment',
      description: 'Select the appropriate role and permissions for this person',
      status: 'pending',
      icon: <ShieldCheckIcon className="w-5 h-5" />,
      estimatedTime: '1 min',
      actionLabel: 'Assign Role',
      requirements: ['Select role', 'Review permissions'],
      formFields: [
        {
          id: 'role',
          type: 'select',
          label: 'Role',
          required: true,
          options: [
            { value: 'viewer', label: 'Viewer - Read-only access' },
            { value: 'member', label: 'Member - Create and edit content' },
            { value: 'admin', label: 'Admin - Manage people and settings' }
          ],
          value: formData.role || ''
        },
        {
          id: 'customPermissions',
          type: 'checkbox',
          label: 'Enable custom permissions',
          required: false,
          value: formData.customPermissions || false
        }
      ]
    },
    {
      id: 'domain-access',
      title: 'Domain Access',
      description: 'Choose which domains this person should have access to',
      status: 'pending',
      icon: <GlobeAltIcon className="w-5 h-5" />,
      estimatedTime: '2 min',
      actionLabel: 'Set Access',
      requirements: ['Select at least one domain'],
      formFields: [
        {
          id: 'domains',
          type: 'multiselect',
          label: 'Domains',
          required: true,
          options: [
            { value: 'tech-domain', label: 'Tech Domain' },
            { value: 'marketing-domain', label: 'Marketing Domain' },
            { value: 'design-domain', label: 'Design Domain' },
            { value: 'sales-domain', label: 'Sales Domain' }
          ],
          value: formData.domains || []
        }
      ]
    },
    {
      id: 'invitation-message',
      title: 'Invitation Message',
      description: 'Customize the invitation message and send the invite',
      status: 'pending',
      icon: <EnvelopeIcon className="w-5 h-5" />,
      estimatedTime: '3 min',
      actionLabel: 'Send Invitation',
      requirements: ['Review message', 'Confirm details'],
      isOptional: false,
      formFields: [
        {
          id: 'message',
          type: 'text',
          label: 'Personal Message',
          placeholder: 'Add a personal message to the invitation (optional)',
          required: false,
          value: formData.message || ''
        },
        {
          id: 'sendWelcomeEmail',
          type: 'checkbox',
          label: 'Send welcome email with platform guide',
          required: false,
          value: formData.sendWelcomeEmail !== false
        },
        {
          id: 'notifyOnAccept',
          type: 'checkbox',
          label: 'Notify me when invitation is accepted',
          required: false,
          value: formData.notifyOnAccept !== false
        }
      ]
    },
    {
      id: 'confirmation',
      title: 'Confirmation',
      description: 'Review and confirm all details before sending the invitation',
      status: 'pending',
      icon: <CheckCircleIcon className="w-5 h-5" />,
      estimatedTime: '1 min',
      actionLabel: 'Send Invitation',
      requirements: ['Review all details', 'Confirm invitation']
    }
  ]);

  const getStatusIcon = (status: ProcessStep['status']) => {
    switch (status) {
      case 'completed':
        return <CheckCircleIcon className="w-6 h-6 text-green-500" />;
      case 'current':
        return <ClockIcon className="w-6 h-6 text-blue-500 animate-pulse" />;
      case 'error':
        return <ExclamationCircleIcon className="w-6 h-6 text-red-500" />;
      default:
        return <div className="w-6 h-6 rounded-full border-2 border-gray-300" />;
    }
  };

  const getStepColor = (status: ProcessStep['status']) => {
    switch (status) {
      case 'completed':
        return 'border-green-200 bg-green-50';
      case 'current':
        return 'border-blue-200 bg-blue-50 ring-2 ring-blue-500 ring-opacity-20';
      case 'error':
        return 'border-red-200 bg-red-50';
      default:
        return 'border-gray-200 bg-white';
    }
  };

  const handleStepAction = (step: ProcessStep) => {
    const interaction = {
      type: 'click' as const,
      frameId: frameInstance.id,
      data: { 
        action: 'step_action', 
        stepId: step.id,
        stepTitle: step.title,
        formData: formData
      },
      timestamp: new Date(),
    };
    
    handleFrameInteraction(interaction);
    onInteraction?.(interaction);
  };

  const handleNavigation = (direction: 'next' | 'previous') => {
    const newStep = direction === 'next' 
      ? Math.min(currentStep + 1, processSteps.length - 1)
      : Math.max(currentStep - 1, 0);
    
    setCurrentStep(newStep);
    
    const interaction = {
      type: 'click' as const,
      frameId: frameInstance.id,
      data: { action: `${direction}_step`, stepIndex: newStep, formData },
      timestamp: new Date(),
    };
    
    handleFrameInteraction(interaction);
    onInteraction?.(interaction);
  };

  const handleFieldChange = (fieldId: string, value: any) => {
    setFormData(prev => ({ ...prev, [fieldId]: value }));
  };

  const validateCurrentStep = () => {
    const currentStepData = processSteps[currentStep];
    if (!currentStepData.formFields) return true;

    return currentStepData.formFields.every(field => {
      if (!field.required) return true;
      const value = formData[field.id];
      
      if (field.type === 'multiselect') {
        return Array.isArray(value) && value.length > 0;
      }
      
      return value && value.toString().trim() !== '';
    });
  };

  const completedSteps = processSteps.filter(step => step.status === 'completed').length;
  const totalSteps = processSteps.length;
  const progressPercentage = Math.round((completedSteps / totalSteps) * 100);

  const renderFormField = (field: FormField) => {
    switch (field.type) {
      case 'text':
      case 'email':
        return (
          <input
            type={field.type}
            value={field.value || ''}
            onChange={(e) => handleFieldChange(field.id, e.target.value)}
            placeholder={field.placeholder}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
            required={field.required}
          />
        );
      
      case 'select':
        return (
          <select
            value={field.value || ''}
            onChange={(e) => handleFieldChange(field.id, e.target.value)}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
            required={field.required}
          >
            <option value="">Select an option</option>
            {field.options?.map(option => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
        );
      
      case 'multiselect':
        return (
          <div className="space-y-2">
            {field.options?.map(option => (
              <label key={option.value} className="flex items-center space-x-2">
                <input
                  type="checkbox"
                  checked={(field.value || []).includes(option.value)}
                  onChange={(e) => {
                    const currentValues = field.value || [];
                    const newValues = e.target.checked
                      ? [...currentValues, option.value]
                      : currentValues.filter((v: string) => v !== option.value);
                    handleFieldChange(field.id, newValues);
                  }}
                  className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300 rounded"
                />
                <span className="text-sm text-gray-900">{option.label}</span>
              </label>
            ))}
          </div>
        );
      
      case 'checkbox':
        return (
          <label className="flex items-center space-x-2">
            <input
              type="checkbox"
              checked={field.value || false}
              onChange={(e) => handleFieldChange(field.id, e.target.checked)}
              className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300 rounded"
            />
            <span className="text-sm text-gray-900">{field.label}</span>
          </label>
        );
      
      default:
        return null;
    }
  };

  if (isPreview) {
    return (
      <div className={`bg-white border border-gray-200 rounded-lg p-4 ${className}`}>
        <div className="flex items-center space-x-2 mb-2">
          <ClipboardDocumentListIcon className="w-5 h-5 text-indigo-600" />
          <h3 className="font-medium text-gray-900">People Process</h3>
        </div>
        <p className="text-sm text-gray-600">
          Guided workflow for onboarding and inviting people to the platform.
        </p>
      </div>
    );
  }

  return (
    <div className={`bg-white border border-gray-200 rounded-lg overflow-hidden ${className}`}>
      {/* Header */}
      <div className="bg-gray-50 px-6 py-4 border-b border-gray-200">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-lg font-semibold text-gray-900">Invite Person Process</h3>
            <p className="text-sm text-gray-600 mt-1">Complete these steps to invite someone to the platform</p>
          </div>
          <div className="text-right">
            <div className="text-2xl font-bold text-indigo-600">{progressPercentage}%</div>
            <div className="text-xs text-gray-500">{completedSteps} of {totalSteps} complete</div>
          </div>
        </div>

        {/* Progress Bar */}
        <div className="mt-4">
          <div className="w-full bg-gray-200 rounded-full h-2">
            <motion.div
              className="h-2 rounded-full bg-indigo-600"
              initial={{ width: 0 }}
              animate={{ width: `${progressPercentage}%` }}
              transition={{ duration: 1, delay: 0.3 }}
            />
          </div>
        </div>

        {/* Step Indicators */}
        <div className="mt-4 flex items-center justify-between">
          {processSteps.map((step, index) => (
            <div key={step.id} className="flex items-center">
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-medium ${
                  index === currentStep
                    ? 'bg-indigo-600 text-white'
                    : index < currentStep
                    ? 'bg-green-500 text-white'
                    : 'bg-gray-200 text-gray-500'
                }`}
              >
                {index < currentStep ? <CheckIcon className="w-4 h-4" /> : index + 1}
              </div>
              {index < processSteps.length - 1 && (
                <div className={`w-8 h-0.5 ${index < currentStep ? 'bg-green-500' : 'bg-gray-200'}`} />
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Current Step Content */}
      <div className="p-6">
        <AnimatePresence mode="wait">
          <motion.div
            key={currentStep}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.3 }}
          >
            {(() => {
              const step = processSteps[currentStep];
              
              if (step.id === 'confirmation') {
                return (
                  <div className="space-y-6">
                    <div className="text-center">
                      <CheckCircleIcon className="w-16 h-16 text-green-500 mx-auto mb-4" />
                      <h4 className="text-xl font-semibold text-gray-900 mb-2">Review Invitation Details</h4>
                      <p className="text-gray-600">Please review all the information before sending the invitation.</p>
                    </div>

                    <div className="bg-gray-50 rounded-lg p-4 space-y-4">
                      <div>
                        <h5 className="font-medium text-gray-900 mb-2">Person Information</h5>
                        <div className="text-sm text-gray-600 space-y-1">
                          <div><strong>Name:</strong> {formData.fullName || 'Not specified'}</div>
                          <div><strong>Email:</strong> {formData.email || 'Not specified'}</div>
                          <div><strong>Title:</strong> {formData.title || 'Not specified'}</div>
                        </div>
                      </div>

                      <div>
                        <h5 className="font-medium text-gray-900 mb-2">Role & Access</h5>
                        <div className="text-sm text-gray-600 space-y-1">
                          <div><strong>Role:</strong> {formData.role || 'Not assigned'}</div>
                          <div><strong>Domains:</strong> {(formData.domains || []).join(', ') || 'None selected'}</div>
                        </div>
                      </div>

                      {formData.message && (
                        <div>
                          <h5 className="font-medium text-gray-900 mb-2">Personal Message</h5>
                          <div className="text-sm text-gray-600 italic">"{formData.message}"</div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              }

              return (
                <div className="space-y-6">
                  <div className="flex items-start space-x-4">
                    <div className="flex-shrink-0 mt-1">
                      {getStatusIcon(step.status)}
                    </div>
                    <div className="flex-1">
                      <h4 className="text-lg font-semibold text-gray-900 mb-2">{step.title}</h4>
                      <p className="text-gray-600 mb-4">{step.description}</p>
                      
                      {step.estimatedTime && (
                        <div className="flex items-center text-sm text-gray-500 mb-4">
                          <ClockIcon className="w-4 h-4 mr-1" />
                          <span>Estimated time: {step.estimatedTime}</span>
                        </div>
                      )}

                      {step.requirements && (
                        <div className="mb-4">
                          <h5 className="text-sm font-medium text-gray-900 mb-2">Requirements:</h5>
                          <ul className="text-sm text-gray-600 space-y-1">
                            {step.requirements.map((req, index) => (
                              <li key={index} className="flex items-center space-x-2">
                                <div className="w-1.5 h-1.5 bg-gray-400 rounded-full flex-shrink-0" />
                                <span>{req}</span>
                              </li>
                            ))}
                          </ul>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Form Fields */}
                  {step.formFields && (
                    <div className="space-y-4">
                      {step.formFields.map((field) => (
                        <div key={field.id}>
                          <label className="block text-sm font-medium text-gray-900 mb-1">
                            {field.label}
                            {field.required && <span className="text-red-500 ml-1">*</span>}
                          </label>
                          {field.type === 'checkbox' ? (
                            renderFormField(field)
                          ) : (
                            renderFormField(field)
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })()}
          </motion.div>
        </AnimatePresence>

        {/* Navigation */}
        <div className="mt-8 flex items-center justify-between">
          <button
            onClick={() => handleNavigation('previous')}
            disabled={currentStep === 0}
            className="inline-flex items-center space-x-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <ArrowLeftIcon className="w-4 h-4" />
            <span>Previous</span>
          </button>

          <div className="text-sm text-gray-500">
            Step {currentStep + 1} of {processSteps.length}
          </div>

          <button
            onClick={() => {
              if (currentStep === processSteps.length - 1) {
                handleStepAction(processSteps[currentStep]);
              } else {
                handleNavigation('next');
              }
            }}
            disabled={!validateCurrentStep()}
            className="inline-flex items-center space-x-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <span>{currentStep === processSteps.length - 1 ? 'Send Invitation' : 'Next'}</span>
            <ArrowRightIcon className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Footer */}
      <div className="bg-gray-50 px-6 py-4 border-t border-gray-200">
        <div className="flex items-center justify-between">
          <p className="text-sm text-gray-600">
            Need help? <a href="#" className="text-indigo-600 hover:text-indigo-700">View invitation guide</a>
          </p>
          <div className="text-xs text-gray-500">
            {currentStep === processSteps.length - 1 ? 'Ready to send invitation' : `${processSteps.length - currentStep - 1} steps remaining`}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PeopleProcessFrame;

/**
 * Role Manager Frame
 * ==================
 * 
 * Config panel frame component for managing roles and permissions.
 * Provides role assignment interface with permissions matrix.
 */

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ShieldCheckIcon,
  UserIcon,
  CheckIcon,
  XMarkIcon,
  PlusIcon,
  TrashIcon,
  InformationCircleIcon,
  LockClosedIcon,
  PencilIcon
} from '@heroicons/react/24/outline';
import { BaseFrameProps, FrameTab } from '../../types/frame';
import { useFrame } from '../../context/FrameContext';

interface Permission {
  id: string;
  name: string;
  description: string;
  category: 'content' | 'people' | 'settings' | 'admin';
}

interface Role {
  id: string;
  name: string;
  description: string;
  color: string;
  permissions: string[];
  isSystem: boolean;
  userCount: number;
}

interface RoleAssignment {
  personId: string;
  personName: string;
  personEmail: string;
  currentRole: string;
  domains: string[];
  journeys: string[];
}

const RoleManagerFrame: React.FC<BaseFrameProps> = ({
  frameInstance,
  className = '',
  onInteraction,
  isPreview = false,
}) => {
  const { handleFrameInteraction } = useFrame();
  const [activeTab, setActiveTab] = useState('roles');
  const [selectedRole, setSelectedRole] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);

  // Mock permissions data
  const [permissions] = useState<Permission[]>([
    { id: 'read_content', name: 'Read Content', description: 'View journeys, moments, and content', category: 'content' },
    { id: 'create_content', name: 'Create Content', description: 'Create new journeys and moments', category: 'content' },
    { id: 'edit_content', name: 'Edit Content', description: 'Modify existing content', category: 'content' },
    { id: 'delete_content', name: 'Delete Content', description: 'Remove content permanently', category: 'content' },
    { id: 'invite_people', name: 'Invite People', description: 'Send invitations to new users', category: 'people' },
    { id: 'manage_people', name: 'Manage People', description: 'Edit user profiles and assignments', category: 'people' },
    { id: 'assign_roles', name: 'Assign Roles', description: 'Change user roles and permissions', category: 'people' },
    { id: 'remove_people', name: 'Remove People', description: 'Remove users from platform', category: 'people' },
    { id: 'manage_domains', name: 'Manage Domains', description: 'Configure domain settings', category: 'settings' },
    { id: 'manage_integrations', name: 'Manage Integrations', description: 'Configure external integrations', category: 'settings' },
    { id: 'view_analytics', name: 'View Analytics', description: 'Access usage and performance data', category: 'settings' },
    { id: 'system_admin', name: 'System Admin', description: 'Full system administration access', category: 'admin' },
  ]);

  // Mock roles data
  const [roles, setRoles] = useState<Role[]>([
    {
      id: 'owner',
      name: 'Owner',
      description: 'Full access to all features and settings',
      color: 'purple',
      permissions: permissions.map(p => p.id),
      isSystem: true,
      userCount: 1
    },
    {
      id: 'admin',
      name: 'Admin',
      description: 'Manage people, content, and most settings',
      color: 'blue',
      permissions: ['read_content', 'create_content', 'edit_content', 'delete_content', 'invite_people', 'manage_people', 'assign_roles', 'manage_domains', 'view_analytics'],
      isSystem: true,
      userCount: 3
    },
    {
      id: 'member',
      name: 'Member',
      description: 'Create and edit content, collaborate on journeys',
      color: 'green',
      permissions: ['read_content', 'create_content', 'edit_content', 'invite_people'],
      isSystem: true,
      userCount: 15
    },
    {
      id: 'viewer',
      name: 'Viewer',
      description: 'Read-only access to content',
      color: 'gray',
      permissions: ['read_content'],
      isSystem: true,
      userCount: 8
    }
  ]);

  // Mock role assignments
  const [assignments] = useState<RoleAssignment[]>([
    {
      personId: '1',
      personName: 'Alice Johnson',
      personEmail: 'alice@example.com',
      currentRole: 'owner',
      domains: ['Tech Domain', 'Marketing Domain'],
      journeys: ['React Development', 'Team Leadership']
    },
    {
      personId: '2',
      personName: 'Bob Smith',
      personEmail: 'bob@example.com',
      currentRole: 'admin',
      domains: ['Tech Domain'],
      journeys: ['Node.js Backend', 'DevOps Practices']
    },
    {
      personId: '3',
      personName: 'Carol Williams',
      personEmail: 'carol@example.com',
      currentRole: 'member',
      domains: ['Marketing Domain'],
      journeys: []
    }
  ]);

  const handleRoleAction = (action: string, data?: any) => {
    const interaction = {
      type: 'submit' as const,
      frameId: frameInstance.id,
      data: { action, ...data },
      timestamp: new Date(),
    };
    
    handleFrameInteraction(interaction);
    onInteraction?.(interaction);
  };

  const getRoleColor = (color: string) => {
    switch (color) {
      case 'purple':
        return 'text-purple-600 bg-purple-50 border-purple-200';
      case 'blue':
        return 'text-blue-600 bg-blue-50 border-blue-200';
      case 'green':
        return 'text-green-600 bg-green-50 border-green-200';
      case 'gray':
        return 'text-gray-600 bg-gray-50 border-gray-200';
      default:
        return 'text-indigo-600 bg-indigo-50 border-indigo-200';
    }
  };

  const getPermissionCategoryColor = (category: Permission['category']) => {
    switch (category) {
      case 'content':
        return 'text-blue-600 bg-blue-100';
      case 'people':
        return 'text-green-600 bg-green-100';
      case 'settings':
        return 'text-orange-600 bg-orange-100';
      case 'admin':
        return 'text-red-600 bg-red-100';
      default:
        return 'text-gray-600 bg-gray-100';
    }
  };

  const permissionsByCategory = permissions.reduce((acc, permission) => {
    if (!acc[permission.category]) {
      acc[permission.category] = [];
    }
    acc[permission.category].push(permission);
    return acc;
  }, {} as Record<string, Permission[]>);

  const tabs: FrameTab[] = [
    {
      id: 'roles',
      label: 'Roles',
      icon: <ShieldCheckIcon className="w-4 h-4" />,
      content: (
        <div className="space-y-6">
          {/* Roles List */}
          <div>
            <div className="flex items-center justify-between mb-4">
              <h4 className="text-sm font-medium text-gray-900">Available Roles</h4>
              <button
                onClick={() => handleRoleAction('role_create')}
                className="inline-flex items-center space-x-1 px-3 py-1.5 bg-indigo-600 text-white text-sm rounded-lg hover:bg-indigo-700"
              >
                <PlusIcon className="w-4 h-4" />
                <span>Create Role</span>
              </button>
            </div>

            <div className="space-y-3">
              {roles.map((role) => (
                <div
                  key={role.id}
                  className={`border rounded-lg p-4 cursor-pointer transition-all ${
                    selectedRole === role.id ? 'ring-2 ring-indigo-500 border-indigo-200' : 'border-gray-200 hover:border-gray-300'
                  }`}
                  onClick={() => setSelectedRole(selectedRole === role.id ? null : role.id)}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center space-x-2 mb-2">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${getRoleColor(role.color)}`}>
                          <ShieldCheckIcon className="w-3 h-3 mr-1" />
                          {role.name}
                        </span>
                        {role.isSystem && (
                          <span className="text-xs text-gray-500 bg-gray-100 px-2 py-0.5 rounded-full">
                            System Role
                          </span>
                        )}
                        <span className="text-xs text-gray-500">
                          {role.userCount} user{role.userCount !== 1 ? 's' : ''}
                        </span>
                      </div>
                      <p className="text-sm text-gray-600 mb-2">{role.description}</p>
                      <div className="text-xs text-gray-500">
                        {role.permissions.length} permission{role.permissions.length !== 1 ? 's' : ''}
                      </div>
                    </div>

                    <div className="flex items-center space-x-1">
                      {!role.isSystem && (
                        <>
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              handleRoleAction('role_edit', { roleId: role.id });
                            }}
                            className="p-1 text-gray-400 hover:text-blue-600 transition-colors"
                          >
                            <PencilIcon className="w-4 h-4" />
                          </button>
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              handleRoleAction('role_delete', { roleId: role.id });
                            }}
                            className="p-1 text-gray-400 hover:text-red-600 transition-colors"
                          >
                            <TrashIcon className="w-4 h-4" />
                          </button>
                        </>
                      )}
                    </div>
                  </div>

                  {/* Expanded Role Details */}
                  <AnimatePresence>
                    {selectedRole === role.id && (
                      <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        className="mt-4 pt-4 border-t border-gray-200"
                      >
                        <h5 className="text-sm font-medium text-gray-900 mb-3">Permissions</h5>
                        <div className="space-y-3">
                          {Object.entries(permissionsByCategory).map(([category, categoryPermissions]) => {
                            const rolePermissions = categoryPermissions.filter(p => role.permissions.includes(p.id));
                            if (rolePermissions.length === 0) return null;

                            return (
                              <div key={category}>
                                <h6 className={`text-xs font-medium mb-2 inline-flex items-center px-2 py-1 rounded-full ${getPermissionCategoryColor(category as Permission['category'])}`}>
                                  {category.charAt(0).toUpperCase() + category.slice(1)}
                                </h6>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                  {rolePermissions.map((permission) => (
                                    <div key={permission.id} className="flex items-center space-x-2 text-sm">
                                      <CheckIcon className="w-4 h-4 text-green-500 flex-shrink-0" />
                                      <div>
                                        <div className="font-medium text-gray-900">{permission.name}</div>
                                        <div className="text-xs text-gray-500">{permission.description}</div>
                                      </div>
                                    </div>
                                  ))}
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              ))}
            </div>
          </div>
        </div>
      )
    },
    {
      id: 'assignments',
      label: 'Assignments',
      icon: <UserIcon className="w-4 h-4" />,
      content: (
        <div className="space-y-6">
          {/* Role Assignments */}
          <div>
            <h4 className="text-sm font-medium text-gray-900 mb-4">Role Assignments</h4>
            <div className="space-y-3">
              {assignments.map((assignment) => {
                const role = roles.find(r => r.id === assignment.currentRole);
                return (
                  <div key={assignment.personId} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg">
                    <div className="flex items-center space-x-3">
                      <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center">
                        <UserIcon className="w-4 h-4 text-gray-500" />
                      </div>
                      <div>
                        <div className="font-medium text-gray-900">{assignment.personName}</div>
                        <div className="text-sm text-gray-500">{assignment.personEmail}</div>
                        <div className="text-xs text-gray-500">
                          {assignment.domains.length} domain{assignment.domains.length !== 1 ? 's' : ''} • 
                          {assignment.journeys.length} journey{assignment.journeys.length !== 1 ? 's' : ''}
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center space-x-3">
                      {role && (
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${getRoleColor(role.color)}`}>
                          {role.name}
                        </span>
                      )}
                      <button
                        onClick={() => handleRoleAction('assignment_edit', { personId: assignment.personId })}
                        className="text-sm text-indigo-600 hover:text-indigo-700 font-medium"
                      >
                        Change Role
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )
    },
    {
      id: 'permissions',
      label: 'Permissions',
      icon: <LockClosedIcon className="w-4 h-4" />,
      content: (
        <div className="space-y-6">
          {/* Permissions Matrix */}
          <div>
            <h4 className="text-sm font-medium text-gray-900 mb-4">Permissions Matrix</h4>
            
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Permission
                    </th>
                    {roles.map((role) => (
                      <th key={role.id} className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">
                        <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${getRoleColor(role.color)}`}>
                          {role.name}
                        </span>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {Object.entries(permissionsByCategory).map(([category, categoryPermissions]) => (
                    <React.Fragment key={category}>
                      <tr className="bg-gray-25">
                        <td colSpan={roles.length + 1} className="px-6 py-2">
                          <span className={`text-xs font-medium px-2 py-1 rounded-full ${getPermissionCategoryColor(category as Permission['category'])}`}>
                            {category.charAt(0).toUpperCase() + category.slice(1)} Permissions
                          </span>
                        </td>
                      </tr>
                      {categoryPermissions.map((permission) => (
