/**
 * Conflict Dialog Component - Phase 3 Implementation
 * Handle merge conflicts when multiple users edit the same board
 */

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ExclamationTriangleIcon,
  ArrowPathIcon,
  DocumentDuplicateIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';

// =============================================================================
// TYPES
// =============================================================================

interface ConflictDialogProps {
  isOpen: boolean;
  conflictData?: {
    serverVersion: any;
    clientEtag: string;
    serverEtag: string;
  };
  onResolve: (resolution: 'server' | 'overwrite') => void;
  onClose: () => void;
}

// =============================================================================
// COMPONENT
// =============================================================================

const ConflictDialog: React.FC<ConflictDialogProps> = ({
  isOpen,
  conflictData,
  onResolve,
  onClose
}) => {
  if (!isOpen || !conflictData) return null;

  const serverVersion = conflictData.serverVersion;
  const serverTime = serverVersion?.updatedAt ? new Date(serverVersion.updatedAt) : new Date();

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="flex items-center justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
            {/* Background overlay */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 transition-opacity bg-gray-500 bg-opacity-75"
              onClick={onClose}
            />

            {/* Dialog */}
            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 20 }}
              className="inline-block w-full max-w-lg p-6 my-8 overflow-hidden text-left align-middle transition-all transform bg-white shadow-xl rounded-lg relative"
            >
              {/* Close button */}
              <button
                onClick={onClose}
                className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"
              >
                <XMarkIcon className="w-5 h-5" />
              </button>

              {/* Header */}
              <div className="flex items-center mb-4">
                <div className="flex-shrink-0">
                  <ExclamationTriangleIcon className="w-8 h-8 text-amber-500" />
                </div>
                <div className="ml-3">
                  <h3 className="text-lg font-medium text-gray-900">
                    Conflict Detected
                  </h3>
                  <p className="text-sm text-gray-600">
                    This board has been modified by another session
                  </p>
                </div>
              </div>

              {/* Conflict details */}
              <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-lg">
                <div className="text-sm text-amber-800">
                  <p className="font-medium mb-2">What happened?</p>
                  <p className="mb-3">
                    The board "{serverVersion?.name || 'Unknown'}" was modified at{' '}
                    <strong>{serverTime.toLocaleString()}</strong> while you were editing.
                  </p>
                  <p>
                    Choose how to resolve this conflict:
                  </p>
                </div>
              </div>

              {/* Resolution options */}
              <div className="space-y-3 mb-6">
                <button
                  onClick={() => onResolve('server')}
                  className="w-full flex items-center p-4 text-left border border-gray-200 rounded-lg hover:border-blue-300 hover:bg-blue-50 transition-colors group"
                >
                  <ArrowPathIcon className="w-5 h-5 text-blue-600 mr-3 group-hover:text-blue-700" />
                  <div>
                    <div className="font-medium text-gray-900 group-hover:text-blue-900">
                      Reload (Recommended)
                    </div>
                    <div className="text-sm text-gray-600 group-hover:text-blue-700">
                      Discard your changes and load the latest version from the server
                    </div>
                  </div>
                </button>

                <button
                  onClick={() => onResolve('overwrite')}
                  className="w-full flex items-center p-4 text-left border border-gray-200 rounded-lg hover:border-red-300 hover:bg-red-50 transition-colors group"
                >
                  <DocumentDuplicateIcon className="w-5 h-5 text-red-600 mr-3 group-hover:text-red-700" />
                  <div>
                    <div className="font-medium text-gray-900 group-hover:text-red-900">
                      Overwrite Server
                    </div>
                    <div className="text-sm text-gray-600 group-hover:text-red-700">
                      Force save your changes, replacing the server version
                    </div>
                  </div>
                </button>
              </div>

              {/* Warning */}
              <div className="p-3 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-xs text-gray-600">
                  <strong>Note:</strong> If you choose "Overwrite Server", any changes made by 
                  other users will be lost. The "Reload" option is usually safer.
                </p>
              </div>
            </motion.div>
          </div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default ConflictDialog;

/**
 * Draggable Tabs Component - Phase 3 Implementation
 * Drag-to-reorder tabs with pinned Cover and Settings
 */

import React, { useState } from 'react';
import { motion, Reorder, useDragControls, AnimatePresence } from 'framer-motion';
import {
  Cog6ToothIcon,
  Bars3Icon,
  ChevronDownIcon,
  CheckIcon,
  MapPinIcon,
  TrashIcon
} from '@heroicons/react/24/outline';

// =============================================================================
// TYPES
// =============================================================================

interface TabData {
  id: string;
  name: string;
  role?: string;
  pattern?: string;
  isPinned?: boolean;
  allowedModes?: string[];
}

interface DraggableTabsProps {
  tabs: TabData[];
  selectedTabId?: string;
  onTabSelect: (tabId: string) => void;
  onTabReorder: (newOrder: string[]) => void;
  onTabConfig?: (tabId: string) => void;
  onModeChange?: (tabId: string, mode: string) => void;
  onPinToggle?: (tabId: string, isPinned: boolean) => void;
  onDelete?: (tabId: string) => void;
  disabled?: boolean;
}

// =============================================================================
// INDIVIDUAL TAB COMPONENT
// =============================================================================

const DraggableTab: React.FC<{
  tab: TabData;
  isSelected: boolean;
  onSelect: () => void;
  onConfig?: () => void;
  onModeChange?: (mode: string) => void;
  onPinToggle?: (isPinned: boolean) => void;
  onDelete?: () => void;
  isDragging: boolean;
}> = ({ tab, isSelected, onSelect, onConfig, onModeChange, onPinToggle, onDelete, isDragging }) => {
  const dragControls = useDragControls();
  const [showModeSelector, setShowModeSelector] = useState(false);
  const [showConfigMenu, setShowConfigMenu] = useState(false);
  
  // EXACT Frame 3 design: "FrameName.mode" with blue period when selected, bottom-aligned mode
  const renderTabName = () => {
    const currentMode = tab.pattern || 'default';
    return (
      <span className="flex items-end">
        <span className="font-medium">{tab.name}</span>
        <span className={`${isSelected ? 'text-blue-500' : 'text-gray-400'}`}>.</span>
        <span className="text-xs text-gray-500 font-normal ml-0.5">{currentMode}</span>
      </span>
    );
  };

  const availableModes = tab.allowedModes || ['default', 'canvas', 'dialogic', 'wizard', 'focus'];

  const handleModeSelect = (mode: string) => {
    if (onModeChange && mode !== tab.pattern) {
      onModeChange(mode);
    }
    setShowModeSelector(false);
  };

  const handleDelete = () => {
    if (onDelete) {
      const confirmDelete = window.confirm(`Are you sure you want to delete "${tab.name}"? This action cannot be undone.`);
      if (confirmDelete) {
        onDelete();
      }
    }
    setShowConfigMenu(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Keyboard navigation for reordering (Alt + Arrow keys)
    if (e.altKey && (e.key === 'ArrowLeft' || e.key === 'ArrowRight')) {
      e.preventDefault();
      // This would need to be implemented at the parent level
      console.log('Keyboard reorder:', e.key);
    }
  };

  return (
    <Reorder.Item
      value={tab}
      dragListener={true}
      dragControls={dragControls}
      role="tab"
      aria-selected={isSelected}
      tabIndex={isSelected ? 0 : -1}
      onKeyDown={handleKeyDown}
      onClick={onSelect}
      className={`
        group relative flex items-center space-x-2 px-3 py-2 text-sm font-medium rounded-t-lg cursor-pointer
        transition-all duration-200 select-none focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-1
        ${isSelected 
          ? 'bg-white text-gray-900 border-b-2 border-blue-500 shadow-sm' 
          : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
        }
        ${isDragging ? 'shadow-lg z-10' : ''}
        cursor-grab active:cursor-grabbing
      `}
      whileDrag={{ scale: 1.05, rotate: 2 }}
      initial={false}
    >
      <div className="flex items-center flex-1 min-w-0 px-1">
        <div className="truncate">{renderTabName()}</div>
      </div>
      
      {/* Mode Selector - Only visible on active tab */}
      {isSelected && onModeChange && (
        <div className="relative">
          <button
            onClick={(e) => {
              e.stopPropagation();
              setShowModeSelector(!showModeSelector);
            }}
            className="text-gray-400 hover:text-gray-600 p-1 rounded"
            title="Change mode"
            aria-label="Change engagement mode"
            aria-expanded={showModeSelector}
          >
            <ChevronDownIcon className={`w-4 h-4 transition-transform ${showModeSelector ? 'rotate-180' : ''}`} />
          </button>
          
          <AnimatePresence>
            {showModeSelector && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="absolute top-full right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-50 min-w-32"
              >
                {availableModes.map((mode) => (
                  <button
                    key={mode}
                    onClick={() => handleModeSelect(mode)}
                    className={`w-full text-left px-3 py-2 text-sm hover:bg-gray-50 first:rounded-t-lg last:rounded-b-lg flex items-center justify-between ${
                      mode === tab.pattern ? 'bg-blue-50 text-blue-700' : 'text-gray-700'
                    }`}
                  >
                    <span className="capitalize">{mode}</span>
                    {mode === tab.pattern && <CheckIcon className="w-4 h-4" />}
                  </button>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      )}
      
      {/* Config menu - Only visible on active tab */}
      {(onConfig || onDelete) && isSelected && (
        <div className="relative">
          <button
            onClick={(e) => {
              e.stopPropagation();
              setShowConfigMenu(!showConfigMenu);
            }}
            className="text-gray-400 hover:text-gray-600 p-1 rounded"
            title="Frame options"
            aria-label="Frame options menu"
            aria-expanded={showConfigMenu}
          >
            <Cog6ToothIcon className="w-4 h-4" />
          </button>
          
          <AnimatePresence>
            {showConfigMenu && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="absolute top-full right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-50 min-w-32"
              >
                {onConfig && (
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onConfig();
                      setShowConfigMenu(false);
                    }}
                    className="w-full text-left px-3 py-2 text-sm hover:bg-gray-50 first:rounded-t-lg text-gray-700 flex items-center gap-2"
                  >
                    <Cog6ToothIcon className="w-4 h-4" />
                    Configure
                  </button>
                )}
                {onDelete && (
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      handleDelete();
                    }}
                    className="w-full text-left px-3 py-2 text-sm hover:bg-red-50 last:rounded-b-lg text-red-600 hover:text-red-700 flex items-center gap-2"
                  >
                    <TrashIcon className="w-4 h-4" />
                    Delete
                  </button>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      )}
      
      {/* Drag handle - visible on ALL tabs */}
      <button
        className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-gray-600 p-1 rounded"
        onPointerDown={(e) => dragControls.start(e)}
        title="Drag to reorder"
        aria-label="Drag to reorder tab"
      >
        <Bars3Icon className="w-3 h-3" />
      </button>
      
      {/* Pin toggle - show when focused OR when pinned */}
      {onPinToggle && (isSelected || tab.isPinned) && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            onPinToggle(!tab.isPinned);
          }}
          className={`p-1 rounded transition-colors ${
            tab.isPinned 
              ? 'text-blue-500 hover:text-blue-700' 
              : 'opacity-0 group-hover:opacity-100 text-gray-400 hover:text-gray-600'
          }`}
          title={tab.isPinned ? 'Unpin frame' : 'Pin frame'}
          aria-label={tab.isPinned ? 'Unpin frame' : 'Pin frame'}
        >
          <MapPinIcon className={`w-4 h-4 ${tab.isPinned ? 'fill-current' : ''}`} />
        </button>
      )}
    </Reorder.Item>
  );
};

// =============================================================================
// MAIN COMPONENT
// =============================================================================

const DraggableTabs: React.FC<DraggableTabsProps> = ({
  tabs,
  selectedTabId,
  onTabSelect,
  onTabReorder,
  onTabConfig,
  onModeChange,
  onPinToggle,
  onDelete,
  disabled = false
}) => {
  const [isDragging, setIsDragging] = useState(false);
  
  // No need to separate tabs - all tabs are treated equally

  const handleModeChange = (tabId: string, mode: string) => {
    if (onModeChange) {
      onModeChange(tabId, mode);
    }
  };

  if (disabled || tabs.length === 0) {
    // Even when disabled, use the same DraggableTab component for consistency
    return (
      <div role="tablist" className="flex border-b border-gray-200 bg-gray-50 px-4">
        {tabs.map((tab) => (
          <DraggableTab
            key={tab.id}
            tab={tab}
            isSelected={selectedTabId === tab.id}
            onSelect={() => onTabSelect(tab.id)}
            onConfig={onTabConfig ? () => onTabConfig(tab.id) : undefined}
            onModeChange={undefined} // No mode changes when disabled
            onPinToggle={onPinToggle ? (isPinned) => onPinToggle(tab.id, isPinned) : undefined}
            onDelete={onDelete ? () => onDelete(tab.id) : undefined}
            isDragging={false}
          />
        ))}
      </div>
    );
  }

  return (
    <div role="tablist" className="flex border-b border-gray-200 bg-gray-50 px-4">
      {/* ALL tabs use the same DraggableTab component - no distinction between pinned and draggable */}
      <Reorder.Group
        axis="x"
        values={tabs}
        onReorder={(newOrder) => {
          if (disabled) return;
          const fullOrder = newOrder.map(tab => tab.id);
          onTabReorder(fullOrder);
        }}
        className="flex w-full"
        style={{ display: 'flex' }}
      >
        {tabs.map((tab) => (
          <DraggableTab
            key={tab.id}
            tab={tab}
            isSelected={selectedTabId === tab.id}
            onSelect={() => onTabSelect(tab.id)}
            onConfig={onTabConfig ? () => onTabConfig(tab.id) : undefined}
            onModeChange={onModeChange ? (mode) => handleModeChange(tab.id, mode) : undefined}
            onPinToggle={onPinToggle ? (isPinned) => onPinToggle(tab.id, isPinned) : undefined}
            onDelete={onDelete ? () => onDelete(tab.id) : undefined}
            isDragging={isDragging}
          />
        ))}
      </Reorder.Group>
    </div>
  );
};

export default DraggableTabs;

