export const BoardDataProvider: React.FC<BoardDataProviderProps> = ({ children }) => {
  const [board, setBoard] = useState<BoardData | null>(null);
  const [entity, setEntity] = useState<EntityData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // =============================================================================
  // ACTIONS
  // =============================================================================

  const loadBoard = async (boardId: string) => {
    setIsLoading(true);
    setError(null);
    
    try {
      // Load board data
      const boardResponse = await apiFetch(`/api/boards/${boardId}`);
      
      if (!boardResponse.success) {
        throw new Error(boardResponse.error || 'Failed to load board');
      }
      
      const boardData = boardResponse.data;
      setBoard(boardData);
      
      // Load entity data if board has scope and entityId
      if (boardData.data?.scope && boardData.data?.entityId) {
        try {
          const entityResponse = await apiFetch(
            `/api/entities/${boardData.data.scope}/${boardData.data.entityId}/min`
          );
          
          if (entityResponse.success) {
            setEntity(entityResponse.data);
          } else {
            console.warn('Failed to load entity data:', entityResponse.error);
            setEntity(null);
          }
        } catch (entityError) {
          console.warn('Error loading entity data:', entityError);
          setEntity(null);
        }
      } else {
        setEntity(null);
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to load board';
      setError(errorMessage);
      console.error('Error loading board:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const saveBoard = async (updates: Partial<BoardData>) => {
    if (!board) {
      throw new Error('No board loaded');
    }
    
    setError(null);
    
    try {
      const response = await apiFetch(`/api/boards/${board.id}`, {
        method: 'PUT',
        body: JSON.stringify(updates)
      });
      
      if (!response.success) {
        throw new Error(response.error || 'Failed to save board');
      }
      
      // Update local board state
      setBoard(prev => prev ? { ...prev, ...updates } : null);
      
      // If entity-related data changed, reload entity
      if (updates.data?.scope || updates.data?.entityId) {
        const newScope = updates.data?.scope || board.data.scope;
        const newEntityId = updates.data?.entityId || board.data.entityId;
        
        if (newScope && newEntityId) {
          try {
            const entityResponse = await apiFetch(
              `/api/entities/${newScope}/${newEntityId}/min`
            );
            
            if (entityResponse.success) {
              setEntity(entityResponse.data);
            }
          } catch (entityError) {
            console.warn('Error reloading entity after board update:', entityError);
          }
        } else {
          setEntity(null);
        }
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to save board';
      setError(errorMessage);
      throw err;
    }
  };

  const addFrame = async (frameData: Partial<FrameData>): Promise<FrameData> => {
    if (!board) {
      throw new Error('No board loaded');
    }
    
    setError(null);
    
    try {
      const response = await apiFetch(`/api/boards/${board.id}/frames`, {
        method: 'POST',
        body: JSON.stringify(frameData)
      });
      
      if (!response.success) {
        throw new Error(response.error || 'Failed to add frame');
      }
      
      const newFrame = response.data;
      
      // Update local board frames
      setBoard(prev => prev ? {
        ...prev,
        frames: [...(prev.frames || []), newFrame].sort((a, b) => a.orderIndex - b.orderIndex)
      } : null);
      
      return newFrame;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to add frame';
      setError(errorMessage);
      throw err;
    }
  };

  const updateFrame = async (frameId: string, updates: Partial<FrameData>) => {
    if (!board) {
      throw new Error('No board loaded');
    }
    
    setError(null);
    
    try {
      const response = await apiFetch(`/api/boards/${board.id}/frames/${frameId}`, {
        method: 'PATCH',
        body: JSON.stringify(updates)
      });
      
      if (!response.success) {
        throw new Error(response.error || 'Failed to update frame');
      }
      
      // Update local board frames
      setBoard(prev => prev ? {
        ...prev,
        frames: (prev.frames || []).map(frame => 
          frame.id === frameId ? { ...frame, ...updates } : frame
        )
      } : null);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to update frame';
      setError(errorMessage);
      throw err;
    }
  };

  const deleteFrame = async (frameId: string) => {
    if (!board) {
      throw new Error('No board loaded');
    }
    
    setError(null);
    
    try {
      const response = await apiFetch(`/api/boards/${board.id}/frames/${frameId}`, {
        method: 'DELETE'
      });
      
      if (!response.success) {
        throw new Error(response.error || 'Failed to delete frame');
      }
      
      // Update local board frames
      setBoard(prev => prev ? {
        ...prev,
        frames: (prev.frames || []).filter(frame => frame.id !== frameId)
      } : null);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to delete frame';
      setError(errorMessage);
      throw err;
    }
  };

  // =============================================================================
  // UTILITY FUNCTIONS
  // =============================================================================

  const getFrameById = (frameId: string): FrameData | undefined => {
    return board?.frames?.find(frame => frame.id === frameId);
  };

  const getFramesByRole = (role: string): FrameData[] => {
    return board?.frames?.filter(frame => frame.role === role) || [];
  };

  const clearBoard = () => {
    setBoard(null);
    setEntity(null);
    setError(null);
  };

  // =============================================================================
  // CONTEXT VALUE
  // =============================================================================

  const contextValue: BoardDataContextType = {
    // State
    board,
    entity,
    isLoading,
    error,
    
    // Actions
    loadBoard,
    saveBoard,
    addFrame,
    updateFrame,
    deleteFrame,
    
    // Utility
    getFrameById,
    getFramesByRole,
    clearBoard,
  };

  return (
    <BoardDataContext.Provider value={contextValue}>
      {children}
    </BoardDataContext.Provider>
  );
};

export default BoardDataContext;

/**
 * Frame Context
 * =============
 * 
 * React context for managing Frame system state across the application.
 * Handles frame loading, updates, and interactions.
 */

import React, { createContext, useContext, useReducer, useCallback, ReactNode } from 'react';
import { 
  FrameContextType, 
  FrameContextState, 
  ExtendedFrameInstance, 
  EngagementMode,
  FrameInteraction 
} from '../types/frame';

// =============================================================================
// CONTEXT SETUP
// =============================================================================

const FrameContext = createContext<FrameContextType | undefined>(undefined);

// =============================================================================
// REDUCER ACTIONS
// =============================================================================

type FrameAction = 
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_FRAMES'; payload: ExtendedFrameInstance[] }
  | { type: 'ADD_FRAME'; payload: ExtendedFrameInstance }
  | { type: 'UPDATE_FRAME'; payload: { id: string; updates: Partial<ExtendedFrameInstance> } }
  | { type: 'REMOVE_FRAME'; payload: string }
  | { type: 'SET_ENGAGEMENT_MODE'; payload: EngagementMode };

// =============================================================================
// REDUCER FUNCTION
// =============================================================================

const frameReducer = (state: FrameContextState, action: FrameAction): FrameContextState => {
  switch (action.type) {
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
      
    case 'SET_ERROR':
      return { ...state, error: action.payload, isLoading: false };
      
    case 'SET_FRAMES':
      return { ...state, activeFrames: action.payload, isLoading: false };
      
    case 'ADD_FRAME':
      return { 
        ...state, 
        activeFrames: [...state.activeFrames, action.payload],
        isLoading: false 
      };
      
    case 'UPDATE_FRAME':
      return {
        ...state,
        activeFrames: state.activeFrames.map(frame => 
          frame.id === action.payload.id 
            ? { ...frame, ...action.payload.updates }
            : frame
        )
      };
      
    case 'REMOVE_FRAME':
      return {
        ...state,
        activeFrames: state.activeFrames.filter(frame => frame.id !== action.payload)
      };
      
    case 'SET_ENGAGEMENT_MODE':
      return { ...state, currentEngagementMode: action.payload };
      
    default:
      return state;
  }
};

// =============================================================================
// INITIAL STATE
// =============================================================================

const initialState: FrameContextState = {
  activeFrames: [],
  currentEngagementMode: 'dialogic',
  isLoading: false,
  error: null,
};

// =============================================================================
// PROVIDER COMPONENT
// =============================================================================

interface FrameProviderProps {
  children: ReactNode;
}

export const FrameProvider: React.FC<FrameProviderProps> = ({ children }) => {
  const [state, dispatch] = useReducer(frameReducer, initialState);

  // =============================================================================
  // ACTION HANDLERS
  // =============================================================================

  const loadFrame = useCallback(async (frameId: string) => {
    dispatch({ type: 'SET_LOADING', payload: true });
    dispatch({ type: 'SET_ERROR', payload: null });

    try {
      // TODO: Implement API call to load frame instance
      // For now, this is a placeholder that will be implemented when backend APIs are ready
      console.log(`Loading frame: ${frameId}`);
      
      // Mock frame loading - replace with actual API call
      await new Promise(resolve => setTimeout(resolve, 500));
      
      // Mock frame data - replace with actual API response
      const mockFrame: ExtendedFrameInstance = {
        id: frameId,
        entityType: 'keeper',
        entityId: 'mock-entity',
        configId: 'mock-config',
        currentContentId: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      dispatch({ type: 'ADD_FRAME', payload: mockFrame });
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Failed to load frame';
      dispatch({ type: 'SET_ERROR', payload: errorMessage });
    }
  }, []);

  const updateFrame = useCallback(async (frameId: string, updates: Partial<ExtendedFrameInstance>) => {
    try {
      // TODO: Implement API call to update frame instance
      console.log(`Updating frame: ${frameId}`, updates);
      
      // Mock update - replace with actual API call
      await new Promise(resolve => setTimeout(resolve, 200));
      
      dispatch({ type: 'UPDATE_FRAME', payload: { id: frameId, updates } });
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Failed to update frame';
      dispatch({ type: 'SET_ERROR', payload: errorMessage });
    }
  }, []);

  const removeFrame = useCallback((frameId: string) => {
    dispatch({ type: 'REMOVE_FRAME', payload: frameId });
  }, []);

  const setEngagementMode = useCallback((mode: EngagementMode) => {
    dispatch({ type: 'SET_ENGAGEMENT_MODE', payload: mode });
  }, []);

  const handleFrameInteraction = useCallback((interaction: FrameInteraction) => {
    // Handle frame interactions - can be extended for analytics, logging, etc.
    console.log('Frame interaction:', interaction);
    
    // TODO: Implement interaction handling logic
    // - Analytics tracking
    // - State updates based on interaction type
    // - Agent communication for dialog frames
    // - Navigation for process frames
  }, []);

  // =============================================================================
  // CONTEXT VALUE
  // =============================================================================

  const contextValue: FrameContextType = {
    // State
    ...state,
    
    // Actions
    loadFrame,
    updateFrame,
    removeFrame,
    setEngagementMode,
    handleFrameInteraction,
  };

  return (
    <FrameContext.Provider value={contextValue}>
      {children}
    </FrameContext.Provider>
  );
};

// =============================================================================
// HOOK
// =============================================================================

/**
 * Hook to use the Frame context
 */
export const useFrame = (): FrameContextType => {
  const context = useContext(FrameContext);
  
  if (context === undefined) {
    throw new Error('useFrame must be used within a FrameProvider');
  }
  
  return context;
};

// =============================================================================
// EXPORTS
// =============================================================================

export default FrameContext;

/**
 * Keeper Context
 * --------------
 * Provides active Keeper scope for Board Studio and related pages.
 */

import React, { createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';
import { apiFetch } from '../lib/api';
import { useAuth } from './AuthContext';

export interface KeeperSummary {
  id: string;
  title: string;
  purpose?: string;
  avatarUrl?: string;
}

interface KeeperContextType {
  keepers: KeeperSummary[];
  activeKeeper: KeeperSummary | null;
  isLoading: boolean;
  error: string | null;
  setActiveKeeperId: (keeperId: string) => void;
  refreshKeepers: () => Promise<void>;
}

const KeeperContext = createContext<KeeperContextType | undefined>(undefined);

export const KeeperProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [keepers, setKeepers] = useState<KeeperSummary[]>([]);
  const [activeKeeperId, setActiveKeeperId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const refreshKeepers = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const userId = user?.id;

      // If we don't have an authenticated user context, do not call the API.
      if (!userId) {
        setKeepers([]);
        setActiveKeeperId(null);
        return;
      }

      // Primary source: Keeper list API (auth-protected)
      const url = `/api/keeper/keepers?userId=${encodeURIComponent(userId)}`;
      try {
        const result = await apiFetch(url);
        const list = Array.isArray((result as any)?.keepers)
          ? (result as any).keepers
          : Array.isArray(result)
            ? (result as any)
            : (result ? [result] : []);
        setKeepers(list);
        if (list.length > 0 && !activeKeeperId) {
          setActiveKeeperId(list[0].id);
        }
      } catch (apiErr: any) {
        // Graceful fallback on network/API errors
        if (keepers.length === 0) {
          setKeepers([]);
          setActiveKeeperId(null);
        }
      }
    } catch (err: any) {
      setError(err?.message || 'Failed to load keepers');
    } finally {
      setIsLoading(false);
    }
  }, [activeKeeperId, user?.id]);

  useEffect(() => {
    void refreshKeepers();
  }, [refreshKeepers]);

  const value = useMemo<KeeperContextType>(() => ({
    keepers,
    activeKeeper: keepers.find(k => k.id === activeKeeperId) || keepers[0] || null,
    isLoading,
    error,
    setActiveKeeperId: (id: string) => setActiveKeeperId(id),
    refreshKeepers,
  }), [keepers, activeKeeperId, isLoading, error, refreshKeepers]);

  return <KeeperContext.Provider value={value}>{children}</KeeperContext.Provider>;
};

export const useKeeperContext = (): KeeperContextType => {
  const ctx = useContext(KeeperContext);
  if (!ctx) throw new Error('useKeeperContext must be used within a KeeperProvider');
  return ctx;
};

import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { useAuth } from './AuthContext';
import { Theme, ThemeTokens, fetchThemeById } from '../lib/themeApi';
import { apiFetch } from '@/lib/api';

// Hardcoded fallback theme to guarantee UI rendering if the API fails.
const KEEPER_CLASSIC_FALLBACK: Theme = {
  id: 'caa32a04-cd5a-4538-8572-f5ff5add85d0',
  slug: 'keeper-classic',
  name: 'Keeper Classic',
  light: {
    background: '0 0% 94.1%', foreground: '25 95% 21%', card: '0 0% 98%', cardForeground: '28 66% 21%', popover: '27 100% 96%', popoverForeground: '39 100% 15%', primary: '13 83% 21%', primaryForeground: '0 0% 100%', secondary: '35 48% 87%', secondaryForeground: '15 72% 38%', muted: '37 24% 80%', mutedForeground: '13 100% 18%', accent: '35 63% 69%', accentForeground: '25 80% 25%', destructive: '15 72% 38%', destructiveForeground: '33 97% 83%', border: '16 11% 43%', input: '210 17% 98%', ring: '33 97% 83%',
  },
  dark: {
    background: '0 0% 0%', foreground: '0 0% 100%', card: '0 0% 6.7%', cardForeground: '0 0% 93.3%', popover: '0 0% 13.3%', popoverForeground: '0 0% 93.3%', primary: '0 0% 80%', primaryForeground: '0 0% 0%', secondary: '0 0% 86.7%', secondaryForeground: '15 72% 38%', muted: '0 0% 93.3%', mutedForeground: '0 0% 0%', accent: '40 8% 79%', accentForeground: '0 0% 0%', destructive: '0 100% 50%', destructiveForeground: '0 0% 100%', border: '0 0% 75.3%', input: '0 0% 95.3%', ring: '40 8% 79%',
  }
};

type ThemeMode = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme | null;
  mode: ThemeMode;
  setMode: (mode: ThemeMode) => void;
}

interface ThemeProviderProps {
  children: ReactNode;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<ThemeProviderProps> = ({ children }) => {
  const { isAuthenticated, token } = useAuth();
  const [theme, setTheme] = useState<Theme | null>(KEEPER_CLASSIC_FALLBACK); // Initialize with fallback
  const [mode, setMode] = useState<ThemeMode>('light');

  // 1. Detect user's system preference for color scheme
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    setMode(mediaQuery.matches ? 'dark' : 'light');

    const handler = (e: MediaQueryListEvent) => setMode(e.matches ? 'dark' : 'light');
    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, []);

  // 2. Fetch the user's preferred theme from the (mock) API
  useEffect(() => {
    const KEEPER_CLASSIC_ID = 'caa32a04-cd5a-4538-8572-f5ff5add85d0';

    const loadUserSettings = async () => {
      let themeIdToLoad = KEEPER_CLASSIC_ID;
      
      if (isAuthenticated && token) {
        try {
          const settings = await apiFetch('/api/kam/settings', {
            headers: { Authorization: `Bearer ${token}` },
          });
          themeIdToLoad = settings.data?.preferred_theme_id || KEEPER_CLASSIC_ID;
        } catch (error) {
          console.error('Failed to fetch user settings, will use default theme.', error);
        }
        
        try {
          const fetchedTheme = await fetchThemeById(themeIdToLoad, token);
          setTheme(fetchedTheme || KEEPER_CLASSIC_FALLBACK);
        } catch (error) {
          console.error('An error occurred while fetching the theme:', error);
          setTheme(KEEPER_CLASSIC_FALLBACK);
        }

      } else {
        // For public visitors, use the hardcoded fallback immediately.
        setTheme(KEEPER_CLASSIC_FALLBACK);
      }
    };
    
    loadUserSettings();
  }, [isAuthenticated, token]);

  // 3. Apply the current theme and mode to the document
  useEffect(() => {
    const root = document.documentElement;
    if (!theme) return;

    // Apply the correct token set (light or dark)
    const tokensToApply: ThemeTokens = theme[mode];

    // Guard against undefined or null tokensToApply
    if (tokensToApply && typeof tokensToApply === 'object') {
      Object.entries(tokensToApply).forEach(([key, value]) => {
        const cssVarName = `--theme-${key.replace(/[A-Z]/g, (letter) => `-${letter.toLowerCase()}`)}`;
        root.style.setProperty(cssVarName, value);
      });
    }
    
    // Add/remove 'dark' class for any vanilla CSS overrides
    root.classList.remove('light', 'dark');
    root.classList.add(mode);

  }, [theme, mode]);

  return (
    <ThemeContext.Provider value={{ theme, mode, setMode }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = (): ThemeContextType => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { ViewMode, ViewModeContextType, ViewModeState } from '../types/viewMode';

const ViewModeContext = createContext<ViewModeContextType | undefined>(undefined);

interface ViewModeProviderProps {
  children: React.ReactNode;
}

const VIEW_MODE_STORAGE_KEY = 'keeper-view-mode';

export const ViewModeProvider: React.FC<ViewModeProviderProps> = ({ children }) => {
  const [currentMode, setCurrentMode] = useState<ViewMode>(() => {
    // Try to load from localStorage first
    const stored = localStorage.getItem(VIEW_MODE_STORAGE_KEY);
    if (stored) {
      try {
        const parsed: ViewModeState = JSON.parse(stored);
        return parsed.mode;
      } catch {
        // If parsing fails, default to Architect
        return ViewMode.Architect;
      }
    }
    return ViewMode.Architect;
  });

  // Persist to localStorage whenever mode changes
  useEffect(() => {
    const viewModeState: ViewModeState = {
      mode: currentMode,
      timestamp: Date.now()
    };
    localStorage.setItem(VIEW_MODE_STORAGE_KEY, JSON.stringify(viewModeState));
  }, [currentMode]);

  const setViewMode = (mode: ViewMode) => {
    setCurrentMode(mode);
  };

  const isMode = (mode: ViewMode) => {
    return currentMode === mode;
  };

  const value: ViewModeContextType = {
    currentMode,
    setViewMode,
    isMode
  };

  return (
    <ViewModeContext.Provider value={value}>
      {children}
    </ViewModeContext.Provider>
  );
};

export const useViewMode = () => {
  const context = useContext(ViewModeContext);
  if (context === undefined) {
    throw new Error('useViewMode must be used within a ViewModeProvider');
  }
  return context;
};

