const SwitchFieldComponent: React.FC<{
  field: FieldSpec;
  value: any;
  onChange: (value: any) => void;
  disabled?: boolean;
}> = ({ field, value, onChange, disabled }) => (
  <div className="flex items-center justify-between">
    <div>
      <label className="text-sm font-medium text-gray-700">
