const SelectFrameFieldComponent: React.FC<{
  field: FieldSpec;
  value: any;
  onChange: (value: any) => void;
  frames?: Array<{ id: string; name: string; role?: string }>;
  disabled?: boolean;
}> = ({ field, value, onChange, frames = [], disabled }) => (
