/**
 * User API Key Manager Page
 * =========================
 * 
 * Allows individual users to manage their personal API keys for AI providers
 */

import React, { useState, useEffect } from 'react';
import { ModelProvider, UserApiKey } from '../types/kip';
import ApiKeyForm from '../components/ui/ApiKeyForm';
import HelpTooltip from '../components/ui/HelpTooltip';

interface ApiKeyEntry extends UserApiKey {
  isActive: boolean;
}

const UserApiKeyManagerPage: React.FC = () => {
  const [keys, setKeys] = useState<ApiKeyEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingProvider, setEditingProvider] = useState<ModelProvider | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [revealedKeys, setRevealedKeys] = useState<Set<ModelProvider>>(new Set());

  const providerInfo = {
    openai: {
      name: 'OpenAI',
      description: 'GPT models (GPT-4o, GPT-4 Turbo, etc.)',
      icon: '🤖',
      cost: '$$',
      getKeyUrl: 'https://platform.openai.com/api-keys'
    },
    anthropic: {
      name: 'Anthropic',
      description: 'Claude models (Claude 3.5 Sonnet, etc.)',
      icon: '🧠',
      cost: '$$',
      getKeyUrl: 'https://console.anthropic.com/'
    },
    together: {
      name: 'Together AI',
      description: 'Open-source models (Llama, Mixtral)',
      icon: '🔗',
      cost: '$',
      getKeyUrl: 'https://api.together.xyz/settings/api-keys'
    },
    elevenlabs: {
      name: 'ElevenLabs',
      description: 'Voice synthesis and speech',
      icon: '🎙️',
      cost: '$',
      getKeyUrl: 'https://elevenlabs.io/app/speech-synthesis'
    }
  };

  const allProviders: ModelProvider[] = ['openai', 'anthropic', 'together', 'elevenlabs'];

  useEffect(() => {
    loadUserKeys();
  }, []);

  const loadUserKeys = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Mock API call - replace with actual API
      const response = await fetch('/api/kip/user-keys', {
        headers: {
          'x-user-id': 'current-user-id' // This should come from auth context
        }
      });
      
      if (!response.ok) {
        throw new Error('Failed to load API keys');
      }
      
      const data = await response.json();
      
      // Transform data to include active status
      const userKeys: ApiKeyEntry[] = data.data.map((key: UserApiKey) => ({
        ...key,
        isActive: true // User keys are always active when present
      }));
      
      setKeys(userKeys);
    } catch (err) {
      console.error('Error loading user keys:', err);
      setError('Failed to load your API keys. Please try again.');
      // Show mock data for development
      setKeys([]);
    } finally {
      setLoading(false);
    }
  };

  const handleAddKey = async (provider: ModelProvider, apiKey: string) => {
    try {
      setSubmitting(true);
      setError(null);
      
      const response = await fetch('/api/kip/user-keys', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-user-id': 'current-user-id'
        },
        body: JSON.stringify({ provider, apiKey })
      });
      
      if (!response.ok) {
        throw new Error('Failed to save API key');
      }
      
      setSuccess(`Successfully added ${providerInfo[provider].name} API key!`);
      setShowAddForm(false);
      await loadUserKeys();
      
      // Clear success message after 3 seconds
      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      console.error('Error adding key:', err);
      setError('Failed to save API key. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteKey = async (provider: ModelProvider) => {
    if (!confirm(`Are you sure you want to delete your ${providerInfo[provider].name} API key?`)) {
      return;
    }

    try {
      setSubmitting(true);
      setError(null);
      
      const response = await fetch(`/api/kip/user-keys/${provider}`, {
        method: 'DELETE',
        headers: {
          'x-user-id': 'current-user-id'
        }
      });
      
      if (!response.ok) {
        throw new Error('Failed to delete API key');
      }
      
      setSuccess(`Successfully deleted ${providerInfo[provider].name} API key!`);
      await loadUserKeys();
      
      // Clear success message after 3 seconds
      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      console.error('Error deleting key:', err);
      setError('Failed to delete API key. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const toggleKeyVisibility = (provider: ModelProvider) => {
    const newRevealed = new Set(revealedKeys);
    if (newRevealed.has(provider)) {
      newRevealed.delete(provider);
    } else {
      newRevealed.add(provider);
    }
    setRevealedKeys(newRevealed);
  };

  const getUserKey = (provider: ModelProvider) => {
    return keys.find(key => key.provider === provider);
  };

  const hasUserKey = (provider: ModelProvider) => {
    return !!getUserKey(provider);
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
            <p className="text-muted-foreground">Loading your API keys...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground mb-2">Your API Keys</h1>
        <p className="text-muted-foreground">
          Manage your personal AI provider API keys. When you provide your own keys, you'll have direct control over costs and usage.
        </p>
      </div>

      {/* Success/Error Messages */}
      {success && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-md">
          <p className="text-sm text-green-600">{success}</p>
        </div>
      )}
      
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-md">
          <p className="text-sm text-red-600">{error}</p>
        </div>
      )}

      {/* Add Key Form */}
      {showAddForm && (
        <div className="mb-8 p-6 border border-input rounded-lg bg-background">
          <h2 className="text-xl font-semibold mb-4">Add API Key</h2>
          <ApiKeyForm
            onSubmit={(provider, apiKey) => handleAddKey(provider, apiKey)}
            onCancel={() => setShowAddForm(false)}
            isSubmitting={submitting}
            showLabel={false}
          />
        </div>
      )}

      {/* Provider Cards */}
      <div className="space-y-6">
        {allProviders.map((provider) => {
          const userKey = getUserKey(provider);
          const info = providerInfo[provider];
          const isRevealed = revealedKeys.has(provider);
          
          return (
            <div key={provider} className="border border-input rounded-lg p-6 bg-background">
              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{info.icon}</span>
                  <div>
                    <h3 className="text-lg font-semibold text-foreground flex items-center gap-2">
                      {info.name}
                      <HelpTooltip content={`${info.description}. Cost tier: ${info.cost}. Click to get your API key from their official website.`} />
                    </h3>
                    <p className="text-sm text-muted-foreground">{info.description}</p>
                  </div>
                </div>
                
                {/* Status Badge */}
                <div className="flex items-center gap-2">
                  {userKey ? (
                    <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-medium rounded-full">
                      🔑 Using personal key
                    </span>
                  ) : (
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs font-medium rounded-full">
                      🏢 Falling back to platform key
                    </span>
                  )}
                </div>
              </div>

              {/* Key Display/Actions */}
              {userKey ? (
                <div className="space-y-3">
                  <div className="flex items-center gap-2">
                    <code className="flex-1 px-3 py-2 bg-muted rounded font-mono text-sm">
                      {isRevealed ? userKey.maskedKey.replace(/\*/g, '•') : userKey.maskedKey}
                    </code>
                    <button
                      onClick={() => toggleKeyVisibility(provider)}
                      className="px-3 py-2 text-sm text-muted-foreground hover:text-foreground border border-input rounded"
                      disabled={submitting}
                    >
                      {isRevealed ? '🙈 Hide' : '👁️ Show'}
                    </button>
                    <button
                      onClick={() => handleDeleteKey(provider)}
                      className="px-3 py-2 text-sm text-destructive hover:text-destructive/80 border border-input rounded hover:border-destructive/50"
                      disabled={submitting}
                    >
                      🗑️ Delete
                    </button>
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Your agents will use this key for {info.name} models, giving you direct control over costs and usage.
                  </p>
                </div>
              ) : (
                <div className="space-y-3">
                  <p className="text-sm text-muted-foreground">
                    No personal key configured. Agents will use the platform's shared key for {info.name} models.
                  </p>
                  <div className="flex gap-2">
                    <button
                      onClick={() => {
                        setShowAddForm(true);
                        // Could pre-select this provider
                      }}
                      className="px-3 py-2 text-sm bg-primary hover:bg-primary/90 text-primary-foreground rounded"
                      disabled={submitting}
                    >
                      Add {info.name} Key
                    </button>
                    <a
                      href={info.getKeyUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="px-3 py-2 text-sm border border-input text-foreground hover:bg-accent rounded"
                    >
                      Get API Key ↗
                    </a>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Add Button */}
      {!showAddForm && (
        <div className="mt-8 text-center">
          <button
            onClick={() => setShowAddForm(true)}
            className="px-6 py-3 bg-primary hover:bg-primary/90 text-primary-foreground rounded-md transition-colors"
            disabled={submitting}
          >
            Add New API Key
          </button>
        </div>
      )}

      {/* Info Section */}
      <div className="mt-12 p-6 bg-muted/50 rounded-lg">
        <h3 className="text-lg font-semibold mb-3 flex items-center gap-2">
          How Personal API Keys Work
          <HelpTooltip content="Personal API keys give you direct control over AI costs and usage while providing enhanced privacy for your agents." />
        </h3>
        <div className="space-y-2 text-sm text-muted-foreground">
          <p>• <strong>Cost Control:</strong> Usage is billed directly to your provider account</p>
          <p>• <strong>Privacy:</strong> Your requests go directly to the provider, not through platform logs</p>
          <p>• <strong>Priority:</strong> Your personal keys always take precedence over platform keys</p>
          <p>• <strong>Fallback:</strong> If no personal key is set, agents use the platform's shared keys</p>
          <p>• <strong>Security:</strong> Keys are encrypted and never displayed in full after saving</p>
        </div>
      </div>
    </div>
  );
};

export default UserApiKeyManagerPage;

import React, { useEffect, useState } from 'react';
import { apiFetch } from '../../lib/api';

interface Role {
  id: string;
  name: string;
  description?: string;
}

interface UserRow {
  id: string;
  email: string | null;
  name: string | null;
  roles: string[];
}

interface RoleDetails {
  name: string;
  description: string;
  permissions: {
    implemented: string[];
    needed: string[];
  };
  color: string;
}

const RolesPage: React.FC = () => {
  const [roles, setRoles] = useState<Role[]>([]);
  const [users, setUsers] = useState<UserRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [selectedRole, setSelectedRole] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'assignment' | 'details' | 'permissions'>('assignment');

  // Role details and permissions tracking
  const roleDetails: Record<string, RoleDetails> = {
    'super-admin': {
      name: 'Super Admin',
      description: 'Full platform access with all administrative capabilities',
      permissions: {
        implemented: ['access_admin_pages', 'manage_platform_roles'],
        needed: ['manage_domains', 'manage_users', 'view_analytics', 'manage_api_keys', 'system_configuration']
      },
      color: 'bg-red-100 text-red-800'
    },
    'admin': {
      name: 'Admin',
      description: 'Platform administrator with domain management access',
      permissions: {
        implemented: [],
        needed: ['manage_domains', 'view_analytics', 'manage_users', 'content_moderation']
      },
      color: 'bg-orange-100 text-orange-800'
    },
    'support': {
      name: 'Support',
      description: 'Platform support staff with user assistance access',
      permissions: {
        implemented: [],
        needed: ['view_user_data', 'assist_users', 'view_logs', 'basic_analytics']
      },
      color: 'bg-blue-100 text-blue-800'
    },
    'moderator': {
      name: 'Moderator',
      description: 'Content moderator with content management access',
      permissions: {
        implemented: [],
        needed: ['moderate_content', 'review_reports', 'manage_flags', 'view_content_analytics']
      },
      color: 'bg-yellow-100 text-yellow-800'
    },
    'analyst': {
      name: 'Analyst',
      description: 'Data analyst with read-only access to analytics',
      permissions: {
        implemented: [],
        needed: ['view_analytics', 'export_data', 'view_reports', 'read_only_access']
      },
      color: 'bg-green-100 text-green-800'
    },
    'developer': {
      name: 'Developer',
      description: 'Developer with API and technical access',
      permissions: {
        implemented: [],
        needed: ['api_access', 'view_logs', 'debug_access', 'technical_tools']
      },
      color: 'bg-purple-100 text-purple-800'
    },
    'viewer': {
      name: 'Viewer',
      description: 'Read-only access to platform data',
      permissions: {
        implemented: [],
        needed: ['read_only_access', 'view_public_data', 'basic_reports']
      },
      color: 'bg-gray-100 text-gray-800'
    }
  };

  const load = async () => {
    setLoading(true);
    setError(null);
    try {
      const [rolesRes, usersRes] = await Promise.all([
        apiFetch('/api/admin/roles'),
        apiFetch('/api/admin/roles/users'),
      ]);
      setRoles(rolesRes.roles);
      setUsers(usersRes.users);
    } catch (e: any) {
      const errorMessage = e.response?.data?.error || e.body || e.message || 'Failed to load roles and users';
      setError(errorMessage);
      console.error('Error loading roles:', e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const toggleRole = async (userId: string, roleName: string, hasRole: boolean) => {
    setActionError(null);
    console.log(`[RolesPage] Attempting to ${hasRole ? 'remove' : 'assign'} role '${roleName}' for user ${userId}`);
    
    try {
      if (hasRole) {
        console.log('[RolesPage] Removing role...');
        await apiFetch('/api/admin/roles/assign', {
          method: 'DELETE',
          body: JSON.stringify({ userId, roleName }),
        });
        console.log('[RolesPage] Role removed successfully');
      } else {
        console.log('[RolesPage] Assigning role...');
        await apiFetch('/api/admin/roles/assign', {
          method: 'POST',
          body: JSON.stringify({ userId, roleName }),
        });
        console.log('[RolesPage] Role assigned successfully');
      }
      await load();
    } catch (e: any) {
      console.error('[RolesPage] Error details:', e);
      console.error('[RolesPage] Error response:', e.response);
      console.error('[RolesPage] Error body:', e.body);
      console.error('[RolesPage] Error message:', e.message);
      
      const errorMessage = e.response?.data?.error || e.body || e.message || 'Failed to update role assignment';
      setActionError(errorMessage);
      console.error('Error updating role:', e);
    }
  };

  const getRoleDetails = (roleName: string) => {
    return roleDetails[roleName] || {
      name: roleName,
      description: 'No description available',
      permissions: { implemented: [], needed: [] },
      color: 'bg-gray-100 text-gray-800'
    };
  };

  if (loading) return <div className="p-4">Loading...</div>;
  if (error) return <div className="p-4 text-red-600">Error: {error}</div>;

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-semibold">Platform Roles</h1>
        <div className="flex space-x-2">
          <button
            onClick={() => setActiveTab('assignment')}
            className={`px-4 py-2 rounded ${activeTab === 'assignment' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
          >
            Role Assignment
          </button>
          <button
            onClick={() => setActiveTab('details')}
            className={`px-4 py-2 rounded ${activeTab === 'details' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
          >
            Role Details
          </button>
          <button
            onClick={() => setActiveTab('permissions')}
            className={`px-4 py-2 rounded ${activeTab === 'permissions' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
          >
            Permissions
          </button>
        </div>
      </div>
      
      {actionError && (
        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded text-red-700">
          Error: {actionError}
          <button 
            onClick={() => setActionError(null)}
            className="ml-2 text-red-500 hover:text-red-700"
          >
            ×
          </button>
        </div>
      )}

      {activeTab === 'assignment' && (
        <div className="bg-white rounded-lg shadow">
          <div className="p-4 border-b">
            <h2 className="text-lg font-medium">Role Assignment Matrix</h2>
            <p className="text-sm text-gray-600 mt-1">
              Assign platform roles to users. Check the boxes to grant roles.
            </p>
          </div>
          <div className="overflow-x-auto">
            <table className="min-w-full text-sm">
              <thead>
                <tr className="bg-gray-50 text-left">
                  <th className="p-3 font-medium">User</th>
                  {roles.map((r) => (
                    <th key={r.id} className="p-3 font-medium text-center">
                      <div className="flex flex-col items-center">
                        <span className="capitalize">{r.name}</span>
                        <span className="text-xs text-gray-500">{getRoleDetails(r.name).name}</span>
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id} className="border-t hover:bg-gray-50">
                    <td className="p-3">
                      <div className="font-medium">{u.name || u.email}</div>
                      <div className="text-xs text-gray-500">{u.id}</div>
                    </td>
                    {roles.map((r) => {
                      const hasRole = u.roles.includes(r.name);
                      return (
                        <td key={r.id} className="p-3 text-center">
                          <input
                            type="checkbox"
                            checked={hasRole}
                            onChange={() => toggleRole(u.id, r.name, hasRole)}
                            className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                          />
                        </td>
                      );
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'details' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {roles.map((role) => {
            const details = getRoleDetails(role.name);
            return (
              <div key={role.id} className="bg-white rounded-lg shadow p-4">
                <div className="flex items-center justify-between mb-3">
                  <h3 className="text-lg font-medium">{details.name}</h3>
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${details.color}`}>
                    {role.name}
                  </span>
                </div>
                <p className="text-gray-600 text-sm mb-4">{details.description}</p>
                <div className="space-y-2">
                  <div>
                    <span className="text-xs font-medium text-gray-500">Implemented Permissions:</span>
                    <div className="mt-1">
                      {details.permissions.implemented.length > 0 ? (
                        details.permissions.implemented.map((perm, idx) => (
                          <span key={idx} className="inline-block bg-green-100 text-green-800 text-xs px-2 py-1 rounded mr-1 mb-1">
                            {perm}
                          </span>
                        ))
                      ) : (
                        <span className="text-xs text-gray-400">None implemented</span>
                      )}
                    </div>
                  </div>
                  <div>
                    <span className="text-xs font-medium text-gray-500">Needed Permissions:</span>
                    <div className="mt-1">
                      {details.permissions.needed.map((perm, idx) => (
                        <span key={idx} className="inline-block bg-yellow-100 text-yellow-800 text-xs px-2 py-1 rounded mr-1 mb-1">
                          {perm}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {activeTab === 'permissions' && (
        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-medium mb-4">Permission Implementation Status</h2>
          <div className="space-y-4">
            {Object.entries(roleDetails).map(([roleName, details]) => (
              <div key={roleName} className="border rounded-lg p-4">
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-medium">{details.name}</h3>
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${details.color}`}>
                    {roleName}
                  </span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <h4 className="text-sm font-medium text-green-700 mb-2">✅ Implemented ({details.permissions.implemented.length})</h4>
                    <div className="space-y-1">
                      {details.permissions.implemented.map((perm, idx) => (
                        <div key={idx} className="text-sm bg-green-50 p-2 rounded">
                          {perm}
                        </div>
                      ))}
                    </div>
                  </div>
                  <div>
                    <h4 className="text-sm font-medium text-yellow-700 mb-2">🚧 Needed ({details.permissions.needed.length})</h4>
                    <div className="space-y-1">
                      {details.permissions.needed.map((perm, idx) => (
                        <div key={idx} className="text-sm bg-yellow-50 p-2 rounded">
                          {perm}
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

