      setUsers(response.users || []);
    } catch (e: any) {
      const errorMessage = e.response?.data?.error || e.body || e.message || 'Failed to load users';
      setError(errorMessage);
      console.error('Error loading users:', e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadUsers();
  }, []);

  const filteredUsers = users.filter(user => 
    user.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) return <div className="p-4">Loading users...</div>;
  if (error) return <div className="p-4 text-red-600">Error: {error}</div>;

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-semibold">Platform User Management</h1>
        <div className="flex items-center space-x-4">
          <input
            type="text"
            placeholder="Search users..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
      </div>

      <div className="bg-white rounded-lg shadow">
        <div className="p-4 border-b">
          <h2 className="text-lg font-medium">Platform Users ({filteredUsers.length})</h2>
          <p className="text-sm text-gray-600 mt-1">
            Manage platform users and their roles. This is separate from domain-level user management.
          </p>
        </div>
        
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="bg-gray-50 text-left">
                <th className="p-3 font-medium">User</th>
                <th className="p-3 font-medium">Email</th>
                <th className="p-3 font-medium">Platform Roles</th>
                <th className="p-3 font-medium">Joined</th>
                <th className="p-3 font-medium">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.map((user) => (
                <tr key={user.id} className="border-t hover:bg-gray-50">
                  <td className="p-3">
                    <div className="font-medium">{user.name || 'Unnamed User'}</div>
                    <div className="text-xs text-gray-500">{user.id}</div>
                  </td>
                  <td className="p-3">{user.email}</td>
                  <td className="p-3">
                    <div className="flex flex-wrap gap-1">
                      {user.platformRoles.length > 0 ? (
                        user.platformRoles.map((role) => (
                          <span
                            key={role}
                            className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full"
                          >
                            {role}
                          </span>
                        ))
                      ) : (
                        <span className="text-gray-400 text-xs">No roles</span>
                      )}
                    </div>
                  </td>
                  <td className="p-3 text-xs text-gray-500">
                    {new Date(user.createdAt).toLocaleDateString()}
                  </td>
                  <td className="p-3">
                    <button className="text-blue-600 hover:text-blue-800 text-xs">
                      View Details
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
        <h3 className="font-medium text-blue-800 mb-2">Platform vs Domain User Management</h3>
        <p className="text-sm text-blue-700">
          <strong>Platform Users:</strong> Users who can access the platform. Managed here with platform-level roles.<br/>
          <strong>Domain Users:</strong> Users within specific domains. Managed in each domain's Root Dashboard.
        </p>
      </div>
    </div>
  );
};

export default UserManagementPage;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import { useViewMode } from '../../context/ViewModeContext';
import { ViewMode } from '../../types/viewMode';
import { keeperApi } from '../../lib/keeperApi';
import { Keeper, KeeperType } from '../../types/keeper';
import {
  PlusIcon,
  BookOpenIcon,
  SparklesIcon,
  DocumentTextIcon,
  EyeIcon,
  TrashIcon,
  MagnifyingGlassIcon,
  FunnelIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';

const AllKeepersPage: React.FC = () => {
  const { user } = useAuth();
  const { currentMode } = useViewMode();
  const navigate = useNavigate();
  
  const [keepers, setKeepers] = useState<Keeper[]>([]);
  const [keeperTypes, setKeeperTypes] = useState<KeeperType[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('');
  const [selectedKeeper, setSelectedKeeper] = useState<Keeper | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    loadData();
  }, [user?.id]);

  const loadData = async () => {
    if (!user?.id) return;

    try {
      setLoading(true);
      const [keepersResponse, typesResponse] = await Promise.all([
        keeperApi.getAllKeepers(user.id),
        keeperApi.getKeeperTypes()
      ]);

      if (keepersResponse.success && keepersResponse.data) {
        setKeepers(keepersResponse.data);
      } else {
        setError(keepersResponse.error || 'Failed to load keepers');
      }

      if (typesResponse.success && typesResponse.data) {
        setKeeperTypes(typesResponse.data);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteKeeper = async (keeper: Keeper) => {
    if (!user?.id) return;

    try {
      const response = await keeperApi.deleteKeeper(keeper.id, user.id);
      if (response.success) {
        setKeepers(prev => prev.filter(k => k.id !== keeper.id));
        setShowDeleteModal(false);
        setSelectedKeeper(null);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete keeper');
    }
  };

  const filteredKeepers = keepers.filter(keeper => {
    const matchesSearch = keeper.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         keeper.purpose.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = !selectedType || keeper.keeperType === selectedType;
    return matchesSearch && matchesType;
  });

  const getKeeperTypeColor = (type?: string) => {
    if (!type) return 'bg-gray-100 text-gray-800';
    
    const colors = {
      'ai-keeper-sole': 'bg-blue-100 text-blue-800',
      'personal-journal': 'bg-green-100 text-green-800',
      'project-tracker': 'bg-purple-100 text-purple-800',
      'memory-palace': 'bg-yellow-100 text-yellow-800',
    };
    
    return colors[type as keyof typeof colors] || 'bg-gray-100 text-gray-800';
  };

  const getMemoryPatternIcon = (pattern?: string) => {
    if (!pattern) return <BookOpenIcon className="w-4 h-4" />;
    
    const icons = {
      'sole': <SparklesIcon className="w-4 h-4" />,
      'journal': <DocumentTextIcon className="w-4 h-4" />,
      'tracker': <BookOpenIcon className="w-4 h-4" />,
    };
    
    return icons[pattern as keyof typeof icons] || <BookOpenIcon className="w-4 h-4" />;
  };

  const navigateToKeeper = (keeper: Keeper) => {
    if (currentMode === ViewMode.Architect) {
      navigate(`/keeper/selected/metadata?id=${keeper.id}`);
    } else {
      navigate(`/keeper/${keeper.id}/dashboard`);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-foreground">All Keepers</h1>
          <p className="text-muted-foreground mt-2">
            {currentMode === ViewMode.Architect 
              ? 'Design and manage your Keeper configurations' 
              : 'Manage your personal Keepers'
            }
          </p>
        </div>
        <div className="flex items-center gap-3 mt-4 sm:mt-0">
          <Link
            to="/keeper/new"
            className="inline-flex items-center px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <PlusIcon className="w-4 h-4 mr-2" />
            Create Keeper
          </Link>
        </div>
      </div>

      {/* Search and Filter */}
      <div className="flex flex-col sm:flex-row gap-4 mb-6">
        <div className="relative flex-1">
          <MagnifyingGlassIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <input
            type="text"
            placeholder="Search keepers..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50"
          />
        </div>
        <div className="relative">
          <select
            value={selectedType}
            onChange={(e) => setSelectedType(e.target.value)}
            className="appearance-none px-4 py-2 pr-10 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 bg-background"
          >
            <option value="">All Types</option>
            {keeperTypes.map(type => (
              <option key={type.id} value={type.name}>
                {type.name}
              </option>
            ))}
          </select>
          <FunnelIcon className="absolute right-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground pointer-events-none" />
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
          <p className="text-red-800">{error}</p>
        </div>
      )}

      {/* Keepers Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <AnimatePresence>
          {filteredKeepers.map((keeper) => (
            <motion.div
              key={keeper.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="bg-card border border-border rounded-lg p-6 hover:shadow-lg transition-shadow"
            >
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <h3 className="font-semibold text-foreground mb-1">{keeper.title}</h3>
                  <p className="text-sm text-muted-foreground line-clamp-2">
                    {keeper.purpose}
                  </p>
                </div>
                <div className="flex items-center gap-2 ml-4">
                  {getMemoryPatternIcon(keeper.memoryPattern)}
                </div>
              </div>

              {/* Keeper Type Badge */}
              {keeper.keeperType && (
                <div className="mb-4">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${getKeeperTypeColor(keeper.keeperType)}`}>
                    {keeper.keeperType}
                  </span>
                </div>
              )}

              {/* Stats */}
              <div className="flex items-center gap-4 mb-4 text-sm text-muted-foreground">
                <div className="flex items-center gap-1">
                  <BookOpenIcon className="w-4 h-4" />
                  <span>{keeper._count?.Journey || 0} journeys</span>
                </div>
                <div className="flex items-center gap-1">
                  <DocumentTextIcon className="w-4 h-4" />
                  <span>{keeper._count?.Path || 0} paths</span>
                </div>
              </div>

              {/* Actions */}
              <div className="flex items-center gap-2">
                <button
                  onClick={() => navigateToKeeper(keeper)}
                  className="flex-1 inline-flex items-center justify-center px-3 py-2 text-sm font-medium text-primary bg-primary/10 rounded-lg hover:bg-primary/20 transition-colors"
                >
                  <EyeIcon className="w-4 h-4 mr-2" />
                  {currentMode === ViewMode.Architect ? 'Configure' : 'View'}
                </button>
                {currentMode === ViewMode.Architect && (
                  <button
                    onClick={() => {
                      setSelectedKeeper(keeper);
                      setShowDeleteModal(true);
                    }}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  >
                    <TrashIcon className="w-4 h-4" />
                  </button>
                )}
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      {/* Empty State */}
      {filteredKeepers.length === 0 && !loading && (
        <div className="text-center py-12">
          <BookOpenIcon className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-foreground mb-2">No keepers found</h3>
          <p className="text-muted-foreground mb-4">
            {searchTerm || selectedType 
              ? 'Try adjusting your search or filter criteria'
              : 'Create your first keeper to get started'
            }
          </p>
          <Link
            to="/keeper/new"
            className="inline-flex items-center px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <PlusIcon className="w-4 h-4 mr-2" />
            Create Keeper
          </Link>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      <AnimatePresence>
        {showDeleteModal && selectedKeeper && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50"
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="bg-card border border-border rounded-lg p-6 max-w-md w-full mx-4"
            >
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold text-foreground">Delete Keeper</h3>
                <button
                  onClick={() => setShowDeleteModal(false)}
                  className="p-1 hover:bg-muted rounded-lg"
                >
                  <XMarkIcon className="w-5 h-5" />
                </button>
              </div>
              
              <p className="text-muted-foreground mb-6">
                Are you sure you want to delete "{selectedKeeper.title}"? This action cannot be undone.
              </p>
              
              <div className="flex justify-end gap-3">
                <button
                  onClick={() => setShowDeleteModal(false)}
                  className="px-4 py-2 text-sm font-medium text-muted-foreground hover:text-foreground transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={() => handleDeleteKeeper(selectedKeeper)}
                  className="px-4 py-2 text-sm font-medium bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
                >
                  Delete
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AllKeepersPage;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { InformationCircleIcon } from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import EchoWriter from '../../components/engagement/EchoWriter';

const EchoWriterPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [keeper, setKeeper] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Demo mode check
  const isDemo = id === 'demo';

  useEffect(() => {
    if (isDemo) {
      // Demo mode - skip keeper fetch
      setKeeper({
        id: 'demo',
        title: 'Demo Keeper',
        purpose: 'Demonstration of Echo Writer functionality'
      });
      setLoading(false);
      return;
    }

    const fetchKeeper = async () => {
      try {
        const response = await fetch(`/api/keeper/keepers/${id}`);
        
        if (!response.ok) {
          throw new Error('Failed to fetch keeper');
        }

        const data = await response.json();
        
        if (data.success && data.data) {
          setKeeper(data.data);
        } else {
          throw new Error(data.error || 'Failed to fetch keeper');
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setLoading(false);
      }
    };

    fetchKeeper();
  }, [id, isDemo]);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <p className="text-red-800">Error: {error}</p>
          <button 
            onClick={() => navigate('/keeper')}
            className="mt-2 text-sm text-red-600 hover:text-red-800 underline"
          >
            Return to Keepers
          </button>
        </div>
      </div>
    );
  }

  if (!keeper) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <p className="text-yellow-800">Keeper not found</p>
          <button 
            onClick={() => navigate('/keeper')}
            className="mt-2 text-sm text-yellow-600 hover:text-yellow-800 underline"
          >
            Return to Keepers
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-6">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="mb-6"
      >
        <div className="flex items-center gap-3 mb-2">
          <button
            onClick={() => navigate('/keeper')}
            className="text-blue-600 hover:text-blue-800 text-sm font-medium"
          >
            ← Back to Keepers
          </button>
          {isDemo && (
            <div className="flex items-center gap-2 bg-blue-50 border border-blue-200 rounded-lg px-3 py-1">
              <InformationCircleIcon className="h-4 w-4 text-blue-600" />
              <span className="text-sm text-blue-700">Demo Mode</span>
            </div>
          )}
        </div>
        <h1 className="text-3xl font-bold text-gray-900">
          {keeper.title} - Echo Writer
        </h1>
        <p className="text-gray-600 mt-1">{keeper.purpose}</p>
      </motion.div>

      {/* Echo Writer Component */}
      <EchoWriter
        keeperId={keeper.id}
        agentId={keeper.ownerId || 'demo-agent'}
        isDemo={isDemo}
      />
    </div>
  );
};

export default EchoWriterPage;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  DocumentTextIcon,
  Cog6ToothIcon,
  PlusIcon
} from '@heroicons/react/24/outline';

type TabType = 'content-types' | 'engagement-process';

type ContentType = {
  id: string;
  name: string;
  description: string;
  category: 'Text' | 'Media' | 'Interactive' | 'Custom';
  fields: string[];
  system: boolean;
  _count?: { templates: number };
};

type EngagementProcess = {
  id: string;
  name: string;
  description: string;
  steps: string[];
  category: 'Sequential' | 'Parallel' | 'Conditional';
  system: boolean;
  _count?: { templates: number };
};

const EngagementTemplatesPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('content-types');
  const [contentTypes, setContentTypes] = useState<ContentType[]>([]);
  const [engagementProcesses, setEngagementProcesses] = useState<EngagementProcess[]>([]);
  const [selectedContentType, setSelectedContentType] = useState<ContentType | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<EngagementProcess | null>(null);

  // Mock data for Content Types
  const mockContentTypes: ContentType[] = [
    {
      id: 'text-prompt',
      name: 'Text Prompt',
      description: 'Simple text-based prompts and questions for keeper interaction',
      category: 'Text',
      fields: ['prompt', 'context', 'expected_response_type'],
      system: true,
      _count: { templates: 12 }
    },
    {
      id: 'reflection-card',
      name: 'Reflection Card',
      description: 'Structured reflection prompts with guided questions',
      category: 'Interactive',
      fields: ['title', 'questions', 'reflection_type', 'tags'],
      system: true,
      _count: { templates: 8 }
    },
    {
      id: 'memory-trigger',
      name: 'Memory Trigger',
      description: 'Content designed to trigger specific memory recall',
      category: 'Interactive',
      fields: ['trigger_text', 'memory_type', 'context_clues'],
      system: true,
      _count: { templates: 5 }
    }
  ];

  // Mock data for Engagement Processes
  const mockEngagementProcesses: EngagementProcess[] = [
    {
      id: 'sole-dialogue',
      name: 'SOLE Dialogue',
      description: 'Self-Organizing Learning Environment conversation flow',
      steps: ['Initial Prompt', 'Memory Activation', 'Pattern Recognition', 'Synthesis'],
      category: 'Sequential',
      system: true,
      _count: { templates: 15 }
    },
    {
      id: 'reflection-journal',
      name: 'Reflection Journal',
      description: 'Guided reflection process with iterative deepening',
      steps: ['Surface Reflection', 'Deep Dive', 'Pattern Analysis', 'Future Integration'],
      category: 'Sequential',
      system: true,
      _count: { templates: 10 }
    },
    {
      id: 'memory-weaving',
      name: 'Memory Weaving',
      description: 'Process for connecting disparate memories into coherent narratives',
      steps: ['Memory Collection', 'Pattern Identification', 'Narrative Construction', 'Integration'],
      category: 'Conditional',
      system: true,
      _count: { templates: 6 }
    }
  ];

  useEffect(() => {
    setContentTypes(mockContentTypes);
    setEngagementProcesses(mockEngagementProcesses);
    setSelectedContentType(mockContentTypes[0]);
    setSelectedProcess(mockEngagementProcesses[0]);
  }, []);

  const renderTabButton = (tab: TabType, icon: React.ReactNode, label: string) => (
    <button
      onClick={() => setActiveTab(tab)}
      className={`flex items-center gap-2 px-4 py-2 font-medium text-sm rounded-lg transition-colors ${
        activeTab === tab
          ? 'bg-primary text-primary-foreground'
          : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
      }`}
    >
      {icon}
      {label}
    </button>
  );

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Text': return 'bg-blue-100 text-blue-800';
      case 'Media': return 'bg-purple-100 text-purple-800';
      case 'Interactive': return 'bg-green-100 text-green-800';
      case 'Sequential': return 'bg-indigo-100 text-indigo-800';
      case 'Parallel': return 'bg-yellow-100 text-yellow-800';
      case 'Conditional': return 'bg-pink-100 text-pink-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const renderContentTypesTab = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-semibold text-foreground">Content Types</h2>
          <p className="text-muted-foreground mt-1">Define structured content formats for keeper engagement</p>
        </div>
        <button
          disabled
          className="inline-flex items-center gap-2 px-4 py-2 bg-muted text-muted-foreground rounded-lg cursor-not-allowed"
        >
          <PlusIcon className="w-4 h-4" />
          Create Content Type
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Content Types List */}
        <div className="space-y-4">
          {contentTypes.map((contentType) => (
            <motion.div
              key={contentType.id}
              className={`p-4 border rounded-lg cursor-pointer transition-all ${
                selectedContentType?.id === contentType.id
                  ? 'border-primary bg-primary/5'
                  : 'border-border hover:border-primary/50'
              }`}
              onClick={() => setSelectedContentType(contentType)}
            >
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-medium text-foreground">{contentType.name}</h3>
                <span className={`px-2 py-1 rounded text-xs ${getCategoryColor(contentType.category)}`}>
                  {contentType.category}
                </span>
              </div>
              <p className="text-sm text-muted-foreground mb-2">{contentType.description}</p>
              <div className="text-xs text-muted-foreground">
                {contentType._count?.templates || 0} templates using this type
              </div>
            </motion.div>
          ))}
        </div>

        {/* Content Type Details */}
        {selectedContentType && (
          <motion.div
            key={selectedContentType.id}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="bg-card border border-border rounded-lg p-6"
          >
            <h3 className="text-lg font-semibold text-foreground mb-4">Content Type Details</h3>
            <div className="space-y-4">
              <div>
                <label className="text-sm font-medium text-muted-foreground">Name</label>
                <p className="text-foreground mt-1">{selectedContentType.name}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Category</label>
                <p className="text-foreground mt-1">{selectedContentType.category}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Description</label>
                <p className="text-foreground mt-1">{selectedContentType.description}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Fields</label>
                <div className="mt-2 space-y-1">
                  {selectedContentType.fields.map((field, index) => (
                    <div key={index} className="text-sm text-foreground flex items-center gap-2">
                      <span className="w-1.5 h-1.5 bg-primary rounded-full"></span>
                      {field}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </div>
    </div>
  );

  const renderEngagementProcessTab = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-semibold text-foreground">Engagement Processes</h2>
          <p className="text-muted-foreground mt-1">Define workflow patterns for keeper interactions</p>
        </div>
        <button
          disabled
          className="inline-flex items-center gap-2 px-4 py-2 bg-muted text-muted-foreground rounded-lg cursor-not-allowed"
        >
          <PlusIcon className="w-4 h-4" />
          Create Process
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Processes List */}
        <div className="space-y-4">
          {engagementProcesses.map((process) => (
            <motion.div
              key={process.id}
              className={`p-4 border rounded-lg cursor-pointer transition-all ${
                selectedProcess?.id === process.id
                  ? 'border-primary bg-primary/5'
                  : 'border-border hover:border-primary/50'
              }`}
              onClick={() => setSelectedProcess(process)}
            >
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-medium text-foreground">{process.name}</h3>
                <span className={`px-2 py-1 rounded text-xs ${getCategoryColor(process.category)}`}>
                  {process.category}
                </span>
              </div>
              <p className="text-sm text-muted-foreground mb-2">{process.description}</p>
              <div className="text-xs text-muted-foreground">
                {process._count?.templates || 0} templates using this process
              </div>
            </motion.div>
          ))}
        </div>

        {/* Process Details */}
        {selectedProcess && (
          <motion.div
            key={selectedProcess.id}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            className="bg-card border border-border rounded-lg p-6"
          >
            <h3 className="text-lg font-semibold text-foreground mb-4">Process Details</h3>
            <div className="space-y-4">
              <div>
                <label className="text-sm font-medium text-muted-foreground">Name</label>
                <p className="text-foreground mt-1">{selectedProcess.name}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Category</label>
                <p className="text-foreground mt-1">{selectedProcess.category}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Description</label>
                <p className="text-foreground mt-1">{selectedProcess.description}</p>
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground">Process Steps</label>
                <div className="mt-2 space-y-2">
                  {selectedProcess.steps.map((step, index) => (
                    <div key={index} className="text-sm text-foreground flex items-center gap-2">
                      <span className="w-6 h-6 bg-primary/10 text-primary rounded-full flex items-center justify-center text-xs font-medium">
                        {index + 1}
                      </span>
                      {step}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </div>
    </div>
  );

  return (
    <motion.div
      className="max-w-7xl mx-auto"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
    >
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground mb-2">Engagement Templates</h1>
        <p className="text-muted-foreground">
          Build structured keeper interactions using Content Types and Engagement Processes
        </p>
      </div>

      {/* Coming Soon Notice */}
      <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-8">
        <p className="text-amber-800 text-sm">
          <strong>Coming Soon:</strong> Engagement Templates will combine Content Types and Engagement Processes 
          to create structured keeper interaction patterns. Template creation and management tools are in development.
        </p>
      </div>

      {/* Tab Navigation */}
      <div className="flex space-x-2 mb-8">
        {renderTabButton('content-types', <DocumentTextIcon className="w-4 h-4" />, 'Content Types')}
        {renderTabButton('engagement-process', <Cog6ToothIcon className="w-4 h-4" />, 'Engagement Process')}
      </div>

      {/* Tab Content */}
      <motion.div
        key={activeTab}
        initial={{ opacity: 0, x: 20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.3 }}
      >
        {activeTab === 'content-types' && renderContentTypesTab()}
        {activeTab === 'engagement-process' && renderEngagementProcessTab()}
      </motion.div>
    </motion.div>
  );
};

export default EngagementTemplatesPage;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { InformationCircleIcon } from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import IdentityLogbook from '../../components/engagement/IdentityLogbook';

const IdentityLogbookPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [keeper, setKeeper] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Demo mode check
  const isDemo = id === 'demo';

  useEffect(() => {
    if (isDemo) {
      // Demo mode - skip keeper fetch
      setKeeper({
        id: 'demo',
        title: 'Demo Keeper',
        purpose: 'Demonstration of Identity Logbook functionality'
      });
      setLoading(false);
      return;
    }

    const fetchKeeper = async () => {
      try {
        const response = await fetch(`/api/keeper/keepers/${id}`);
        
        if (!response.ok) {
          throw new Error('Failed to fetch keeper');
        }

        const data = await response.json();
        
        if (data.success && data.data) {
          setKeeper(data.data);
        } else {
          throw new Error(data.error || 'Failed to fetch keeper');
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setLoading(false);
      }
    };

    fetchKeeper();
  }, [id, isDemo]);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <p className="text-red-800">Error: {error}</p>
          <button 
            onClick={() => navigate('/keeper')}
            className="mt-2 text-sm text-red-600 hover:text-red-800 underline"
          >
            Return to Keepers
          </button>
        </div>
      </div>
    );
  }

  if (!keeper) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <p className="text-yellow-800">Keeper not found</p>
          <button 
            onClick={() => navigate('/keeper')}
            className="mt-2 text-sm text-yellow-600 hover:text-yellow-800 underline"
          >
            Return to Keepers
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-6">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="mb-6"
      >
        <div className="flex items-center gap-3 mb-2">
          <button
            onClick={() => navigate('/keeper')}
            className="text-blue-600 hover:text-blue-800 text-sm font-medium"
          >
            ← Back to Keepers
          </button>
          {isDemo && (
            <div className="flex items-center gap-2 bg-blue-50 border border-blue-200 rounded-lg px-3 py-1">
              <InformationCircleIcon className="h-4 w-4 text-blue-600" />
              <span className="text-sm text-blue-700">Demo Mode</span>
            </div>
          )}
        </div>
        <h1 className="text-3xl font-bold text-gray-900">
          {keeper.title} - Identity Logbook
        </h1>
        <p className="text-gray-600 mt-1">{keeper.purpose}</p>
      </motion.div>

      {/* Identity Logbook Component */}
      <IdentityLogbook
        keeperId={keeper.id}
        agentId={keeper.ownerId || 'demo-agent'}
        isDemo={isDemo}
      />
    </div>
  );
};

export default IdentityLogbookPage;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import { useViewMode } from '../../context/ViewModeContext';
import { keeperApi } from '../../lib/keeperApi';
import { Keeper, KeeperType, UpdateKeeperRequest } from '../../types/keeper';
import {
  BookOpenIcon,
  CogIcon,
  PlusIcon,
  PencilIcon,
  TrashIcon,
  EyeIcon,
  ArrowPathIcon,
  TagIcon,
  SparklesIcon,
  ChatBubbleLeftRightIcon,
  DocumentDuplicateIcon,
  CalendarIcon,
  UserIcon
} from '@heroicons/react/24/outline';

type TabType = 'registry' | 'keeper';

const KeeperManagePage: React.FC = () => {
  const { user } = useAuth();
  const { currentMode } = useViewMode();
  const [activeTab, setActiveTab] = useState<TabType>('registry');
  
  // State for keepers and types
  const [keepers, setKeepers] = useState<Keeper[]>([]);
  const [keeperTypes, setKeeperTypes] = useState<KeeperType[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  
  // State for selected keeper and form
  const [selectedKeeper, setSelectedKeeper] = useState<Keeper | null>(null);
  const [editedKeeper, setEditedKeeper] = useState<UpdateKeeperRequest>({});
  const [isEditing, setIsEditing] = useState(false);
  const [saving, setSaving] = useState(false);
  
  // State for deletion
  const [deletingKeeper, setDeletingKeeper] = useState<Keeper | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    if (user?.id) {
      loadData();
    }
  }, [user?.id]);

  const loadData = async () => {
    if (!user?.id) return;

    try {
      setLoading(true);
      setError(null);
      const [keepersResponse, typesResponse] = await Promise.all([
        keeperApi.getAllKeepers(user.id),
        keeperApi.getKeeperTypes()
      ]);

      if (keepersResponse.success && keepersResponse.data) {
        setKeepers(keepersResponse.data);
      } else {
        setError(keepersResponse.error || 'Failed to load keepers');
      }

      if (typesResponse.success && typesResponse.data) {
        setKeeperTypes(typesResponse.data);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleSelectKeeper = (keeper: Keeper) => {
    setSelectedKeeper(keeper);
    setEditedKeeper({
      title: keeper.title,
      purpose: keeper.purpose,
      keeperTypeId: keeper.keeperTypeId || '',
      keeperType: keeper.keeperType || '',
      memoryPattern: keeper.memoryPattern || ''
    });
    setActiveTab('keeper');
  };

  const handleCreateNewKeeper = () => {
    setSelectedKeeper(null);
    setEditedKeeper({});
    setActiveTab('keeper');
  };

  const handleBackToRegistry = () => {
    setSelectedKeeper(null);
    setEditedKeeper({});
    setIsEditing(false);
    setActiveTab('registry');
  };

  const handleSaveKeeper = async () => {
    if (!user?.id) return;

    try {
      setSaving(true);
      
      if (selectedKeeper) {
        // Update existing keeper
        const response = await keeperApi.updateKeeper(selectedKeeper.id, editedKeeper, user.id);
        if (response.success && response.data) {
          setKeepers(prev => prev.map(k => k.id === selectedKeeper.id ? response.data! : k));
          setSelectedKeeper(response.data);
          setIsEditing(false);
          setError(null);
        } else {
          setError(response.error || 'Failed to update keeper');
        }
      } else {
        // Create new keeper
        const createData = {
          ...editedKeeper,
          ownerId: user.id
        };
        const response = await keeperApi.createKeeper(createData as any);
        if (response.success && response.data) {
          setKeepers(prev => [...prev, response.data!]);
          setActiveTab('registry');
        } else {
          setError(response.error || 'Failed to create keeper');
        }
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to save keeper');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteKeeper = async (keeper: Keeper) => {
    setDeletingKeeper(keeper);
  };

  const confirmDelete = async () => {
    if (!deletingKeeper || !user?.id) return;
    
    setIsDeleting(true);
    try {
      const response = await keeperApi.deleteKeeper(deletingKeeper.id, user.id);
      if (response.success) {
        setKeepers(prev => prev.filter(k => k.id !== deletingKeeper.id));
        setDeletingKeeper(null);
        // If we're deleting the currently selected keeper, go back to registry
        if (selectedKeeper?.id === deletingKeeper.id) {
          handleBackToRegistry();
        }
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete keeper');
    } finally {
      setIsDeleting(false);
    }
  };

  const cancelDelete = () => {
    setDeletingKeeper(null);
  };

  const getKeeperTypeColor = (type?: string) => {
    if (!type) return 'bg-gray-100 text-gray-800';
    
    const colors = {
      'ai-keeper-sole': 'bg-blue-100 text-blue-800',
      'personal-journal': 'bg-green-100 text-green-800',
      'project-tracker': 'bg-purple-100 text-purple-800',
      'memory-palace': 'bg-yellow-100 text-yellow-800',
    };
    
    return colors[type as keyof typeof colors] || 'bg-gray-100 text-gray-800';
  };

  const getMemoryPatternIcon = (pattern?: string) => {
    if (!pattern) return <BookOpenIcon className="w-4 h-4" />;
    
    const icons = {
      'sole': <SparklesIcon className="w-4 h-4" />,
      'journal': <DocumentDuplicateIcon className="w-4 h-4" />,
      'tracker': <BookOpenIcon className="w-4 h-4" />,
    };
    
    return icons[pattern as keyof typeof icons] || <BookOpenIcon className="w-4 h-4" />;
  };

  const renderTabButton = (tab: TabType, icon: React.ReactNode, label: string) => (
    <button
      onClick={() => setActiveTab(tab)}
      className={`flex items-center gap-2 px-4 py-2 font-medium text-sm rounded-lg transition-colors ${
        activeTab === tab
          ? 'bg-primary text-primary-foreground'
          : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
      }`}
    >
      {icon}
      {label}
    </button>
  );

  const renderRegistryTab = () => (
    <div className="space-y-6">
      {/* Registry Header */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-semibold text-foreground">Keeper Registry</h2>
          <p className="text-muted-foreground mt-1">Select a keeper to view and edit, or create a new one</p>
        </div>
        <div className="flex items-center gap-3">
          <button
            onClick={loadData}
            disabled={loading}
            className="inline-flex items-center gap-2 px-3 py-2 text-sm text-muted-foreground hover:text-foreground border border-border rounded-lg hover:bg-muted/50 transition-colors disabled:opacity-50"
          >
            <ArrowPathIcon className="w-4 h-4" />
            {loading ? 'Refreshing...' : 'Refresh'}
          </button>
          <button
            onClick={handleCreateNewKeeper}
            className="inline-flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
          >
            <PlusIcon className="w-4 h-4" />
            Create New Keeper
          </button>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
          <p className="text-sm text-red-600">{error}</p>
          <button 
            onClick={loadData}
            className="mt-2 text-sm text-red-700 hover:text-red-900 underline"
          >
            Retry
          </button>
        </div>
      )}

      {/* Loading State */}
      {loading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          <span className="ml-2 text-sm text-muted-foreground">Loading keepers...</span>
        </div>
      ) : (
        /* Keeper Grid */
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {keepers.map((keeper) => (
            <motion.div
              key={keeper.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="bg-card border border-border rounded-lg p-4 space-y-3 hover:shadow-md transition-shadow cursor-pointer"
              onClick={() => handleSelectKeeper(keeper)}
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <h3 className="font-semibold text-foreground mb-1">{keeper.title}</h3>
                  <p className="text-sm text-muted-foreground line-clamp-2">
                    {keeper.purpose}
                  </p>
                </div>
                <div className="flex items-center gap-2 ml-4">
                  {getMemoryPatternIcon(keeper.memoryPattern)}
                </div>
              </div>

              {/* Keeper Type Badge */}
              {keeper.keeperType && (
                <div className="mb-2">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${getKeeperTypeColor(keeper.keeperType)}`}>
                    {keeper.keeperType}
                  </span>
                </div>
              )}

              {/* Stats */}
              <div className="flex items-center gap-4 mb-3 text-sm text-muted-foreground">
                <div className="flex items-center gap-1">
                  <BookOpenIcon className="w-4 h-4" />
                  <span>{keeper._count?.Journey || 0} journeys</span>
                </div>
                <div className="flex items-center gap-1">
                  <DocumentDuplicateIcon className="w-4 h-4" />
                  <span>{keeper._count?.Path || 0} paths</span>
                </div>
              </div>

              <div className="flex space-x-2" onClick={(e) => e.stopPropagation()}>
                <button
                  onClick={() => handleSelectKeeper(keeper)}
                  className="flex-1 inline-flex items-center justify-center gap-1 px-3 py-2 text-xs bg-primary hover:bg-primary/90 text-primary-foreground rounded transition-colors"
                >
                  <EyeIcon className="w-3 h-3" />
                  Configure
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDeleteKeeper(keeper);
                  }}
                  disabled={isDeleting}
                  className="px-3 py-2 text-xs bg-red-600 hover:bg-red-700 disabled:bg-red-300 text-white rounded transition-colors"
                >
                  <TrashIcon className="w-3 h-3" />
                </button>
              </div>
            </motion.div>
          ))}
          
          {keepers.length === 0 && !loading && (
            <div className="col-span-full text-center py-12">
              <BookOpenIcon className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
              <h3 className="text-lg font-semibold text-foreground mb-2">No keepers found</h3>
              <p className="text-muted-foreground mb-4">
                Create your first keeper to get started with the platform.
              </p>
              <button
                onClick={handleCreateNewKeeper}
                className="inline-flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
              >
                <PlusIcon className="w-4 h-4" />
                Create New Keeper
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );

  const renderKeeperTab = () => (
    <div className="space-y-6">
      {/* Keeper Header */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-semibold text-foreground">
            {selectedKeeper ? 'Keeper Configuration' : 'Create New Keeper'}
          </h2>
          <p className="text-muted-foreground mt-1">
            {selectedKeeper 
              ? `Configure metadata, engagement templates, and memory tools for ${selectedKeeper.title}` 
              : 'Set up a new keeper with metadata and configuration settings'
            }
          </p>
        </div>
        <button
          onClick={handleBackToRegistry}
          className="px-4 py-2 text-sm text-muted-foreground border border-border rounded-lg hover:bg-muted/50 transition-colors"
        >
          ← Back to Registry
        </button>
      </div>

      {/* Configuration Sections */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Basic Information */}
        <div className="bg-card border border-border rounded-lg p-6">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <BookOpenIcon className="w-6 h-6 text-primary" />
              <h3 className="text-xl font-semibold text-foreground">Basic Information</h3>
            </div>
            {selectedKeeper && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className="inline-flex items-center gap-2 px-3 py-2 text-sm bg-secondary hover:bg-secondary/90 text-secondary-foreground rounded-lg transition-colors"
              >
                <PencilIcon className="w-4 h-4" />
                {isEditing ? 'Cancel' : 'Edit'}
              </button>
            )}
          </div>

          <div className="space-y-4">
            {/* Title */}
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Title *
              </label>
              {isEditing || !selectedKeeper ? (
                <input
                  type="text"
                  value={editedKeeper.title || ''}
                  onChange={(e) => setEditedKeeper(prev => ({ ...prev, title: e.target.value }))}
                  className="w-full px-3 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50"
                  placeholder="Enter keeper title"
                />
              ) : (
                <p className="text-foreground font-medium">{selectedKeeper.title}</p>
              )}
            </div>

            {/* Purpose */}
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Purpose *
              </label>
              {isEditing || !selectedKeeper ? (
                <textarea
                  value={editedKeeper.purpose || ''}
                  onChange={(e) => setEditedKeeper(prev => ({ ...prev, purpose: e.target.value }))}
                  rows={3}
                  className="w-full px-3 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50 resize-none"
                  placeholder="Describe the keeper's purpose"
                />
              ) : (
                <p className="text-muted-foreground">{selectedKeeper.purpose}</p>
              )}
            </div>

            {/* Keeper Type */}
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Keeper Type
              </label>
              {isEditing || !selectedKeeper ? (
                <select
                  value={editedKeeper.keeperType || ''}
                  onChange={(e) => {
                    const selectedType = keeperTypes.find(t => t.name === e.target.value);
                    setEditedKeeper(prev => ({ 
                      ...prev, 
                      keeperType: e.target.value,
                      keeperTypeId: selectedType?.id || ''
                    }));
                  }}
                  className="w-full px-3 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50"
                >
                  <option value="">Select a type</option>
                  {keeperTypes.map(type => (
                    <option key={type.id} value={type.name}>
                      {type.name}
                    </option>
                  ))}
                </select>
              ) : (
                <div className="flex items-center gap-2">
                  <TagIcon className="w-4 h-4 text-muted-foreground" />
                  <span className="text-foreground">{selectedKeeper.keeperType || 'Not assigned'}</span>
                </div>
              )}
            </div>

            {/* Memory Pattern */}
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Memory Pattern
              </label>
              {isEditing || !selectedKeeper ? (
                <select
                  value={editedKeeper.memoryPattern || ''}
                  onChange={(e) => setEditedKeeper(prev => ({ ...prev, memoryPattern: e.target.value }))}
                  className="w-full px-3 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/50"
                >
                  <option value="">Select a pattern</option>
                  <option value="sole">SOLE (Structured Ontological Learning Experience)</option>
                  <option value="journal">Journal (Chronological)</option>
                  <option value="tracker">Tracker (Project-based)</option>
                  <option value="palace">Memory Palace (Spatial)</option>
                </select>
              ) : (
                <div className="flex items-center gap-2">
                  <CogIcon className="w-4 h-4 text-muted-foreground" />
                  <span className="text-foreground">{selectedKeeper.memoryPattern || 'Not specified'}</span>
                </div>
              )}
            </div>

            {/* Save Button */}
            {(isEditing || !selectedKeeper) && (
              <div className="pt-4">
                <button
                  onClick={handleSaveKeeper}
                  disabled={saving || !editedKeeper.title || !editedKeeper.purpose}
                  className="w-full px-4 py-2 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50"
                >
                  {saving ? 'Saving...' : (selectedKeeper ? 'Update Keeper' : 'Create Keeper')}
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Metadata & Tools */}
        <div className="bg-card border border-border rounded-lg p-6">
          <div className="flex items-center gap-3 mb-6">
            <CogIcon className="w-6 h-6 text-primary" />
            <h3 className="text-xl font-semibold text-foreground">Configuration & Tools</h3>
          </div>

          {selectedKeeper ? (
            <div className="space-y-6">
              {/* Metadata */}
              <div>
                <h4 className="text-sm font-medium text-foreground mb-3">Metadata</h4>
                <div className="space-y-2 text-sm">
                  <div className="flex items-center gap-2">
                    <UserIcon className="w-4 h-4 text-muted-foreground" />
                    <span className="text-muted-foreground">Owner:</span>
                    <span className="text-foreground">{user?.name || user?.email}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <CalendarIcon className="w-4 h-4 text-muted-foreground" />
                    <span className="text-muted-foreground">Created:</span>
                    <span className="text-foreground">
                      {new Date(selectedKeeper.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <CalendarIcon className="w-4 h-4 text-muted-foreground" />
                    <span className="text-muted-foreground">Updated:</span>
                    <span className="text-foreground">
                      {new Date(selectedKeeper.updatedAt).toLocaleDateString()}
                    </span>
                  </div>
                </div>
              </div>

              {/* Statistics */}
              <div>
                <h4 className="text-sm font-medium text-foreground mb-3">Statistics</h4>
                <div className="grid grid-cols-2 gap-3">
                  <div className="text-center p-3 bg-muted/50 rounded-lg">
                    <div className="text-xl font-bold text-primary">{selectedKeeper._count?.Journey || 0}</div>
                    <div className="text-xs text-muted-foreground">Journeys</div>
                  </div>
                  <div className="text-center p-3 bg-muted/50 rounded-lg">
                    <div className="text-xl font-bold text-primary">{selectedKeeper._count?.Path || 0}</div>
                    <div className="text-xs text-muted-foreground">Paths</div>
                  </div>
                </div>
              </div>

              {/* Available Tools */}
              <div>
                <h4 className="text-sm font-medium text-foreground mb-3">Available Tools</h4>
                <div className="space-y-2">
                  <div className="flex items-center justify-between p-3 border border-border rounded-lg">
                    <div className="flex items-center gap-2">
                      <DocumentDuplicateIcon className="w-4 h-4 text-primary" />
                      <span className="text-sm font-medium">Metadata Management</span>
                    </div>
                    <span className="text-xs text-green-600 bg-green-100 px-2 py-1 rounded-full">Active</span>
                  </div>
                  
                  <div className="flex items-center justify-between p-3 border border-border rounded-lg">
                    <div className="flex items-center gap-2">
                      <ChatBubbleLeftRightIcon className="w-4 h-4 text-primary" />
                      <span className="text-sm font-medium">Engagement Templates</span>
                    </div>
                    <span className="text-xs text-blue-600 bg-blue-100 px-2 py-1 rounded-full">
                      {selectedKeeper.engagement_templates?.length || 0} templates
                    </span>
                  </div>

                  {selectedKeeper.memoryPattern && (
                    <div className="flex items-center justify-between p-3 border border-border rounded-lg">
                      <div className="flex items-center gap-2">
                        <SparklesIcon className="w-4 h-4 text-primary" />
                        <span className="text-sm font-medium">Memory Pattern Tools</span>
                      </div>
                      <span className="text-xs text-purple-600 bg-purple-100 px-2 py-1 rounded-full">
                        {selectedKeeper.memoryPattern.toUpperCase()}
                      </span>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ) : (
            <div className="text-center py-8 text-muted-foreground">
              <CogIcon className="w-12 h-12 mx-auto mb-3 opacity-50" />
              <p>Configuration options will appear after creating the keeper.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );

  return (
    <motion.div
      className="max-w-6xl mx-auto py-8 px-4 sm:px-6 lg:px-8"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
    >
      {/* Header */}
      <header className="mb-8">
        <div>
          <h1 className="text-3xl font-bold text-foreground">
            Manage Keepers
          </h1>
          <p className="mt-2 text-lg text-muted-foreground">
            Create and configure keepers for the Keeper platform architecture.
          </p>
        </div>
      </header>

      {/* Tabs */}
      <div className="flex items-center gap-2 mb-6 border-b border-border">
        <div className="flex items-center gap-1 pb-3">
          {renderTabButton('registry', <BookOpenIcon className="w-4 h-4" />, 'Registry')}
          {renderTabButton('keeper', <CogIcon className="w-4 h-4" />, 'Keeper')}
        </div>
      </div>

      {/* Tab Content */}
      <div className="min-h-[400px]">
        {activeTab === 'registry' && renderRegistryTab()}
        {activeTab === 'keeper' && renderKeeperTab()}
      </div>

      {/* Delete Confirmation Dialog */}
      {deletingKeeper && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <motion.div 
            initial={{ scale: 0.95, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="bg-card border border-border rounded-lg shadow-lg p-6 max-w-md w-full mx-4"
          >
            <h3 className="text-lg font-semibold mb-4 text-foreground">Delete Keeper</h3>
            <p className="text-sm text-muted-foreground mb-6">
              Are you sure you want to delete <strong>{deletingKeeper.title}</strong>? 
              This action cannot be undone and will permanently remove the keeper and all its data.
            </p>
            <div className="flex justify-end space-x-3">
              <button
                onClick={cancelDelete}
                disabled={isDeleting}
                className="px-4 py-2 bg-secondary hover:bg-secondary/90 disabled:bg-secondary/50 text-secondary-foreground rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={confirmDelete}
                disabled={isDeleting}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 disabled:bg-red-300 text-white rounded-lg transition-colors"
              >
                {isDeleting ? 'Deleting...' : 'Delete Keeper'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </motion.div>
  );
};

export default KeeperManagePage;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { keeperApi } from '../../lib/keeperApi';
import { KeeperType, EngagementTemplate } from '../../types/keeper';
import SoleArchitectureTab from '../../components/keeper/SoleArchitectureTab';
import {
  SparklesIcon,
  TagIcon,
  DocumentTextIcon,
  CpuChipIcon,
  PlusIcon,
  InformationCircleIcon,
  PlayIcon
} from '@heroicons/react/24/outline';

interface TabProps {
  id: string;
  label: string;
  icon: React.ReactNode;
}

const tabs: TabProps[] = [
  { id: 'metadata', label: 'Metadata', icon: <InformationCircleIcon className="w-4 h-4" /> },
  { id: 'templates', label: 'Engagement Templates', icon: <DocumentTextIcon className="w-4 h-4" /> },
  { id: 'memory', label: 'Memory Pattern', icon: <CpuChipIcon className="w-4 h-4" /> }
];

const KeeperTypesPage: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [keeperTypes, setKeeperTypes] = useState<KeeperType[]>([]);
  const [selectedKeeperType, setSelectedKeeperType] = useState<KeeperType | null>(null);
  const [activeTab, setActiveTab] = useState('metadata');
  const [engagementTemplates, setEngagementTemplates] = useState<EngagementTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [templatesLoading, setTemplatesLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    loadKeeperTypes();
  }, []);

  useEffect(() => {
    if (selectedKeeperType && activeTab === 'templates') {
      loadEngagementTemplates();
    }
  }, [selectedKeeperType, activeTab]);

  const loadKeeperTypes = async () => {
    try {
      setLoading(true);
      const response = await keeperApi.getKeeperTypes();
      
      if (response.success && response.data) {
        setKeeperTypes(response.data);
        if (response.data.length > 0 && !selectedKeeperType) {
          setSelectedKeeperType(response.data[0]);
        }
      } else {
        setError(response.error || 'Failed to load keeper types');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load keeper types');
    } finally {
      setLoading(false);
    }
  };

  const loadEngagementTemplates = async () => {
    if (!selectedKeeperType) return;

    try {
      setTemplatesLoading(true);
      const response = await keeperApi.getEngagementTemplatesByKeeperType(selectedKeeperType.id);
      
      if (response.success && response.data) {
        setEngagementTemplates(response.data);
      }
    } catch (err) {
      console.error('Error loading engagement templates:', err);
    } finally {
      setTemplatesLoading(false);
    }
  };

  const getMemoryPatternIcon = (pattern?: string) => {
    switch (pattern) {
      case 'SOLE':
        return <SparklesIcon className="w-4 h-4" />;
      case 'CRMTimeline':
        return <TagIcon className="w-4 h-4" />;
      default:
        return <CpuChipIcon className="w-4 h-4" />;
    }
  };

  const getMemoryPatternColor = (pattern?: string) => {
    switch (pattern) {
      case 'SOLE':
        return 'bg-blue-100 text-blue-800';
      case 'CRMTimeline':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const handleTestTemplate = (template: EngagementTemplate) => {
    // Map template slugs to routes - using 'demo' as the keeper ID for demo mode
    const templateRoutes: Record<string, string> = {
      'reflection_journal': '/keeper/demo/reflection-journal',
      'memorycard_generator': '/keeper/demo/memory-cards',
      'voice_panel': '/keeper/demo/voice-panel',
      'echo_writer': '/keeper/demo/echo-writer',
      'identity_logbook': '/keeper/demo/identity-logbook'
    };

    const route = templateRoutes[template.slug];
    
    if (route) {
      // Navigate to the template page in demo mode
      navigate(route);
    } else {
      // For other templates not yet implemented, show coming soon message
      alert(`Template "${template.label}" testing is coming soon!`);
    }
  };

  const renderMetadataTab = () => (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="space-y-6"
    >
      <div className="bg-card border border-border rounded-lg p-6">
        <h3 className="text-lg font-semibold text-foreground mb-4">Basic Information</h3>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="text-sm font-medium text-muted-foreground">ID</label>
            <p className="text-foreground font-mono text-sm bg-muted/50 px-3 py-2 rounded mt-1">
              {selectedKeeperType?.id}
            </p>
          </div>
          
          <div>
            <label className="text-sm font-medium text-muted-foreground">Name</label>
            <p className="text-foreground mt-1">{selectedKeeperType?.name}</p>
          </div>
          
          <div>
            <label className="text-sm font-medium text-muted-foreground">Memory Pattern</label>
            <div className="mt-1">
              {selectedKeeperType?.memoryPattern ? (
                <span className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium ${getMemoryPatternColor(selectedKeeperType.memoryPattern)}`}>
                  {getMemoryPatternIcon(selectedKeeperType.memoryPattern)}
                  {selectedKeeperType.memoryPattern}
                </span>
              ) : (
                <span className="text-muted-foreground">No pattern specified</span>
              )}
            </div>
          </div>
          
          <div>
            <label className="text-sm font-medium text-muted-foreground">System Type</label>
            <div className="mt-1">
              <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                selectedKeeperType?.system ? 'bg-purple-100 text-purple-800' : 'bg-gray-100 text-gray-800'
              }`}>
                {selectedKeeperType?.system ? 'System Reserved' : 'User Created'}
              </span>
            </div>
          </div>
          
          {selectedKeeperType?.createdAt && (
            <div>
              <label className="text-sm font-medium text-muted-foreground">Created At</label>
              <p className="text-foreground mt-1">
                {new Date(selectedKeeperType.createdAt).toLocaleString()}
              </p>
            </div>
          )}
          
          <div>
            <label className="text-sm font-medium text-muted-foreground">Active Keepers</label>
            <p className="text-foreground mt-1">
              {selectedKeeperType?._count?.Keeper || 0} keepers using this type
            </p>
          </div>
        </div>
      </div>

      {/* Actions - Hidden for System Types */}
      {selectedKeeperType?.system ? (
        <div className="bg-amber-50 border border-amber-200 rounded-lg p-6">
          <div className="flex items-center gap-3 mb-2">
            <InformationCircleIcon className="w-5 h-5 text-amber-600" />
            <h3 className="text-lg font-semibold text-amber-800">System Reserved Type</h3>
          </div>
          <p className="text-amber-700">
            This is a system-reserved Keeper Type. Editing is disabled.
          </p>
        </div>
      ) : (
        <div className="bg-card border border-border rounded-lg p-6">
          <h3 className="text-lg font-semibold text-foreground mb-4">Actions</h3>
          <div className="flex flex-wrap gap-3">
            <button className="inline-flex items-center px-4 py-2 text-sm bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors">
              <PlusIcon className="w-4 h-4 mr-2" />
              Edit Type
            </button>
          </div>
        </div>
      )}
    </motion.div>
  );

  const renderEngagementTemplatesTab = () => (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="space-y-6"
    >
      <div className="bg-card border border-border rounded-lg p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-foreground">Engagement Templates</h3>
          <button className="inline-flex items-center px-3 py-2 text-sm bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors">
            <PlusIcon className="w-4 h-4 mr-2" />
            Link Template
          </button>
        </div>

        {templatesLoading ? (
          <div className="flex items-center justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            <span className="ml-2 text-sm text-muted-foreground">Loading templates...</span>
          </div>
        ) : engagementTemplates.length > 0 ? (
          <div className="space-y-3">
            {engagementTemplates.map((template) => (
              <div key={template.id} className="border border-border rounded-lg p-4">
                <div className="flex items-center justify-between">
                  <div className="flex-1">
                    <h4 className="font-medium text-foreground">{template.label}</h4>
                    <p className="text-sm text-muted-foreground">{template.slug}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                      template.type === 'memory' ? 'bg-blue-100 text-blue-800' :
                      template.type === 'identity' ? 'bg-green-100 text-green-800' :
                      template.type === 'timeline' ? 'bg-purple-100 text-purple-800' :
                      'bg-gray-100 text-gray-800'
                    }`}>
                      {template.type}
                    </span>
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                      template.system ? 'bg-purple-100 text-purple-800' : 'bg-gray-100 text-gray-800'
                    }`}>
                      {template.system ? 'System' : 'Custom'}
                    </span>
                    <button
                      onClick={() => handleTestTemplate(template)}
                      className="inline-flex items-center px-3 py-1 text-xs bg-green-100 text-green-800 rounded-lg hover:bg-green-200 transition-colors"
                      title={`Test ${template.label} template`}
                    >
                      <PlayIcon className="w-3 h-3 mr-1" />
                      Test
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-8">
            <DocumentTextIcon className="w-12 h-12 text-muted-foreground mx-auto mb-3" />
            <p className="text-muted-foreground">
              No engagement templates linked to this keeper type yet.
            </p>
          </div>
        )}
      </div>
    </motion.div>
  );

  const renderMemoryPatternTab = () => {
    if (selectedKeeperType?.memoryPattern === 'SOLE') {
      // Create a mock keeper for the SOLE architecture tab
      const mockKeeper = {
        id: 'mock-keeper',
        title: 'Mock Keeper for SOLE Preview',
        purpose: 'Demonstration',
        memoryPattern: 'SOLE',
        sole: {
          type: "narrative-intro",
          content: "You are an agent in a Self-Organizing Learning Environment. Memory is not your storage — it is your mental model taking shape. Reflect often. Forget wisely. Remember what brings clarity. You are allowed to change how you remember, as long as you can explain why.",
          timestamp: new Date().toISOString(),
          author: "system",
          editable: false
        },
        ownerId: user?.id || '',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        KeeperType: selectedKeeperType
      };

      return (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="space-y-6"
        >
          <div className="bg-card border border-border rounded-lg p-6">
            <h3 className="text-lg font-semibold text-foreground mb-4">SOLE Memory Pattern</h3>
            <p className="text-muted-foreground mb-6">
              This KeeperType uses the SOLE (Self-Organizing Learning Environment) memory pattern.
              Below is the default memory architecture that gets seeded when keepers of this type are created.
            </p>
            
            <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-6">
              <p className="text-amber-800 text-sm">
                <strong>Read-Only Preview:</strong> This shows the default SOLE architecture. 
                Individual keepers can modify their memory structure through agent proposals.
              </p>
            </div>
            
            <SoleArchitectureTab
              keeper={mockKeeper as any}
              userId={user?.id || ''}
              onUpdate={() => {}} // No-op for read-only view
            />
          </div>
        </motion.div>
      );
    }

    return (
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="space-y-6"
      >
        <div className="bg-card border border-border rounded-lg p-6">
          <h3 className="text-lg font-semibold text-foreground mb-4">Memory Pattern</h3>
          
          {selectedKeeperType?.memoryPattern ? (
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                {getMemoryPatternIcon(selectedKeeperType.memoryPattern)}
                <h4 className="text-lg font-medium text-foreground">
                  {selectedKeeperType.memoryPattern}
                </h4>
              </div>
              
              <div className="bg-muted/50 rounded-lg p-4">
                <p className="text-muted-foreground">
                  {selectedKeeperType.memoryPattern === 'CRMTimeline' && 
                    'Structured customer records with engagement tracking and timeline management.'
                  }
                  {selectedKeeperType.memoryPattern !== 'SOLE' && selectedKeeperType.memoryPattern !== 'CRMTimeline' &&
                    'Custom memory pattern implementation.'
                  }
                </p>
              </div>
            </div>
          ) : (
            <div className="text-center py-8">
              <CpuChipIcon className="w-12 h-12 text-muted-foreground mx-auto mb-3" />
              <p className="text-muted-foreground">
                No specific memory pattern defined for this keeper type.
              </p>
            </div>
          )}
        </div>
      </motion.div>
    );
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground mb-2">Keeper Types</h1>
        <p className="text-muted-foreground">
          Manage keeper type definitions and memory patterns
        </p>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
          <p className="text-red-800">{error}</p>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Sidebar - Keeper Types List */}
        <div className="lg:col-span-1">
          <div className="bg-card border border-border rounded-lg p-4">
            <h2 className="text-lg font-semibold text-foreground mb-4">Keeper Types</h2>
            
            <div className="space-y-2">
              {keeperTypes.map((type) => (
                <button
                  key={type.id}
                  onClick={() => setSelectedKeeperType(type)}
                  className={`w-full text-left p-3 rounded-lg transition-colors ${
                    selectedKeeperType?.id === type.id
                      ? 'bg-primary text-primary-foreground'
                      : 'hover:bg-muted/50'
                  }`}
                >
                  <div className="flex items-center gap-2 mb-1">
                    {getMemoryPatternIcon(type.memoryPattern)}
                    <span className="font-medium truncate">{type.name}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    {type.memoryPattern && (
                      <span className="text-xs bg-muted/80 px-2 py-1 rounded">
                        {type.memoryPattern}
                      </span>
                    )}
                    {type.system && (
                      <span className="text-xs bg-purple-100 text-purple-800 px-2 py-1 rounded">
                        System
                      </span>
                    )}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="lg:col-span-3">
          {selectedKeeperType ? (
            <>
              {/* Tabs */}
              <div className="border-b border-border mb-6">
                <nav className="flex space-x-8">
                  {tabs.map((tab) => (
                    <button
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id)}
                      className={`flex items-center gap-2 py-4 px-1 border-b-2 font-medium text-sm transition-colors ${
                        activeTab === tab.id
                          ? 'border-primary text-primary'
                          : 'border-transparent text-muted-foreground hover:text-foreground hover:border-muted-foreground'
                      }`}
                    >
                      {tab.icon}
                      {tab.label}
                    </button>
                  ))}
                </nav>
              </div>

              {/* Tab Content */}
              <div>
                {activeTab === 'metadata' && renderMetadataTab()}
                {activeTab === 'templates' && renderEngagementTemplatesTab()}
                {activeTab === 'memory' && renderMemoryPatternTab()}
              </div>
            </>
          ) : (
            <div className="text-center py-16">
              <SparklesIcon className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
              <h3 className="text-lg font-semibold text-foreground mb-2">
                Select a Keeper Type
              </h3>
              <p className="text-muted-foreground">
                Choose a keeper type from the sidebar to view its details and configuration.
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

