      {/* Voice Panel Component */}
      <VoicePanel
        keeperId={keeper.id}
        agentId={keeper.ownerId || 'demo-agent'}
        isDemo={isDemo}
      />
    </div>
  );
};

export default VoicePanelPage;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import { apiFetch } from '../../lib/api';
import { 
  UserIcon,
  CogIcon,
  KeyIcon,
  CheckCircleIcon
} from '@heroicons/react/24/outline';
import DomainManager from '../../components/domain-manager/DomainManager';

interface TabProps {
  id: string;
  label: string;
  icon: React.ReactNode;
  isActive: boolean;
  onClick: (id: string) => void;
}

const Tab: React.FC<TabProps> = ({ id, label, icon, isActive, onClick }) => (
  <button
    onClick={() => onClick(id)}
    className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
      isActive 
        ? 'bg-primary text-primary-foreground shadow-sm' 
        : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'
    }`}
  >
    <span className="w-4 h-4">{icon}</span>
    <span>{label}</span>
  </button>
);

const RootDashboardPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState('profile');
  const { user, updateUser } = useAuth();
  
  // Profile form state
  const [profileForm, setProfileForm] = useState({
    name: user?.name || '',
    email: user?.email || ''
  });
  const [profileSaving, setProfileSaving] = useState(false);
  const [profileError, setProfileError] = useState<string | null>(null);
  const [profileSuccess, setProfileSuccess] = useState<string | null>(null);

  // Domain form state
  const [domainForm, setDomainForm] = useState({
    name: '',
    slug: '',
    description: '',
    customDomain: ''
  });
  // List of all domains for this user
  const [domains, setDomains] = useState<any[]>([]);
  // Add-domain form helpers
  const [showAddDomainForm, setShowAddDomainForm] = useState(false);
  const [newDomainForm, setNewDomainForm] = useState({
    name: '',
    slug: '',
    description: ''
  });
  const [addingDomain, setAddingDomain] = useState(false);
  const [domainSaving, setDomainSaving] = useState(false);
  const [domainError, setDomainError] = useState<string | null>(null);
  const [domainSuccess, setDomainSuccess] = useState<string | null>(null);
  const [domainLoading, setDomainLoading] = useState(true);
  const [currentDomain, setCurrentDomain] = useState<any>(null);
  const [domainModal, setDomainModal] = useState<any | null>(null);
  const refreshList = () => {};

  // Load domain data when user becomes available or changes
  useEffect(() => {
    if (user?.id) {
      loadDomainData();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user?.id]);

  const loadDomainData = async () => {
    if (!user?.id) return;
    
    try {
      // Load user's domains
      const response = await apiFetch('/api/domains/my');
      if (Array.isArray(response)) {
        setDomains(response);
      }
      if (Array.isArray(response) && response.length > 0) {
        // Prefer the API-provided isPrimary flag, then fallback to ownership
        const primaryDomain = response.find((d: any) => d.isPrimary) ||
                              response.find((d: any) => d.ownerId === user.id) ||
                              response[0];

        if (primaryDomain) {
          setCurrentDomain(primaryDomain);
          setDomainForm({
            name: primaryDomain.name || '',
            slug: primaryDomain.slug || '',
            description: primaryDomain.description || '',
            customDomain: primaryDomain.customDomain || ''
          });
        }
      }
    } catch (error) {
      console.error('Error loading domain data:', error);
    } finally {
      setDomainLoading(false);
    }
  };

  const tabs = [
    { id: 'profile', label: 'Profile', icon: <UserIcon /> },
    { id: 'domain', label: 'Domain Settings', icon: <CogIcon /> },
    { id: 'api-keys', label: 'Personal API Keys', icon: <KeyIcon /> },
  ];

  const handleProfileSave = async () => {
    if (!user?.id) return;
    
    setProfileSaving(true);
    setProfileError(null);
    setProfileSuccess(null);

    try {
      const data = await apiFetch(`/api/users/${user.id}`, {
        method: 'PUT',
        body: JSON.stringify({
          name: profileForm.name
        })
      });

      if (data.success) {
        // Update auth context with new user data
        updateUser(data.data);
        setProfileSuccess('Profile updated successfully!');
        
        // Clear success message after 3 seconds
        setTimeout(() => setProfileSuccess(null), 3000);
      } else {
        setProfileError(data.error || 'Failed to update profile');
      }
    } catch (error) {
      console.error('Profile update error:', error);
      setProfileError('Failed to update profile. Please try again.');
    } finally {
      setProfileSaving(false);
    }
  };

  const handleDomainSave = async () => {
    if (!user?.id || !currentDomain) return;
    
    setDomainSaving(true);
    setDomainError(null);
    setDomainSuccess(null);

    try {
      const response = await apiFetch(`/api/domains/${currentDomain.id}`, {
        method: 'PUT',
        body: JSON.stringify({
          // name/slug/description only
          customDomain: null
        })
      });

      if (response.domain) {
        setDomainSuccess('Domain configuration saved successfully!');
        setCurrentDomain(response.domain);
        setDomains(prev => prev.map(d => d.id === response.domain.id ? response.domain : d));
        
        // Clear success message after 3 seconds
        setTimeout(() => setDomainSuccess(null), 3000);
      } else {
        setDomainError(response.error || 'Failed to save domain configuration');
      }
    } catch (error) {
      console.error('Domain save error:', error);
      setDomainError('Failed to save domain configuration. Please try again.');
    } finally {
      setDomainSaving(false);
    }
  };

  const handleCustomDomainSave = async () => {
    if (!currentDomain) return;
    setDomainSaving(true);
    setDomainError(null);
    try {
      const resp = await apiFetch(`/api/domains/${currentDomain.id}/custom-domain`, {
        method: 'POST',
        body: JSON.stringify({ customDomain: domainForm.customDomain })
      });
      if (resp.success) {
        setCurrentDomain(resp.domain);
        setDomainSuccess('Custom domain saved. Configure DNS then click Verify.');
      } else {
        setDomainError(resp.error || 'Failed');
      }
    } catch (e) {
      setDomainError('Failed');
    } finally {
      setDomainSaving(false);
    }
  };

  const handleCustomDomainVerify = async () => {
    if (!currentDomain) return;
    setDomainSaving(true);
    setDomainError(null);
    try {
      const resp = await apiFetch(`/api/domains/${currentDomain.id}/custom-domain/verify`, { method: 'POST' });
      if (resp.success) {
        setCurrentDomain(resp.domain);
        setDomainSuccess('Domain verified and SSL issued!');
      } else {
        setDomainError(resp.error || 'Verification failed');
      }
    } catch (e) {
      setDomainError('Verification failed');
    } finally {
      setDomainSaving(false);
    }
  };

  const handleCustomDomainDelete = async () => {
    if (!currentDomain) return;
    const confirm = window.confirm('Remove custom domain?');
    if (!confirm) return;
    setDomainSaving(true);
    setDomainError(null);
    try {
      const resp = await apiFetch(`/api/domains/${currentDomain.id}/custom-domain`, { method: 'DELETE' });
      if (resp.success) {
        setCurrentDomain(resp.domain);
        setDomainForm(prev => ({ ...prev, customDomain: '' }));
        setDomainSuccess('Custom domain removed');
      } else {
        setDomainError(resp.error || 'Failed');
      }
    } catch (e) {
      setDomainError('Failed');
    } finally {
      setDomainSaving(false);
    }
  };

  // Create a brand-new domain
  const handleAddDomain = async () => {
    if (!user?.id) return;
    if (!newDomainForm.name.trim()) return;
    setAddingDomain(true);
    setDomainError(null);

    try {
      const resp = await apiFetch('/api/domains', {
        method: 'POST',
        body: JSON.stringify({
          name: newDomainForm.name,
          slug: newDomainForm.slug || undefined,
          description: newDomainForm.description || undefined,
        }),
      });

      if (resp.domain) {
        setDomains(prev => [...prev, resp.domain]);
        setCurrentDomain(resp.domain);
        setDomainForm({
          name: resp.domain.name || '',
          slug: resp.domain.slug || '',
          description: resp.domain.description || '',
          customDomain: resp.domain.customDomain || '',
        });
        setNewDomainForm({ name: '', slug: '', description: '' });
        setShowAddDomainForm(false);
        setDomainSuccess('New domain created!');
      } else {
        setDomainError(resp.error || 'Failed to create domain');
      }
    } catch (e) {
      console.error('Add domain error:', e);
      setDomainError('Failed to create domain. Please try again.');
    } finally {
      setAddingDomain(false);
    }
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'profile':
        return (
          <div className="space-y-6">
            <div className="bg-card border border-border rounded-lg p-6">
              <div className="flex items-center space-x-4 mb-6">
                <div className="w-16 h-16 bg-muted rounded-full flex-shrink-0"></div>
                <div>
                  <h3 className="text-lg font-medium text-card-foreground">{user?.name || 'User'}</h3>
                  <p className="text-sm text-muted-foreground">{user?.email}</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    Member since {new Date().toLocaleDateString()}
                  </p>
                </div>
              </div>
              
              {profileError && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-md">
                  <p className="text-sm text-red-800">{profileError}</p>
                </div>
              )}
              
              {profileSuccess && (
                <div className="mb-4 p-3 bg-green-50 border border-green-200 rounded-md">
                  <p className="text-sm text-green-800">{profileSuccess}</p>
                </div>
              )}
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">Full Name</label>
                  <input
                    type="text"
                    value={profileForm.name}
                    onChange={(e) => setProfileForm(prev => ({ ...prev, name: e.target.value }))}
                    className="w-full px-3 py-2 border border-input rounded-md bg-background text-foreground"
                    placeholder="Enter your full name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">Email</label>
                  <input
                    type="email"
                    value={profileForm.email}
                    className="w-full px-3 py-2 border border-input rounded-md bg-background text-foreground"
                    disabled
                  />
                </div>
              </div>
              <div className="mt-6">
                <button 
                  onClick={handleProfileSave}
                  disabled={profileSaving || !profileForm.name.trim()}
                  className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {profileSaving ? 'Saving...' : 'Save Changes'}
                </button>
              </div>
            </div>
          </div>
        );

      case 'domain':
        return (
          <div className="h-[600px] border rounded-lg overflow-hidden">
            <DomainManager scope="user" allowCreate={true} />
          </div>
        );

      case 'api-keys':
        return (
          <div className="space-y-6">
            <div className="bg-card border border-border rounded-lg p-6">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-medium text-card-foreground">Your Personal API Keys</h3>
                <button className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:bg-primary/90 transition-colors">
                  Add Your API Key
                </button>
              </div>
              <p className="text-sm text-muted-foreground mb-4">
                Bring your own personal API keys to access AI models. When you don't provide your own keys, the platform will use shared fallback keys managed by administrators.
              </p>
              <div className="mt-3 p-3 bg-green-50 border border-green-200 rounded-lg">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-green-600">ℹ️</span>
                  <span className="font-medium text-green-800">Personal vs Platform Keys</span>
                </div>
                <p className="text-sm text-green-700">
                  <strong>Your Personal Keys:</strong> Managed here, give you direct control over costs and usage<br/>
                  <strong>Platform Keys:</strong> Managed by administrators in System Administration → Platform API Keys
                </p>
              </div>
              <div className="space-y-3">
                <div className="flex items-center justify-between p-3 border border-border rounded-md">
                  <div>
                    <p className="text-sm font-medium text-foreground">Your OpenAI API Key</p>
                    <p className="text-xs text-muted-foreground">Personal key for AI agent interactions</p>
                  </div>
                  <div className="flex items-center space-x-2">
                    <CheckCircleIcon className="w-4 h-4 text-green-500" />
                    <span className="text-xs text-muted-foreground">Your key active</span>
                  </div>
                </div>
                <div className="flex items-center justify-between p-3 border border-border rounded-md bg-muted/20">
                  <div>
                    <p className="text-sm font-medium text-foreground">Your Anthropic API Key</p>
                    <p className="text-xs text-muted-foreground">Personal key for Claude model access</p>
                  </div>
                  <span className="text-xs text-muted-foreground">Using platform fallback</span>
                </div>
              </div>
              <div className="mt-4">
                <button className="text-sm text-primary hover:underline">
                  Manage Your API Keys →
                </button>
              </div>
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <motion.div
      className="max-w-6xl mx-auto"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
    >
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground mb-2">Root Dashboard</h1>
        <p className="text-muted-foreground">
          Manage your Keeper platform configuration and settings
        </p>
      </div>

      {/* Tab Navigation */}
      <div className="flex space-x-2 mb-8 overflow-x-auto pb-2">
        {tabs.map((tab) => (
          <Tab
            key={tab.id}
            id={tab.id}
            label={tab.label}
            icon={tab.icon}
            isActive={activeTab === tab.id}
            onClick={setActiveTab}
          />
        ))}
      </div>

      {/* Tab Content */}
      <div className="min-h-[400px]">
        {renderTabContent()}
      </div>
    </motion.div>
  );
};

export default RootDashboardPage;

/**
 * User API Key Manager Page
 * =========================
 * 
 * Allows individual users to manage their personal API keys for AI providers
 */

import React, { useState, useEffect } from 'react';
import { ModelProvider, UserApiKey } from '../../types/kip';
import ApiKeyForm from '../../components/ui/ApiKeyForm';
import HelpTooltip from '../../components/ui/HelpTooltip';

interface ApiKeyEntry extends UserApiKey {
  isActive: boolean;
}

const UserApiKeyManagerPage: React.FC = () => {
  const [keys, setKeys] = useState<ApiKeyEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingProvider, setEditingProvider] = useState<ModelProvider | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [revealedKeys, setRevealedKeys] = useState<Set<ModelProvider>>(new Set());

  const providerInfo = {
    openai: {
      name: 'OpenAI',
      description: 'GPT models (GPT-4o, GPT-4 Turbo, etc.)',
      icon: '🤖',
      cost: '$$',
      getKeyUrl: 'https://platform.openai.com/api-keys'
    },
    anthropic: {
      name: 'Anthropic',
      description: 'Claude models (Claude 3.5 Sonnet, etc.)',
      icon: '🧠',
      cost: '$$',
      getKeyUrl: 'https://console.anthropic.com/'
    },
    together: {
      name: 'Together AI',
      description: 'Open-source models (Llama, Mixtral)',
      icon: '🔗',
      cost: '$',
      getKeyUrl: 'https://api.together.xyz/settings/api-keys'
    },
    elevenlabs: {
      name: 'ElevenLabs',
      description: 'Voice synthesis and speech',
      icon: '🎙️',
      cost: '$',
      getKeyUrl: 'https://elevenlabs.io/app/speech-synthesis'
    }
  };

  const allProviders: ModelProvider[] = ['openai', 'anthropic', 'together', 'elevenlabs'];

  useEffect(() => {
    loadUserKeys();
  }, []);

  const loadUserKeys = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Mock API call - replace with actual API
      const response = await fetch('/api/kip/user-keys', {
        headers: {
          'x-user-id': 'current-user-id' // This should come from auth context
        }
      });
      
      if (!response.ok) {
        throw new Error('Failed to load API keys');
      }
      
      const data = await response.json();
      
      // Transform data to include active status
      const userKeys: ApiKeyEntry[] = data.data.map((key: UserApiKey) => ({
        ...key,
        isActive: true // User keys are always active when present
      }));
      
      setKeys(userKeys);
    } catch (err) {
      console.error('Error loading user keys:', err);
      setError('Failed to load your API keys. Please try again.');
      // Show mock data for development
      setKeys([]);
    } finally {
      setLoading(false);
    }
  };

  const handleAddKey = async (provider: ModelProvider, apiKey: string) => {
    try {
      setSubmitting(true);
      setError(null);
      
      const response = await fetch('/api/kip/user-keys', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-user-id': 'current-user-id'
        },
        body: JSON.stringify({ provider, apiKey })
      });
      
      if (!response.ok) {
        throw new Error('Failed to save API key');
      }
      
      setSuccess(`Successfully added ${providerInfo[provider].name} API key!`);
      setShowAddForm(false);
      await loadUserKeys();
      
      // Clear success message after 3 seconds
      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      console.error('Error adding key:', err);
      setError('Failed to save API key. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteKey = async (provider: ModelProvider) => {
    if (!confirm(`Are you sure you want to delete your ${providerInfo[provider].name} API key?`)) {
      return;
    }

    try {
      setSubmitting(true);
      setError(null);
      
      const response = await fetch(`/api/kip/user-keys/${provider}`, {
        method: 'DELETE',
        headers: {
          'x-user-id': 'current-user-id'
        }
      });
      
      if (!response.ok) {
        throw new Error('Failed to delete API key');
      }
      
      setSuccess(`Successfully deleted ${providerInfo[provider].name} API key!`);
      await loadUserKeys();
      
      // Clear success message after 3 seconds
      setTimeout(() => setSuccess(null), 3000);
    } catch (err) {
      console.error('Error deleting key:', err);
      setError('Failed to delete API key. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const toggleKeyVisibility = (provider: ModelProvider) => {
    const newRevealed = new Set(revealedKeys);
    if (newRevealed.has(provider)) {
      newRevealed.delete(provider);
    } else {
      newRevealed.add(provider);
    }
    setRevealedKeys(newRevealed);
  };

  const getUserKey = (provider: ModelProvider) => {
    return keys.find(key => key.provider === provider);
  };

  const hasUserKey = (provider: ModelProvider) => {
    return !!getUserKey(provider);
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
            <p className="text-muted-foreground">Loading your API keys...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-foreground mb-2">Your API Keys</h1>
        <p className="text-muted-foreground">
          Manage your personal AI provider API keys. When you provide your own keys, you'll have direct control over costs and usage.
        </p>
      </div>

      {/* Success/Error Messages */}
      {success && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-md">
          <p className="text-sm text-green-600">{success}</p>
        </div>
      )}
      
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-md">
          <p className="text-sm text-red-600">{error}</p>
        </div>
      )}

      {/* Add Key Form */}
      {showAddForm && (
        <div className="mb-8 p-6 border border-input rounded-lg bg-background">
          <h2 className="text-xl font-semibold mb-4">Add API Key</h2>
          <ApiKeyForm
            onSubmit={(provider, apiKey) => handleAddKey(provider, apiKey)}
            onCancel={() => setShowAddForm(false)}
            isSubmitting={submitting}
            showLabel={false}
          />
        </div>
      )}

      {/* Provider Cards */}
      <div className="space-y-6">
        {allProviders.map((provider) => {
          const userKey = getUserKey(provider);
          const info = providerInfo[provider];
          const isRevealed = revealedKeys.has(provider);
          
          return (
            <div key={provider} className="border border-input rounded-lg p-6 bg-background">
              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{info.icon}</span>
                  <div>
                    <h3 className="text-lg font-semibold text-foreground flex items-center gap-2">
                      {info.name}
                      <HelpTooltip content={`${info.description}. Cost tier: ${info.cost}. Click to get your API key from their official website.`} />
                    </h3>
                    <p className="text-sm text-muted-foreground">{info.description}</p>
                  </div>
                </div>
                
                {/* Status Badge */}
                <div className="flex items-center gap-2">
                  {userKey ? (
                    <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-medium rounded-full">
                      🔑 Using personal key
                    </span>
                  ) : (
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs font-medium rounded-full">
                      🏢 Falling back to platform key
                    </span>
                  )}
                </div>
              </div>

              {/* Key Display/Actions */}
              {userKey ? (
                <div className="space-y-3">
                  <div className="flex items-center gap-2">
                    <code className="flex-1 px-3 py-2 bg-muted rounded font-mono text-sm">
                      {isRevealed ? userKey.maskedKey.replace(/\*/g, '•') : userKey.maskedKey}
                    </code>
                    <button
                      onClick={() => toggleKeyVisibility(provider)}
                      className="px-3 py-2 text-sm text-muted-foreground hover:text-foreground border border-input rounded"
                      disabled={submitting}
                    >
                      {isRevealed ? '🙈 Hide' : '👁️ Show'}
                    </button>
                    <button
                      onClick={() => handleDeleteKey(provider)}
                      className="px-3 py-2 text-sm text-destructive hover:text-destructive/80 border border-input rounded hover:border-destructive/50"
                      disabled={submitting}
                    >
                      🗑️ Delete
                    </button>
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Your agents will use this key for {info.name} models, giving you direct control over costs and usage.
                  </p>
                </div>
              ) : (
                <div className="space-y-3">
                  <p className="text-sm text-muted-foreground">
                    No personal key configured. Agents will use the platform's shared key for {info.name} models.
                  </p>
                  <div className="flex gap-2">
                    <button
                      onClick={() => {
                        setShowAddForm(true);
